function loadState() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
        try {
            const parsed = JSON.parse(saved);
            app.state = { installations: [], coupons: [], pendingApprovals: [], productCommissions: {}, pendingUsers: [], pendingInstallations: [], photoInstallations: [], trainingProgress: {}, clientDocuments: [], clientReferrals: [], clientRedemptions: [], pointsConfig: { pointsPerRef: 100, brlPerPoint: 0.10 }, segmentForms: {}, notifications: [], goals: { default: 10, byConsultant: {} }, followUps: [], chats: {}, metaAlertsSent: {}, chamados: [], tecnicoClients: {}, clientTecnicoHistory: {}, docChecklists: {}, docSlots: {}, comunicados: [], produtos_config: [], formConfigs: {}, ...parsed };
            // Só injeta comunicados/produtos demo se o sistema tem dados de demo
            const _hasDemoSignal = (parsed.users||[]).some(u => u.email === 'gestor@tracktiv.com' || u.email === 'consultor@tracktiv.com');
            if (_hasDemoSignal && (!app.state.comunicados || app.state.comunicados.length === 0)) {
                app.state.comunicados = JSON.parse(JSON.stringify(sampleState.comunicados || []));
            }
            if (_hasDemoSignal && (!app.state.produtos_config || app.state.produtos_config.length === 0)) {
                app.state.produtos_config = JSON.parse(JSON.stringify(sampleState.produtos_config || []));
            }
            if (!app.state.formConfigs) app.state.formConfigs = {};
            // Migração: garante cliente demo apenas se o sistema já tem dados de demonstração
            const users = app.state.users || [];
            const hasDemoData = users.some(u => u.email === 'gestor@tracktiv.com' || u.email === 'consultor@tracktiv.com');
            if (hasDemoData && !users.some(u => u.role === 'cliente')) {
                const demoCliente = sampleState.users.find(u => u.role === 'cliente');
                if (demoCliente && !users.some(u => u.email === demoCliente.email)) {
                    app.state.users = [...users, JSON.parse(JSON.stringify(demoCliente))];
                }
            }
            // Migração: garante documentos demo quando sistema tem dados demo
            if (hasDemoData && (!app.state.clientDocuments || app.state.clientDocuments.length === 0)) {
                app.state.clientDocuments = JSON.parse(JSON.stringify(sampleState.clientDocuments || []));
            }
            // Migração: garante contractedServices em todos os clientes existentes
            (app.state.users || []).forEach(u => {
                if (u.role === 'cliente' && !u.contractedServices) u.contractedServices = [];
            });
            // Migração: garante que presidente existe no estado salvo
            if (!(app.state.users || []).some(u => u.role === 'presidente')) {
                const pres = cleanState.users.find(u => u.role === 'presidente');
                if (pres) app.state.users = [JSON.parse(JSON.stringify(pres)), ...(app.state.users || [])];
            }
            // Migração: garante que gestor_master (gestor@tracktiv.com.br) existe
            if (!(app.state.users || []).some(u => u.email === 'gestor@tracktiv.com.br')) {
                const gm = cleanState.users.find(u => u.email === 'gestor@tracktiv.com.br');
                if (gm) app.state.users = [...(app.state.users || []), JSON.parse(JSON.stringify(gm))];
            }
            // Migração: garante campos chamados e tecnicoClients
            if (!app.state.chamados) app.state.chamados = JSON.parse(JSON.stringify(sampleState.chamados || []));
            if (!app.state.tecnicoClients) app.state.tecnicoClients = JSON.parse(JSON.stringify(sampleState.tecnicoClients || {}));
            if (!app.state.clientTecnicoHistory) app.state.clientTecnicoHistory = {};
            // Migração: normaliza campos dos itens de checklist
            Object.values(app.state.docChecklists || {}).forEach(items => {
                items.forEach(item => {
                    if (!item.status) item.status = item.done ? 'concluido' : 'aguardando';
                    if (item.required === undefined) item.required = true;
                });
            });
            // Migração: novos campos para as 5 features avançadas
            if (!app.state.reengagementQueue)  app.state.reengagementQueue  = [];
            if (!app.state.recoveryHistory)     app.state.recoveryHistory    = [];
            if (!app.state.churnAlertsSent)     app.state.churnAlertsSent    = {};
            // Migração: Portal de Parceiros
            if (!app.state.indicadorReferrals) app.state.indicadorReferrals = [];
            (app.state.users || []).forEach(u => {
                if (u.role === 'instalador' && !u.partnerType) u.partnerType = 'instalador';
            });
            // Migração: Mural e Desafios / Link de Cadastro
            if (!app.state.muralConfig) app.state.muralConfig = { enabled: true, showRanking: true, showMeta: true, showFeed: true, showChallenges: true, showComissions: false, hideFeedNames: false, metaValue: 10 };
            if (!app.state.challenges)  app.state.challenges  = [];
            if (!app.state.salesFeed)   app.state.salesFeed   = [];
            // Migração: campos do Presidente
            if (!app.state.auditLog)          app.state.auditLog          = [];
            if (!app.state.presidenteConfig)  app.state.presidenteConfig  = { companyName: 'Tracktiv', cnpj: '', address: '', email: '', phone: '', logo: '' };
            if (!app.state.commissionRules)   app.state.commissionRules   = { consultorFirstSale: 50, consultorRecurrence: [{minSales:1,maxSales:4,pct:10},{minSales:5,maxSales:9,pct:15},{minSales:10,maxSales:null,pct:20}], instaladorInstall: 60, indicadorRef: 10, referralBonus: 100, history: [] };
            if (!app.state.commissionRules.history) app.state.commissionRules.history = [];
            if (!app.state.recurrenceRules)   app.state.recurrenceRules   = { gracePeriodDays: 30, minClientsToActivate: 1, minMonthlySales: 0, history: [] };
            if (!app.state.recurrenceRules.history) app.state.recurrenceRules.history = [];
            if (!app.state.savedSimulations)  app.state.savedSimulations  = [];
            if (!app.state.simCustomCosts)       app.state.simCustomCosts       = [];
            if (!app.state.simCustomRevenues)  app.state.simCustomRevenues  = [];
            // Migração: módulos e white label
            if (!app.state.moduleConfig) {
                app.state.moduleConfig = {};
                MODULE_DEFINITIONS.forEach(m => { app.state.moduleConfig[m.key] = { enabled: true }; });
            } else {
                MODULE_DEFINITIONS.forEach(m => { if (!app.state.moduleConfig[m.key]) app.state.moduleConfig[m.key] = { enabled: true }; });
            }
            if (!app.state.brandConfig) app.state.brandConfig = { companyName: 'Tracktiv', tagline: 'Portal do Vendedor', logoData: null, primaryColor: '#1a2e4a', accentColor: '#f5820d', sidebarBg: '#0f1c2e', email: '', phone: '', website: '' };
            // Migração: Parceiro Executivo
            if (!app.state.executivoClientConfig) app.state.executivoClientConfig = {};
            if (!app.state.executivoPayments)     app.state.executivoPayments     = [];
            if (!app.state.executivoSales)        app.state.executivoSales        = [];
            // Migrar modelo antigo (% de receita) para novo (% de lucro)
            Object.values(app.state.executivoClientConfig).forEach(cfgs => {
                cfgs.forEach(cfg => {
                    if (cfg.monthlyValue !== undefined && !cfg.monthlyRevenue) {
                        cfg.monthlyRevenue = cfg.monthlyValue; delete cfg.monthlyValue;
                        cfg.profitCommPct  = cfg.commissionPct || 0; delete cfg.commissionPct;
                    }
                });
            });
            (app.state.executivoPayments || []).forEach(p => {
                if (p.monthlyValue !== undefined && !p.monthlyRevenue) {
                    p.monthlyRevenue = p.monthlyValue; p.type = p.type || 'carteira';
                    p.profit = p.monthlyValue - (p.operationalCost || 0);
                    p.profitCommPct = p.commissionPct || 0;
                    p.portfolioComm = p.commissionValue || 0;
                    p.companyNet    = p.netProfit || 0;
                    delete p.monthlyValue; delete p.commissionPct;
                    delete p.commissionValue; delete p.netProfit;
                }
            });
            // Migração: features novas
            if (!app.state.emailQueue)        app.state.emailQueue        = [];
            if (!app.state.customTrainings)   app.state.customTrainings   = [];
            if (!app.state.clientSignatures)  app.state.clientSignatures  = {};
            if (!app.state.proposalSignatures) app.state.proposalSignatures = [];
            if (!app.state.goalsHistory)      app.state.goalsHistory      = [];
            if (!app.state.goalsConfig)       app.state.goalsConfig       = [];
            if (!app.state.empresas)          app.state.empresas          = [{ id: 'main', name: app.state.brandConfig?.companyName || 'Tracktiv', plan: 'enterprise', status: 'ativa', createdAt: '2026-01-01', modules: [] }];
            if (!app.state.activeEmpresaId)   app.state.activeEmpresaId   = 'main';
            if (!app.state.empresaData)       app.state.empresaData       = {};
            // Migração: Qualificação, Link e Formulário do Técnico
            if (!app.state.tecnicoForms)         app.state.tecnicoForms         = {};
            if (!app.state.tecnicoSubmissions)   app.state.tecnicoSubmissions   = {};
            if (!app.state.tecnicoFormSends)     app.state.tecnicoFormSends     = [];
            if (!app.state.tecnicoLinkStats)     app.state.tecnicoLinkStats     = {};
            // Migração: converte formato antigo { fields:[...] } para array de formulários
            Object.keys(app.state.tecnicoForms).forEach(tecId => {
                const v = app.state.tecnicoForms[tecId];
                if (v && !Array.isArray(v)) {
                    app.state.tecnicoForms[tecId] = [{
                        id: 'tform_default_' + tecId,
                        name: 'Formulário padrão',
                        sector: 'rastreamento',
                        createdAt: todayISO(),
                        fields: v.fields || JSON.parse(JSON.stringify(TECNICO_DEFAULT_FORM_FIELDS))
                    }];
                }
            });
        } catch (e) {
            app.state = JSON.parse(JSON.stringify(cleanState));
        }
    } else {
        app.state = JSON.parse(JSON.stringify(cleanState));
    }
}

function saveState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(app.state));
}

/* ═══════════════════════════════════════════════════════════════════
   NAVIGATION
═══════════════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════
   HIERARCHICAL NAVIGATION
═══════════════════════════════════════════════════════════════════ */

function showSection(sectionId) {
    document.querySelectorAll('#appScreen .section').forEach(s => {
        s.classList.toggle('active', s.id === sectionId);
    });
    app.activeView = sectionId;
    // Close mobile sidebar
    const mg = document.querySelector('#appScreen .main-grid');
    if (mg) mg.classList.remove('sidebar-open');
}

function renderNavigation() {
    const tabs = document.getElementById('navigationTabs');
    tabs.innerHTML = '';
    const role = app.currentUser.role;
    const isIndicador = role === 'instalador' && app.currentUser.partnerType === 'indicador';
    const rawTree = role === 'presidente' ? NAV_TREE_PRESIDENTE : (isIndicador ? NAV_TREE_INDICADOR : (NAV_TREE[role] || []));
    const tree = filterNavByModules(rawTree, isIndicador ? 'indicador' : role);
    const expandedId = app.navState.expandedGroup;

    if (expandedId) {
        // Find the group
        const group = tree.find(item => item.id === expandedId);
        if (group && group.children) {
            // Back button
            const backBtn = document.createElement('button');
            backBtn.className = 'tab nav-back';
            backBtn.type = 'button';
            backBtn.innerHTML = `<span style="font-size:1rem;flex-shrink:0;">‹</span><span>${esc(group.label)}</span>`;
            backBtn.addEventListener('click', () => {
                app.navState.expandedGroup = null;
                renderNavigation();
            });
            tabs.appendChild(backBtn);

            // Label
            const lbl = document.createElement('div');
            lbl.className = 'nav-section-label';
            lbl.textContent = group.label;
            tabs.appendChild(lbl);

            group.children.forEach(child => {
                const btn = document.createElement('button');
                const isActive = app.navState.activeItemId === child.id;
                btn.className = 'tab tab-child' + (isActive ? ' active' : '');
                btn.type = 'button';
                btn.dataset.navId = child.id;
                btn.innerHTML = `<span style="font-size:1rem;flex-shrink:0;">${child.icon || ''}</span><span>${esc(child.label)}</span>`;
                btn.addEventListener('click', () => navItemClick(child, group));
                tabs.appendChild(btn);
            });
        }
    } else {
        // Top-level items
        const unread = (app.state.notifications||[]).filter(n=>!n.read && (n.targetUserId === app.currentUser.id || n.consultantId === app.currentUser.id)).length;
        tree.forEach(item => {
            const btn = document.createElement('button');
            const isActive = app.navState.activeItemId === item.id;
            btn.className = 'tab' + (isActive ? ' active' : '');
            btn.type = 'button';
            btn.dataset.navId = item.id;
            const icon = item.icon || NAV_ICONS[item.section || ''] || '';
            if (item.children) {
                btn.innerHTML = `<span style="font-size:1.1rem;flex-shrink:0;">${icon}</span><span>${esc(item.label)}</span><span class="nav-chevron">›</span>`;
                btn.addEventListener('click', () => {
                    app.navState.expandedGroup = item.id;
                    app.navState.activeItemId = null;
                    renderNavigation();
                    renderBreadcrumb();
                });
            } else {
                btn.innerHTML = `<span style="font-size:1.1rem;flex-shrink:0;">${icon}</span><span>${esc(item.label)}</span>`;
                if (unread > 0 && item.section === 'consultorDashboard') {
                    btn.innerHTML += `<span class="nav-badge">${unread}</span>`;
                }
                btn.addEventListener('click', () => navItemClick(item, null));
            }
            tabs.appendChild(btn);
        });
    }
}

function navItemClick(item, parent) {
    app.navState.activeItemId = item.id;

    // Build breadcrumb path
    const role = app.currentUser.role;
    const roleLabel = role === 'presidente' ? 'Presidente' : role === 'gestor' ? 'Gestor' : role === 'consultor' ? 'Consultor' : role === 'tecnico' ? 'Técnico' : role === 'executivo' ? 'Parceiro Executivo'
        : (app.currentUser.partnerType === 'indicador' ? 'Parceiro Indicador' : 'Parceiro Instalador');
    const path = [{ label: roleLabel, groupId: null }];
    if (parent) {
        path.push({ label: parent.label, groupId: parent.id });
    }
    path.push({ label: item.label, groupId: null, active: true });
    app.navState.path = path;

    renderNavigation();
    renderBreadcrumb();

    if (item.action) {
        item.action();
    } else if (item.render) {
        showSection('dynamicContent');
        item.render();
    } else if (item.section) {
        showSection(item.section);
        renderActiveSection(item.section);
    }
}

function renderBreadcrumb() {
    const bar = document.getElementById('breadcrumbBar');
    if (!bar) return;
    const path = app.navState.path || [];
    if (path.length <= 1) {
        bar.innerHTML = '';
        return;
    }
    let html = '';
    path.forEach((seg, i) => {
        if (i > 0) html += `<span class="bc-sep">›</span>`;
        if (seg.active) {
            html += `<span class="bc-item active">${esc(seg.label)}</span>`;
        } else if (seg.groupId) {
            html += `<button class="bc-item" data-groupid="${esc(seg.groupId)}">${esc(seg.label)}</button>`;
        } else {
            html += `<span class="bc-item">${esc(seg.label)}</span>`;
        }
    });
    bar.innerHTML = html;
    bar.querySelectorAll('.bc-item[data-groupid]').forEach(btn => {
        btn.addEventListener('click', () => {
            const gid = btn.dataset.groupid;
            app.navState.expandedGroup = gid;
            app.navState.activeItemId = null;
            app.navState.path = app.navState.path.slice(0, app.navState.path.findIndex(p => p.groupId === gid) + 1);
            renderNavigation();
            renderBreadcrumb();
        });
    });
}

function selectView(viewId, btn) {
    app.activeView = viewId;
    document.querySelectorAll('#appScreen .tab').forEach(t => t.classList.toggle('active', t === btn));
    showSection(viewId);
    renderActiveSection(viewId);
}

function showActiveSection() {
    document.querySelectorAll('#appScreen .section').forEach(s => s.classList.toggle('active', s.id === app.activeView));
}

function renderActiveSection(viewId) {
    const renders = {
        gestorDashboard:    () => { renderGestorStats(); renderConsultorTable(); renderInstaladorDashTable(); renderPendingApprovals(); },
        gestorConsultores:  renderManageConsultors,
        gestorInstaladores: renderGestorInstaladores,
        gestorCupons:       renderGestorCupons,
        gestorConfig:           renderGestorConfig,
        gestorClientesPortal:   renderGestorClientesPortal,
        consultorDashboard: renderConsultorDashboard,
        consultorCRM:       renderFunnelBoard,
        consultorClientes:  renderClientTable,
        consultorProdutos:  renderProducts,
        consultorTreinamento:  renderTrainingModules,
        consultorSimulador:    renderSimulador,
        consultorInformativos: renderInformativos,
        instaladorDashboard:    renderInstaladorDashboard,
        instaladorCRM:          renderInstaladorFunnelBoard,
        instaladorClientes:     renderInstaladorClientes,
        instaladorInformativos: renderInstaladorInformativos,
        instaladorFotos:        renderInstaladorFotos,
        instaladorExtrato:      renderInstaladorExtrato,
        tecnicoDashboard:       renderTecnicoDashboard,
        tecnicoClientes:        renderTecnicoClientes,
        tecnicoChamados:        renderTecnicoChamados
    };
    if (renders[viewId]) renders[viewId]();
}

/* ═══════════════════════════════════════════════════════════════════
   GESTOR: RENDER DASHBOARD
═══════════════════════════════════════════════════════════════════ */

function renderGestorStats() {
    const consultants   = (app.state.users || []).filter(u => u.role === 'consultor');
    const instaladores  = (app.state.users || []).filter(u => u.role === 'instalador');
    const allClients    = app.state.clients || [];
    const totalSales    = allClients.filter(isClosedThisMonth).length;
    const totalMonthlyInst = (app.state.installations || []).filter(i => i.date && i.date.slice(0,7) === getCurrentMonthKey()).length;
    const totalConsComm = consultants.reduce((s, u) => s + getConsultantMetrics(u).commission, 0);
    const totalInstComm = instaladores.reduce((s, u) => s + getInstaladorMetrics(u).totalToReceive, 0);

    document.getElementById('gestorStats').innerHTML = `
        <div class="card"><h3>Consultores</h3><div class="metric">${consultants.length}</div><small>ativos na base</small></div>
        <div class="card"><h3>Instaladores</h3><div class="metric">${instaladores.length}</div><small>parceiros ativos</small></div>
        <div class="card"><h3>Clientes totais</h3><div class="metric">${allClients.length}</div><small>base consolidada</small></div>
        <div class="card"><h3>Vendas no mês</h3><div class="metric">${totalSales}</div><small>fechadas este mês</small></div>
        <div class="card"><h3>Instalações mês</h3><div class="metric">${totalMonthlyInst}</div><small>× R$ ${INSTALL_FEE},00</small></div>
        <div class="card"><h3>Comissão consultores</h3><div class="metric" style="font-size:1.5rem;">R$&nbsp;${formatCurrency(totalConsComm)}</div><small>prevista este mês</small></div>
        <div class="card"><h3>Comissão instaladores</h3><div class="metric" style="font-size:1.5rem;">R$&nbsp;${formatCurrency(totalInstComm)}</div><small>instal. + recorrência</small></div>
        <div class="card"><h3>Total a pagar</h3><div class="metric" style="font-size:1.5rem;">R$&nbsp;${formatCurrency(totalConsComm + totalInstComm)}</div><small>consultores + instaladores</small></div>
    `;
    // Mini bar chart: vendas por consultor
    const chartConsultants = (app.state.users||[]).filter(u=>u.role==='consultor');
    const chartData = chartConsultants.map(u => ({ name: u.name.split(' ')[0], sales: getConsultantMetrics(u).salesCount }));
    const maxSales = Math.max(...chartData.map(d=>d.sales), 1);
    const chartCard = document.createElement('div');
    chartCard.className = 'card';
    chartCard.style.cssText = 'margin-top:0;grid-column:1/-1;';
    chartCard.innerHTML = `
        <h3 style="margin:0 0 16px;">Vendas por consultor</h3>
        ${chartData.length === 0 ? '<p class="text-muted">Nenhum consultor cadastrado.</p>' :
            chartData.map(d => `
                <div class="chart-bar-wrap">
                    <div class="chart-bar-label"><span>${esc(d.name)}</span><strong style="color:var(--accent);">${d.sales}</strong></div>
                    <div class="chart-bar-track"><div class="chart-bar-fill" style="width:${(d.sales/maxSales*100).toFixed(0)}%"></div></div>
                </div>`).join('')}`;
    document.getElementById('gestorStats').appendChild(chartCard);
    const rankingEl = document.getElementById('gestorRanking');
    if (rankingEl) {
        const ranked = buildRanking();
        rankingEl.innerHTML = ranked.length ? ranked.map(r => `
            <div class="ranking-item">
                <div class="rank-pos ${r.rank <= 3 ? 'top' + r.rank : ''}">#${r.rank}</div>
                <div style="font-size:1.3rem;">${r.badge.emoji}</div>
                <div class="rank-name">${esc(r.user.name)}<br><span class="rank-meta">${r.m.salesCount} venda${r.m.salesCount !== 1 ? 's' : ''} · ${r.m.clientCount} cliente${r.m.clientCount !== 1 ? 's' : ''}</span></div>
                <span class="badge ${r.badge.cls}">${r.badge.label}</span>
                <div class="rank-commission">R$ ${formatCurrency(r.m.commission)}</div>
            </div>
        `).join('') : '<p class="text-muted" style="padding:12px 0;">Nenhum consultor cadastrado.</p>';
    }
}

function renderConsultorTable() {
    const body = document.getElementById('consultorTableBody');
    if (!body) return;
    body.innerHTML = '';
    const ranked = buildRanking();
    (app.state.users || []).filter(u => u.role === 'consultor').forEach(u => {
        const m    = getConsultantMetrics(u);
        const re   = ranked.find(r => r.user.id === u.id);
        const b    = re ? re.badge : getPerformanceBadge(m.salesCount);
        const rank = re ? `#${re.rank}` : '—';
        const tr   = document.createElement('tr');
        tr.innerHTML = `
            <td><strong>${esc(u.name)}</strong><br><small>${esc(u.email)}</small></td>
            <td>${m.clientCount}</td>
            <td>${m.salesCount}</td>
            <td><span class="badge ${m.recurrence.badge}">${m.recurrence.label}</span></td>
            <td>R$ ${formatCurrency(m.commission)}</td>
            <td><span class="badge ${b.cls}">${b.emoji} ${b.label}</span> <small style="color:var(--text-soft);">${rank}</small></td>
        `;
        body.appendChild(tr);
    });
}

