function renderGestorDocsPendentes() {
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    const clientes = (app.state.users || []).filter(u => u.role === 'cliente');
    const allWithChecklist = clientes.filter(u => {
        const items = (app.state.docChecklists || {})[u.id] || [];
        return items.length > 0;
    });
    const summary = allWithChecklist.map(u => {
        const items = (app.state.docChecklists || {})[u.id] || [];
        const approved = items.filter(i => _chkStatus(i) === 'concluido').length;
        const enviado  = items.filter(i => _chkStatus(i) === 'enviado').length;
        const pending  = items.filter(i => { const s = _chkStatus(i); return s === 'aguardando' || s === 'recusado'; }).length;
        const pct = Math.round(approved / items.length * 100);
        return { u, items, approved, enviado, pending, pct, total: items.length };
    }).sort((a, b) => b.pending - a.pending);

    const rows = summary.length ? summary.map(({ u, items, approved, enviado, pending, pct, total }) => {
        const statusChip = pending > 0
            ? `<span style="color:#dc3545;font-weight:700;">🔴 ${pending} pendente${pending !== 1 ? 's' : ''}</span>`
            : enviado > 0
            ? `<span style="color:#856404;font-weight:700;">📤 ${enviado} aguardando</span>`
            : `<span style="color:#10b981;font-weight:700;">✅ Completo</span>`;
        const tec = Object.keys(app.state.tecnicoClients || {}).find(tId =>
            (app.state.tecnicoClients[tId] || []).includes(u.clientId));
        const tecName = tec ? (app.state.users || []).find(usr => usr.id === tec)?.name || '—' : '—';
        return `<tr>
            <td><strong>${esc(u.name)}</strong><br><small style="color:var(--text-soft);">${esc(u.email)}</small></td>
            <td>${esc(tecName)}</td>
            <td>
                <div style="font-size:0.82rem;margin-bottom:4px;">${approved}/${total} aprovados</div>
                <div class="seg-progress-track" style="height:6px;"><div class="seg-progress-fill" style="width:${pct}%;height:6px;${pct === 100 ? 'background:linear-gradient(90deg,#10b981,#059669);' : ''}"></div></div>
            </td>
            <td>${statusChip}</td>
            <td>
                ${enviado > 0 ? items.filter(i => _chkStatus(i) === 'enviado').map(i =>
                    `<div style="font-size:0.8rem;margin-bottom:4px;"><strong>${esc(i.label)}</strong>
                     <button class="small-btn" style="font-size:0.72rem;background:#e6f7ec;color:#1a6e35;border-color:#a3d9b5;" onclick="approveChecklistItem('${u.id}','${i.id}');renderGestorDocsPendentes()">✅ Aprovar</button>
                     <button class="small-btn danger-btn" style="font-size:0.72rem;" onclick="rejectChecklistItem('${u.id}','${i.id}');renderGestorDocsPendentes()">❌ Recusar</button></div>`
                ).join('') : ''}
            </td>
            <td><button class="small-btn" onclick="openDocChecklistModal('${u.id}')">📋 Gerenciar</button></td>
        </tr>`;
    }).join('') : `<tr><td colspan="6" style="text-align:center;color:var(--text-soft);">Nenhum cliente com checklist configurado.</td></tr>`;

    el.innerHTML = `
        <div class="section-header"><div><h2>Documentos Requeridos</h2><p>Checklists de documentos por cliente — gerencie e aprove documentos enviados.</p></div></div>
        <div class="card" style="overflow-x:auto;">
            <table>
                <thead><tr><th>Cliente</th><th>Técnico</th><th>Progresso</th><th>Status</th><th>Aguardando aprovação</th><th>Ação</th></tr></thead>
                <tbody>${rows}</tbody>
            </table>
        </div>`;
    showSection('dynamicContent');
}

function renderGestorFormsIncompletos() {
    const el = document.getElementById('pageContent');
    if (!el) return;
    const clientes = (app.state.users || []).filter(u => u.role === 'cliente');
    const incomplete = clientes.filter(u => {
        const contracted = u.contractedServices || [];
        return contracted.some(key => {
            const svc = SERVICE_MAP.find(s => s.key === key);
            if (!svc) return false;
            const formKey = `${u.id}_${key}`;
            const fs = (app.state.segmentForms || {})[formKey] || { data: {} };
            return calcSegmentProgress(svc.product, fs.data || {}) < 100;
        });
    });
    const rows = incomplete.length ? incomplete.map(u => {
        const contracted = u.contractedServices || [];
        const incompleteServices = contracted.filter(key => {
            const svc = SERVICE_MAP.find(s => s.key === key);
            if (!svc) return false;
            const fs = (app.state.segmentForms || {})[`${u.id}_${key}`] || { data: {} };
            return calcSegmentProgress(svc.product, fs.data || {}) < 100;
        });
        return `<tr>
            <td>${esc(u.name)}</td>
            <td>${esc(u.email)}</td>
            <td>${incompleteServices.map(k => { const s = SERVICE_MAP.find(sv => sv.key === k); return s ? esc(s.label) : k; }).join(', ')}</td>
        </tr>`;
    }).join('') : `<tr><td colspan="3" style="text-align:center;color:var(--text-soft);">Nenhum formulário incompleto.</td></tr>`;
    el.innerHTML = `
        <div class="section-header"><div><h2>Formulários Incompletos</h2><p>Clientes com formulários de serviço incompletos.</p></div></div>
        <div class="card" style="overflow-x:auto;">
            <table>
                <thead><tr><th>Cliente</th><th>E-mail</th><th>Serviços incompletos</th></tr></thead>
                <tbody>${rows}</tbody>
            </table>
        </div>`;
}

function renderHistoricoVendas() {
    const el = document.getElementById('pageContent');
    if (!el) return;
    const fechados = (app.state.clients || []).filter(c => c.stage === 'Fechado')
        .sort((a, b) => (b.closedDate || '').localeCompare(a.closedDate || ''));
    const rows = fechados.length ? fechados.map(c => {
        const cons = (app.state.users || []).find(u => u.id === c.consultantId);
        return `<tr>
            <td>${esc(c.name)}</td>
            <td>${esc(c.plan || '—')}</td>
            <td>R$ ${formatCurrency(c.monthlyFee || 0)}</td>
            <td>${esc(c.closedDate || '—')}</td>
            <td>${esc(cons ? cons.name : '—')}</td>
        </tr>`;
    }).join('') : `<tr><td colspan="5" style="text-align:center;color:var(--text-soft);">Nenhuma venda fechada.</td></tr>`;
    el.innerHTML = `
        <div class="section-header"><div><h2>Histórico de Vendas</h2><p>Todos os clientes que fecharam contrato.</p></div></div>
        <div class="card" style="overflow-x:auto;">
            <table>
                <thead><tr><th>Cliente</th><th>Plano</th><th>Mensalidade</th><th>Data fechamento</th><th>Consultor</th></tr></thead>
                <tbody>${rows}</tbody>
            </table>
        </div>`;
}

function renderGestorRelatorios() {
    const el = document.getElementById('pageContent');
    if (!el) return;
    const consultores  = (app.state.users || []).filter(u => u.role === 'consultor');
    const instaladores = (app.state.users || []).filter(u => u.role === 'instalador');
    const clientes     = (app.state.clients || []);
    const fechados     = clientes.filter(c => c.stage === 'Fechado');
    const fechadosMes  = clientes.filter(isClosedThisMonth);
    const perdidosMes  = clientes.filter(c => c.stage === 'Perdido' && (c.updatedAt||'').startsWith(getCurrentMonthKey()));
    const totalFees    = fechados.reduce((s, c) => s + (c.monthlyFee || 0), 0);
    const totalComis   = consultores.reduce((s, u) => s + getConsultantMetrics(u).commission, 0);
    const convRate     = clientes.length ? ((fechados.length / clientes.length) * 100).toFixed(1) : 0;

    // Last 6 months sales data
    const months6 = Array.from({length: 6}, (_, i) => {
        const d = new Date(); d.setMonth(d.getMonth() - (5 - i));
        const key = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
        const label = d.toLocaleDateString('pt-BR', {month:'short'}).replace('.','');
        const count = clientes.filter(c => c.stage === 'Fechado' && (c.closedDate||'').startsWith(key)).length;
        return { label, value: count, key };
    });
    const prevMonthSales = months6[4]?.value || 0;
    const thisMontSales  = months6[5]?.value || 0;
    const salesTrend = thisMontSales > prevMonthSales ? 'up' : thisMontSales < prevMonthSales ? 'down' : 'flat';
    const salesTrendPct = prevMonthSales > 0 ? Math.abs(((thisMontSales - prevMonthSales) / prevMonthSales) * 100).toFixed(0) : null;

    // Clients by product
    const byProduct = {};
    clientes.forEach(c => { const p = c.product || 'Outros'; byProduct[p] = (byProduct[p]||0) + 1; });
    const PRODUCT_COLORS = ['#3b82f6','#10b981','#f59e0b','#8b5cf6','#ef4444','#06b6d4'];
    const productData = Object.entries(byProduct).map(([label, value], i) => ({ label, value, color: PRODUCT_COLORS[i % PRODUCT_COLORS.length] }));

    // Sales by consultant
    const consData = consultores.map(u => {
        const m = getConsultantMetrics(u);
        return { label: u.name.split(' ')[0], value: m.salesCount, color: 'var(--accent)' };
    }).filter(d => d.value > 0).sort((a,b) => b.value - a.value).slice(0, 6);

    el.innerHTML = `
        <div class="section-header">
            <div><h2>📊 Relatórios</h2><p>Análise completa de desempenho — ${getCurrentMonthLabel()}</p></div>
            <div style="display:flex;gap:8px;flex-wrap:wrap;">
                <button class="secondary-btn" onclick="openPrintRelatorio('vendas')" style="font-size:0.82rem;">🖨️ PDF Vendas</button>
                <button class="secondary-btn" onclick="openPrintRelatorio('comissoes')" style="font-size:0.82rem;">🖨️ PDF Comissões</button>
                <button class="secondary-btn" onclick="openPrintRelatorio('clientes')" style="font-size:0.82rem;">🖨️ PDF Clientes</button>
                <button class="secondary-btn" onclick="exportCSVClientes()" style="font-size:0.82rem;">📥 CSV Clientes</button>
                <button class="secondary-btn" onclick="exportCSVLeads()" style="font-size:0.82rem;">📥 CSV Leads</button>
            </div>
            <button class="secondary-btn" onclick="exportRelatorioCSV()">📥 Exportar CSV</button>
        </div>

        <!-- KPIs com tendências -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:14px;margin-bottom:24px;">
            <div class="card" style="padding:14px;">
                <div style="font-size:0.75rem;font-weight:600;color:var(--text-soft);margin-bottom:4px;">VENDAS ESTE MÊS</div>
                <div style="font-size:2rem;font-weight:800;color:var(--primary);">${thisMontSales}</div>
                <div style="margin-top:4px;">
                    <span class="report-kpi-trend trend-${salesTrend}">${salesTrend === 'up' ? '▲' : salesTrend === 'down' ? '▼' : '—'} ${salesTrendPct ? salesTrendPct + '%' : 'igual'} vs mês ant.</span>
                </div>
            </div>
            <div class="card" style="padding:14px;">
                <div style="font-size:0.75rem;font-weight:600;color:var(--text-soft);margin-bottom:4px;">RECEITA RECORRENTE</div>
                <div style="font-size:1.5rem;font-weight:800;color:var(--primary);">R$ ${formatCurrency(totalFees)}</div>
                <small style="color:var(--text-soft);">${fechados.length} contratos ativos</small>
            </div>
            <div class="card" style="padding:14px;">
                <div style="font-size:0.75rem;font-weight:600;color:var(--text-soft);margin-bottom:4px;">TAXA DE CONVERSÃO</div>
                <div style="font-size:2rem;font-weight:800;color:var(--success);">${convRate}%</div>
                <small style="color:var(--text-soft);">${fechados.length} de ${clientes.length} leads</small>
            </div>
            <div class="card" style="padding:14px;">
                <div style="font-size:0.75rem;font-weight:600;color:var(--text-soft);margin-bottom:4px;">COMISSÕES PREVISTAS</div>
                <div style="font-size:1.5rem;font-weight:800;color:var(--accent);">R$ ${formatCurrency(totalComis)}</div>
                <small style="color:var(--text-soft);">${consultores.length} consultores</small>
            </div>
            <div class="card" style="padding:14px;">
                <div style="font-size:0.75rem;font-weight:600;color:var(--text-soft);margin-bottom:4px;">PERDIDOS ESTE MÊS</div>
                <div style="font-size:2rem;font-weight:800;color:var(--danger);">${perdidosMes.length}</div>
                <small style="color:var(--text-soft);">leads perdidos</small>
            </div>
        </div>

        <!-- Charts row -->
        <div style="display:grid;grid-template-columns:2fr 1fr;gap:20px;margin-bottom:24px;">
            <div class="report-chart-card">
                <div class="report-chart-title">📈 Vendas por mês (últimos 6 meses)</div>
                ${_svgBarChart(months6, 520, 200)}
            </div>
            <div class="report-chart-card">
                <div class="report-chart-title">🥧 Clientes por produto</div>
                ${productData.length ? _svgDonutChart(productData, 180) : '<p class="text-muted">Sem dados.</p>'}
            </div>
        </div>

        ${consData.length ? `<div class="report-chart-card" style="margin-bottom:24px;">
            <div class="report-chart-title">🏆 Vendas por consultor (mês atual)</div>
            ${_svgBarChart(consData, 520, 180)}
        </div>` : ''}

        <!-- Tabela detalhada por consultor -->
        <div class="card" style="overflow-x:auto;">
            <div style="padding:14px 16px;border-bottom:1px solid var(--border);font-weight:700;">Detalhamento por consultor</div>
            <table>
                <thead><tr><th>Consultor</th><th>Vendas mês</th><th>Base total</th><th>MRR</th><th>Comissão</th><th>Conv. rate</th></tr></thead>
                <tbody>
                ${consultores.map(u => {
                    const m = getConsultantMetrics(u);
                    const myCli = clientes.filter(c => c.consultantId === u.id);
                    const myFec = myCli.filter(c => c.stage === 'Fechado');
                    const myMrr = myFec.reduce((s,c) => s + (c.monthlyFee||0), 0);
                    const cr    = myCli.length ? ((myFec.length / myCli.length) * 100).toFixed(0) : 0;
                    return `<tr>
                        <td><strong>${esc(u.name)}</strong></td>
                        <td>${m.salesCount}</td>
                        <td>${myCli.length}</td>
                        <td>R$ ${formatCurrency(myMrr)}</td>
                        <td>R$ ${formatCurrency(m.commission)}</td>
                        <td><span class="badge badge-info">${cr}%</span></td>
                    </tr>`;
                }).join('') || '<tr><td colspan="6" style="text-align:center;color:var(--text-soft);">Nenhum consultor cadastrado.</td></tr>'}
                </tbody>
            </table>
        </div>
    `;
}

