/* ═══════════════════════════════════════════════════════════════════
   NOTIFICAÇÕES
═══════════════════════════════════════════════════════════════════ */

const NOTIF_ICONS = {
    sale_approved: '✅', sale_rejected: '❌', new_sale_pending: '💼',
    install_complete: '🔧', install_pending: '🔧', new_consultant_referred: '👥',
    meta_50: '🎯', meta_80: '🔥', meta_100: '🏆',
    new_message: '💬', new_document: '📄', points_credited: '🎁', followup_overdue: '⏰'
};

function addNotification(targetUserId, type, message, linkAction) {
    if (!targetUserId) return;
    if (!app.state.notifications) app.state.notifications = [];
    const cutoff = thirtyDaysAgoISO(30);
    app.state.notifications = app.state.notifications.filter(n => n.createdAt >= cutoff);
    app.state.notifications.push({
        id: `notif_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        targetUserId, type, message, read: false,
        createdAt: new Date().toISOString(),
        linkAction: linkAction || null
    });
    saveState();
    updateNotifBadge();
}

function updateNotifBadge() {
    if (!app.currentUser) return;
    const uid = app.currentUser.id;
    const unreadNotifs = (app.state.notifications || []).filter(n => n.targetUserId === uid && !n.read).length;
    const unreadComs = getComunicadosNaoLidos().length;
    const unread = unreadNotifs + unreadComs;
    const badge = document.getElementById('notifBadge');
    if (badge) {
        badge.textContent = unread > 99 ? '99+' : String(unread);
        badge.classList.toggle('hidden', unread === 0);
    }
    const chatUnread = getChatUnreadCount();
    const chatBadge = document.getElementById('chatBadge');
    if (chatBadge) {
        chatBadge.textContent = chatUnread > 99 ? '99+' : String(chatUnread);
        chatBadge.classList.toggle('hidden', chatUnread === 0);
    }
}

function toggleNotifPanel() {
    const panel = document.getElementById('notifPanel');
    if (!panel) return;
    const wasHidden = panel.classList.contains('hidden');
    panel.classList.toggle('hidden');
    if (wasHidden) {
        renderNotifPanel();
        document.getElementById('chatOverlay')?.classList.add('hidden');
    }
}

function renderNotifPanel() {
    const panel = document.getElementById('notifPanel');
    if (!panel || !app.currentUser) return;
    const uid = app.currentUser.id;
    const cutoff = thirtyDaysAgoISO(30);
    const notifs = (app.state.notifications || [])
        .filter(n => n.targetUserId === uid && n.createdAt >= cutoff)
        .sort((a, b) => b.createdAt.localeCompare(a.createdAt));

    const naoLidos = getComunicadosNaoLidos();
    const comHtml = naoLidos.length === 0 ? '' : `
        <div class="notif-section-label">📢 Comunicados não lidos</div>
        ${naoLidos.map(c => `<div class="notif-item unread comunicado-notif" data-cid="${esc(c.id)}">
            <div class="notif-item-icon">${c.prioridade === 'urgente' ? '🚨' : c.prioridade === 'importante' ? '⚠️' : '📢'}</div>
            <div class="notif-item-body">
                <p class="notif-item-msg"><strong>${esc(c.titulo)}</strong></p>
                <span class="notif-item-time">${esc(c.criadoEm)}</span>
            </div>
            <div class="notif-item-dot"></div>
        </div>`).join('')}
        <div class="notif-section-label">🔔 Notificações</div>`;

    const listHtml = notifs.length === 0
        ? `<div class="notif-empty">Nenhuma notificação nos últimos 30 dias.</div>`
        : notifs.map(n => {
            const icon = NOTIF_ICONS[n.type] || '🔔';
            return `<div class="notif-item ${n.read ? '' : 'unread'}" data-nid="${esc(n.id)}" ${n.linkAction ? `data-link='${JSON.stringify(n.linkAction).replace(/'/g,"&#39;")}'` : ''}>
                <div class="notif-item-icon">${icon}</div>
                <div class="notif-item-body">
                    <p class="notif-item-msg">${esc(n.message)}</p>
                    <span class="notif-item-time">${fmtNotifTime(n.createdAt)}</span>
                </div>
                ${!n.read ? '<div class="notif-item-dot"></div>' : ''}
            </div>`;
        }).join('');

    panel.innerHTML = `
        <div class="notif-panel-header">
            <strong>Notificações</strong>
            <button type="button" id="markAllReadBtn">✓ Marcar todas lidas</button>
        </div>
        <div class="notif-list">${comHtml}${listHtml}</div>`;

    document.getElementById('markAllReadBtn')?.addEventListener('click', () => {
        (app.state.notifications || []).forEach(n => { if (n.targetUserId === uid) n.read = true; });
        getComunicadosAtivos().forEach(c => markComunicadoRead(c.id));
        saveState(); updateNotifBadge(); renderNotifPanel();
    });

    panel.querySelectorAll('.comunicado-notif').forEach(el => {
        el.addEventListener('click', () => {
            markComunicadoRead(el.dataset.cid);
            saveState(); updateNotifBadge();
            panel.classList.add('hidden');
            showSection('dynamicContent');
            renderComunicadosMural();
        });
    });

    panel.querySelectorAll('.notif-item:not(.comunicado-notif)').forEach(el => {
        el.addEventListener('click', () => {
            const n = (app.state.notifications || []).find(x => x.id === el.dataset.nid);
            if (n) { n.read = true; saveState(); updateNotifBadge(); }
            const linkStr = el.dataset.link;
            if (linkStr) {
                try {
                    const action = JSON.parse(linkStr);
                    panel.classList.add('hidden');
                    if (action.section) {
                        showSection(action.section);
                        renderActiveSection(action.section);
                    } else if (action.render) {
                        const fns = {
                            renderFollowUpCalendar, renderGestorRelatorios,
                            renderGestorMetas, renderGestorComissoes
                        };
                        showSection('dynamicContent');
                        if (fns[action.render]) fns[action.render]();
                    }
                } catch(e) { /* invalid link */ }
            }
            renderNotifPanel();
        });
    });
}

function fmtNotifTime(iso) {
    try {
        const d = new Date(iso);
        const ms = Date.now() - d;
        const min = Math.floor(ms / 60000);
        const hr  = Math.floor(ms / 3600000);
        const day = Math.floor(ms / 86400000);
        if (min < 1)  return 'Agora';
        if (min < 60) return `${min}min atrás`;
        if (hr  < 24) return `${hr}h atrás`;
        if (day < 7)  return `${day}d atrás`;
        return formatDate(iso.slice(0, 10));
    } catch { return ''; }
}

/* ═══════════════════════════════════════════════════════════════════
   METAS MENSAIS
═══════════════════════════════════════════════════════════════════ */

const TRAK_META_MSGS = [
    ['Calma, a viagem começa com o primeiro passo! 🚀 Você tem tempo para mudar o jogo este mês.', 'Cada grande vendedor já esteve onde você está. Foque em uma venda por vez! 💪'],
    ['Boa! Você está no caminho certo. Continue assim! 🌟', 'Metade do caminho percorrido — o segundo tempo é onde os campeões brilham! ⚡'],
    ['Quase lá! Você está a um passo do objetivo. Não para agora! 🔥', 'Que ritmo! A linha de chegada está bem perto. Vai fundo! 🏃'],
    ['META BATIDA! Você é um(a) monstro das vendas! 🏆🥇', 'SENSACIONAL! Você bateu a meta! Hora de celebrar — e mirar mais alto! 🎉'],
    ['ALÉM DA META! Você está em outro nível. Isso é excelência pura! 🌟🏆', 'Acima e além! Cada venda extra é comissão extra no bolso. Lenda! 💰🔥']
];

function getGoalForConsultant(userId) {
    const g = app.state.goals || {};
    const byC = g.byConsultant || {};
    return byC[userId] != null ? byC[userId] : (g.default || 10);
}

function checkMetaAlerts(consultantId) {
    const consultant = (app.state.users || []).find(u => u.id === consultantId);
    if (!consultant) return;
    const m = getConsultantMetrics(consultant);
    const goal = getGoalForConsultant(consultantId);
    if (goal <= 0) return;
    const pct = (m.salesCount / goal) * 100;
    if (!app.state.metaAlertsSent) app.state.metaAlertsSent = {};
    const key  = `${consultantId}_${getCurrentMonthKey()}`;
    const sent = app.state.metaAlertsSent[key] || 0;
    const gestor = (app.state.users || []).find(u => u.role === 'gestor');
    if (pct >= 100 && sent < 100) {
        app.state.metaAlertsSent[key] = 100;
        addNotification(consultantId, 'meta_100', `🏆 Você bateu sua meta de ${goal} vendas este mês!`, { section: 'consultorDashboard' });
        if (gestor) addNotification(gestor.id, 'meta_100', `🏆 ${consultant.name} bateu a meta de ${goal} vendas!`, { render: 'renderGestorMetas' });
    } else if (pct >= 80 && sent < 80) {
        app.state.metaAlertsSent[key] = 80;
        addNotification(consultantId, 'meta_80', `🔥 Você está em ${Math.round(pct)}% da meta! (${m.salesCount}/${goal} vendas)`, { section: 'consultorDashboard' });
        if (gestor) addNotification(gestor.id, 'meta_80', `🔥 ${consultant.name} está em ${Math.round(pct)}% da meta!`, { render: 'renderGestorMetas' });
    } else if (pct >= 50 && sent < 50) {
        app.state.metaAlertsSent[key] = 50;
        addNotification(consultantId, 'meta_50', `🎯 Você chegou em 50% da meta! (${m.salesCount}/${goal} vendas)`, { section: 'consultorDashboard' });
        if (gestor) addNotification(gestor.id, 'meta_50', `🎯 ${consultant.name} chegou em 50% da meta.`, { render: 'renderGestorMetas' });
    }
    saveState();
}

function renderConsMetaWidget(containerId) {
    const el = document.getElementById(containerId);
    if (!el || !app.currentUser) return;
    const goal  = getGoalForConsultant(app.currentUser.id);
    const m     = getConsultantMetrics(app.currentUser);
    const sales = m.salesCount;
    const pct   = goal > 0 ? Math.min(100, Math.round((sales / goal) * 100)) : 0;
    const over  = sales > goal;
    const today = new Date();
    const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
    const daysLeft    = daysInMonth - today.getDate();
    const daysPassed  = today.getDate();
    const projection  = daysPassed > 0 ? Math.round((sales / daysPassed) * daysInMonth) : 0;
    const msgIdx      = over ? 4 : pct >= 100 ? 3 : pct >= 80 ? 2 : pct >= 50 ? 1 : 0;
    const msgs        = TRAK_META_MSGS[msgIdx];
    const msg         = msgs[Math.floor(Math.random() * msgs.length)];
    const fillCls     = pct >= 100 ? 'complete' : pct >= 50 ? 'on-track' : '';
    const pctColor    = pct >= 100 ? '#22c55e' : pct >= 80 ? 'var(--primary)' : '#f59e0b';

    el.innerHTML = `<div class="card" style="margin-bottom:8px;">
        <h3>Meta do mês</h3>
        <div style="display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:4px;">
            <div>
                <span class="metric" style="font-size:1.9rem;">${sales}</span>
                <span class="text-muted" style="font-size:0.88rem;"> / ${goal} vendas</span>
            </div>
            <span style="font-size:1.5rem;font-weight:800;color:${pctColor};">${pct}%</span>
        </div>
        <div class="meta-progress-track"><div class="meta-progress-fill ${fillCls}" style="width:${pct}%;"></div></div>
        <div style="display:flex;justify-content:space-between;margin-top:7px;font-size:0.77rem;color:var(--text-soft);">
            <span>📅 ${daysLeft} dia${daysLeft !== 1 ? 's' : ''} restante${daysLeft !== 1 ? 's' : ''}</span>
            <span>📈 Projeção: ${projection} venda${projection !== 1 ? 's' : ''}</span>
        </div>
        <div class="trak-bubble" style="margin-top:12px;">
            <div class="trak-avatar">🤖</div>
            <div class="trak-text">${esc(msg)}</div>
        </div>
    </div>`;
}

/* ═══════════════════════════════════════════════════════════════════
   FOLLOW-UP CALENDAR
═══════════════════════════════════════════════════════════════════ */

const FU_TYPES = ['Ligação', 'Visita', 'Email', 'WhatsApp'];
const FU_ICONS_MAP = { 'Ligação': '📞', 'Visita': '🤝', 'Email': '✉️', 'WhatsApp': '💬' };

function openFollowUpModal(clientId) {
    const c = (app.state.clients || []).find(x => x.id === clientId);
    if (!c) return;
    const uid = app.currentUser?.id;
    const existing = (app.state.followUps || []).filter(f => f.clientId === clientId && !f.done && f.date >= todayISO());
    const existHtml = existing.length ? `
        <div style="margin-bottom:12px;padding:10px;background:var(--surface-2);border-radius:8px;font-size:0.82rem;">
            <strong style="font-size:0.82rem;">Follow-ups já agendados:</strong>
            ${existing.map(f => `<div style="margin-top:4px;">${FU_ICONS_MAP[f.type] || '📅'} ${formatDate(f.date)}${f.time ? ' ' + f.time : ''} — ${esc(f.type)}${f.notes ? ' · ' + esc(f.notes) : ''}</div>`).join('')}
        </div>` : '';

    showModal(`📅 Agendar Follow-up — ${esc(c.name)}`, `
        ${existHtml}
        <form id="followUpForm">
            <div class="field" style="margin-bottom:12px;"><label>Data *</label><input type="date" id="fuDate" required value="${todayISO()}" min="${todayISO()}"></div>
            <div class="field" style="margin-bottom:12px;"><label>Hora</label><input type="time" id="fuTime" value="09:00"></div>
            <div class="field" style="margin-bottom:12px;">
                <label>Tipo *</label>
                <select id="fuType">${FU_TYPES.map(t => `<option value="${esc(t)}">${FU_ICONS_MAP[t] || ''} ${esc(t)}</option>`).join('')}</select>
            </div>
            <div class="field" style="margin-bottom:16px;"><label>Observação</label><input type="text" id="fuNotes" placeholder="Ex: perguntar sobre plano profissional" maxlength="200"></div>
            <div id="fuErr" class="error-text" style="margin-bottom:8px;"></div>
            <div style="display:flex;gap:10px;">
                <button type="submit" class="primary-btn">Agendar</button>
                <button type="button" id="cancelFuBtn" class="secondary-btn">Cancelar</button>
            </div>
        </form>`);

    document.getElementById('cancelFuBtn').addEventListener('click', closeModal);
    document.getElementById('followUpForm').addEventListener('submit', e => {
        e.preventDefault();
        const date  = document.getElementById('fuDate').value;
        const time  = document.getElementById('fuTime').value;
        const type  = document.getElementById('fuType').value;
        const notes = document.getElementById('fuNotes').value.trim();
        if (!date) { document.getElementById('fuErr').textContent = 'Data obrigatória.'; return; }
        if (!app.state.followUps) app.state.followUps = [];
        const fuId = `fu_${Date.now()}`;
        app.state.followUps.push({ id: fuId, clientId, consultantId: uid, date, time, type, notes, done: false, result: null, createdAt: new Date().toISOString() });
        saveState(); closeModal();
        const gcalLink = getGCalLink(`Follow-up: ${c.name}`, date, `${type}${notes ? ' — ' + notes : ''} | Portal Tracktiv`);
        showToast(`Follow-up agendado para ${formatDate(date)}. <a href="${gcalLink}" target="_blank" style="color:inherit;font-weight:700;text-decoration:underline;">📅 Adicionar ao Google Agenda</a>`, 'success', true);
    });
}

function renderFollowUpCalendar() {
    const el = document.getElementById('pageContent');
    if (!el || !app.currentUser) return;
    const uid = app.currentUser.id;
    const isGestor = app.currentUser.role === 'gestor';
    const todayStr = todayISO();
    const now   = new Date();
    const year  = now.getFullYear();
    const month = now.getMonth();

    const allFUs = isGestor
        ? (app.state.followUps || [])
        : (app.state.followUps || []).filter(f => f.consultantId === uid);

    const overdue  = allFUs.filter(f => !f.done && f.date < todayStr).sort((a, b) => a.date.localeCompare(b.date));
    const todayFUs = allFUs.filter(f => !f.done && f.date === todayStr).sort((a, b) => (a.time||'').localeCompare(b.time||''));
    const upcoming = allFUs.filter(f => !f.done && f.date > todayStr).sort((a, b) => a.date.localeCompare(b.date));
    const doneList = allFUs.filter(f => f.done).sort((a, b) => b.date.localeCompare(a.date)).slice(0, 8);

    // Build calendar grid
    const firstDay    = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const monthKey    = `${year}-${String(month + 1).padStart(2, '0')}`;
    const fus4month   = allFUs.filter(f => f.date.startsWith(monthKey));
    const byDay       = {};
    fus4month.forEach(f => {
        const d = parseInt(f.date.split('-')[2]);
        if (!byDay[d]) byDay[d] = [];
        byDay[d].push(f);
    });
    const DAY_NAMES   = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
    const MONTH_NAMES = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

    let calHtml = `<div class="fu-calendar">`;
    DAY_NAMES.forEach(d => { calHtml += `<div class="fu-cal-day-name">${d}</div>`; });
    for (let i = 0; i < firstDay; i++) calHtml += `<div class="fu-cal-day other-month"></div>`;
    for (let d = 1; d <= daysInMonth; d++) {
        const dateStr = `${monthKey}-${String(d).padStart(2, '0')}`;
        const isToday = dateStr === todayStr;
        const df      = byDay[d] || [];
        const dots    = df.slice(0, 4).map(f => `<div class="fu-cal-dot ${f.done ? 'done' : f.date < todayStr ? 'overdue' : ''}"></div>`).join('');
        calHtml += `<div class="fu-cal-day ${isToday ? 'today' : ''} ${df.length ? 'has-items' : ''}" data-fu-date="${dateStr}">
            <div class="fu-cal-day-num">${d}</div>
            <div class="fu-cal-dots">${dots}</div>
        </div>`;
    }
    calHtml += `</div>`;

    const renderItem = (f) => {
        const c    = (app.state.clients || []).find(x => x.id === f.clientId);
        const cons = (app.state.users || []).find(u => u.id === f.consultantId);
        const isOv = !f.done && f.date < todayStr;
        const icon = FU_ICONS_MAP[f.type] || '📅';
        return `<div class="fu-item ${f.done ? 'done-item' : isOv ? 'overdue' : ''}">
            <div class="fu-item-icon">${icon}</div>
            <div class="fu-item-body">
                <div class="fu-item-title">${esc(c?.name || '—')}${isOv ? ' <span style="color:#e53e3e;font-size:0.72rem;font-weight:700;">VENCIDO</span>' : ''}</div>
                <div class="fu-item-meta">${esc(f.type)} · ${formatDate(f.date)}${f.time ? ' ' + f.time : ''}${isGestor && cons ? ' · ' + esc(cons.name) : ''}</div>
                ${f.notes ? `<div class="fu-item-meta" style="margin-top:2px;">📝 ${esc(f.notes)}</div>` : ''}
                ${f.done && f.result ? `<div class="fu-item-meta" style="color:#22c55e;margin-top:2px;">✅ ${esc(f.result)}</div>` : ''}
                ${!f.done ? `<div class="fu-item-actions">
                    <button class="secondary-btn" style="padding:4px 10px;font-size:0.76rem;" data-done-fu="${esc(f.id)}">✅ Marcar feito</button>
                    ${c ? `<button class="secondary-btn" style="padding:4px 10px;font-size:0.76rem;" data-reagendar="${esc(f.id)}">📅 Reagendar</button>` : ''}
                    <a href="${getGCalLink(`Follow-up: ${c?.name||''}`, f.date, f.time||null, `${f.type}${f.notes?' — '+f.notes:''} | Portal Tracktiv`)}" target="_blank" class="secondary-btn" style="padding:4px 10px;font-size:0.76rem;text-decoration:none;">📅 Google Agenda</a>
                </div>` : ''}
            </div>
        </div>`;
    };

    const sec = (title, items, empty) => `
        <h3 style="margin:20px 0 10px;font-size:0.93rem;">${title}</h3>
        ${items.length ? `<div class="fu-list">${items.map(renderItem).join('')}</div>` : `<p class="text-muted" style="font-size:0.85rem;">${empty}</p>`}`;

    const totalPend = overdue.length + todayFUs.length + upcoming.length;
    el.innerHTML = `
        <div class="section-header"><div><h2>Follow-ups${isGestor ? ' — Todos' : ''}</h2><p>Calendário e lista de acompanhamentos agendados.</p></div></div>
        <div class="card" style="margin-bottom:14px;">
            <h3 style="margin:0 0 2px;">${MONTH_NAMES[month]} ${year}</h3>
            <p class="text-muted" style="font-size:0.8rem;margin:0 0 10px;">${totalPend} pendente${totalPend!==1?'s':''} · ${doneList.length} concluído${doneList.length!==1?'s':''} (exibindo últimos)</p>
            ${calHtml}
        </div>
        <div class="card">
            ${sec('⏰ Vencidos', overdue, 'Nenhum follow-up vencido.')}
            ${sec('📅 Hoje', todayFUs, 'Nenhum follow-up para hoje.')}
            ${sec('🗓️ Próximos', upcoming.slice(0, 12), upcoming.length === 0 ? 'Nenhum follow-up futuro agendado.' : '')}
            ${doneList.length ? sec('✅ Concluídos recentes', doneList, '') : ''}
        </div>`;

    el.querySelectorAll('[data-done-fu]').forEach(btn => {
        btn.addEventListener('click', () => {
            const fu = (app.state.followUps || []).find(f => f.id === btn.dataset.doneFu);
            if (!fu) return;
            const result = prompt('Resultado do follow-up (opcional):') || '';
            fu.done = true;
            fu.result = result;
            fu.completedAt = new Date().toISOString();
            saveState();
            renderFollowUpCalendar();
        });
    });
    el.querySelectorAll('[data-reagendar]').forEach(btn => {
        btn.addEventListener('click', () => {
            const fu = (app.state.followUps || []).find(f => f.id === btn.dataset.reagendar);
            if (fu) openFollowUpModal(fu.clientId);
        });
    });
    el.querySelectorAll('.fu-cal-day[data-fu-date]').forEach(day => {
        day.addEventListener('click', () => {
            const date = day.dataset.fuDate;
            const items = allFUs.filter(f => f.date === date);
            if (!items.length) return;
            const listHtml = items.map(f => {
                const c = (app.state.clients || []).find(x => x.id === f.clientId);
                const icon = FU_ICONS_MAP[f.type] || '📅';
                return `<div class="fu-item ${f.done ? 'done-item' : ''}">
                    <div class="fu-item-icon">${icon}</div>
                    <div class="fu-item-body">
                        <div class="fu-item-title">${esc(c?.name || '—')}</div>
                        <div class="fu-item-meta">${esc(f.type)}${f.time ? ' · ' + f.time : ''}${f.done ? ' · ✅ Concluído' : ''}</div>
                        ${f.notes ? `<div class="fu-item-meta">📝 ${esc(f.notes)}</div>` : ''}
                    </div>
                </div>`;
            }).join('');
            showModal(`📅 ${formatDate(date)}`, `<div class="fu-list" style="padding:8px 0;">${listHtml}</div>`);
        });
    });
}

function renderTodayFollowUps(containerId) {
    const el = document.getElementById(containerId);
    if (!el || !app.currentUser) return;
    const uid      = app.currentUser.id;
    const todayStr = todayISO();
    const fus = (app.state.followUps || [])
        .filter(f => f.consultantId === uid && !f.done && f.date <= todayStr)
        .sort((a, b) => a.date.localeCompare(b.date) || (a.time||'').localeCompare(b.time||''));
    if (!fus.length) { el.innerHTML = ''; return; }

    const items = fus.slice(0, 5).map(f => {
        const c  = (app.state.clients || []).find(x => x.id === f.clientId);
        const isOv = f.date < todayStr;
        const icon = FU_ICONS_MAP[f.type] || '📅';
        return `<div style="display:flex;align-items:center;gap:8px;padding:7px 0;border-bottom:1px solid var(--border);">
            <span>${icon}</span>
            <div style="flex:1;">
                <div style="font-size:0.84rem;font-weight:600;">${esc(c?.name || '—')}</div>
                <div style="font-size:0.74rem;color:${isOv ? '#e53e3e' : 'var(--text-soft)'};">${isOv ? '⏰ Vencido' : (f.time || 'Hoje')} · ${esc(f.type)}</div>
            </div>
        </div>`;
    }).join('');

    el.innerHTML = `<div class="card" style="margin-bottom:8px;">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
            <h3 style="margin:0;">Follow-ups${fus.some(f => f.date < todayStr) ? ' <span style="color:#e53e3e;font-size:0.75rem;">· vencidos</span>' : ''}</h3>
            <button class="secondary-btn" style="padding:3px 10px;font-size:0.76rem;" id="viewAllFUBtn">Ver todos</button>
        </div>
        ${items}
        ${fus.length > 5 ? `<div style="font-size:0.76rem;color:var(--text-soft);margin-top:7px;">+${fus.length - 5} mais</div>` : ''}
    </div>`;

    document.getElementById('viewAllFUBtn')?.addEventListener('click', () => {
        showSection('dynamicContent');
        renderFollowUpCalendar();
    });
}

/* ═══════════════════════════════════════════════════════════════════
   CHAT INTERNO
═══════════════════════════════════════════════════════════════════ */

function getChatKey(uid1, uid2) {
    return [uid1, uid2].sort((a, b) => (a === 'gestor' ? -1 : b === 'gestor' ? 1 : a.localeCompare(b))).join('__');
}

function getChatUnreadCount() {
    if (!app.currentUser || !app.state.chats) return 0;
    const uid = app.currentUser.id;
    let count = 0;
    Object.values(app.state.chats).forEach(msgs => {
        if (Array.isArray(msgs)) msgs.forEach(m => { if (m.to === uid && !m.read) count++; });
    });
    return count;
}

function sendChatMessage(targetUserId, text) {
    if (!text.trim()) return;
    const fromId = app.currentUser.id;
    const key    = getChatKey(fromId, targetUserId);
    if (!app.state.chats) app.state.chats = {};
    if (!app.state.chats[key]) app.state.chats[key] = [];
    app.state.chats[key].push({ id: `msg_${Date.now()}`, from: fromId, to: targetUserId, text: text.trim(), time: new Date().toISOString(), read: false });
    const sender = (app.state.users || []).find(u => u.id === fromId);
    const preview = text.trim().slice(0, 45) + (text.length > 45 ? '…' : '');
    addNotification(targetUserId, 'new_message', `💬 ${sender?.name || 'Mensagem'}: "${preview}"`, null);
    saveState();
    updateNotifBadge();
}

function markChatMessagesRead(otherUserId) {
    const key  = getChatKey(app.currentUser.id, otherUserId);
    const msgs = (app.state.chats || {})[key] || [];
    let changed = false;
    msgs.forEach(m => { if (m.to === app.currentUser.id && !m.read) { m.read = true; changed = true; } });
    if (changed) saveState();
    updateNotifBadge();
}

function renderChatConversation(otherUserId, containerId) {
    const el = document.getElementById(containerId);
    if (!el) return;
    markChatMessagesRead(otherUserId);
    const key   = getChatKey(app.currentUser.id, otherUserId);
    const msgs  = (app.state.chats || {})[key] || [];
    const other = (app.state.users || []).find(u => u.id === otherUserId);
    const myId  = app.currentUser.id;
    const isGestor = app.currentUser.role === 'gestor';

    const msgsHtml = msgs.length === 0
        ? `<div class="chat-empty">Nenhuma mensagem ainda. Diga oi! 👋</div>`
        : msgs.map(m => {
            const mine = m.from === myId;
            return `<div class="chat-bubble ${mine ? 'mine' : 'theirs'}">
                ${esc(m.text)}
                <span class="chat-bubble-meta">${fmtNotifTime(m.time)}</span>
            </div>`;
        }).join('');

    const backFn = isGestor ? `renderGestorChatPanel('${containerId}')` : `document.getElementById('chatOverlay').classList.add('hidden')`;

    el.innerHTML = `
        <div class="chat-panel-header">
            <button type="button" class="chat-back-btn" id="chatBackBtn">‹</button>
            <div class="chat-list-avatar" style="width:32px;height:32px;font-size:0.85rem;">${esc((other?.name || '?').charAt(0).toUpperCase())}</div>
            <h3>${esc(other?.name || 'Usuário')}</h3>
            <button type="button" class="chat-close-btn" id="chatCloseConvBtn">×</button>
        </div>
        <div class="chat-messages" id="chatMsgArea">${msgsHtml}</div>
        <div class="chat-input-area">
            <input type="text" id="chatMsgInput" placeholder="Digite uma mensagem…" maxlength="500" autocomplete="off">
            <button type="button" id="chatSendBtn">Enviar</button>
        </div>`;

    requestAnimationFrame(() => {
        const area = document.getElementById('chatMsgArea');
        if (area) area.scrollTop = area.scrollHeight;
    });

    document.getElementById('chatBackBtn')?.addEventListener('click', () => {
        if (isGestor) renderGestorChatPanel(containerId);
        else document.getElementById('chatOverlay')?.classList.add('hidden');
    });
    document.getElementById('chatCloseConvBtn')?.addEventListener('click', () => {
        document.getElementById('chatOverlay')?.classList.add('hidden');
    });

    const doSend = () => {
        const input = document.getElementById('chatMsgInput');
        if (!input?.value.trim()) return;
        sendChatMessage(otherUserId, input.value);
        input.value = '';
        renderChatConversation(otherUserId, containerId);
    };
    document.getElementById('chatSendBtn')?.addEventListener('click', doSend);
    document.getElementById('chatMsgInput')?.addEventListener('keydown', e => {
        if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); doSend(); }
    });
}

function renderGestorChatPanel(containerId) {
    const el = document.getElementById(containerId);
    if (!el) return;
    const myId  = app.currentUser.id;
    const staff = (app.state.users || []).filter(u => u.role === 'consultor' || u.role === 'instalador');

    const items = staff.map(u => {
        const key     = getChatKey(myId, u.id);
        const msgs    = (app.state.chats || {})[key] || [];
        const last    = msgs[msgs.length - 1];
        const unread  = msgs.filter(m => m.to === myId && !m.read).length;
        const preview = last ? (last.from === myId ? 'Você: ' : '') + last.text.slice(0, 42) : 'Nenhuma mensagem ainda';
        const role    = u.role === 'consultor' ? 'Consultor' : 'Instalador';
        return `<div class="chat-list-item ${unread ? 'has-unread' : ''}" data-chat-uid="${esc(u.id)}">
            <div class="chat-list-avatar">${esc(u.name.charAt(0).toUpperCase())}</div>
            <div class="chat-list-body">
                <div class="chat-list-name">${esc(u.name)} <span style="font-size:0.73rem;color:var(--text-soft);">${role}</span></div>
                <div class="chat-list-preview">${esc(preview)}</div>
            </div>
            ${unread ? `<div class="chat-unread-pill">${unread}</div>` : ''}
        </div>`;
    }).join('');

    el.innerHTML = `
        <div class="chat-panel-header">
            <h3>Mensagens</h3>
            <button type="button" class="chat-close-btn" id="chatCloseListBtn">×</button>
        </div>
        <div class="chat-messages" style="padding:10px;overflow-y:auto;">
            ${staff.length === 0 ? '<div class="chat-empty">Nenhum consultor ou instalador cadastrado.</div>' : items}
        </div>`;

    document.getElementById('chatCloseListBtn')?.addEventListener('click', () => {
        document.getElementById('chatOverlay')?.classList.add('hidden');
    });
    el.querySelectorAll('[data-chat-uid]').forEach(item => {
        item.addEventListener('click', () => renderChatConversation(item.dataset.chatUid, containerId));
    });
}

function openChatOverlay(targetUserIdOrNull) {
    const overlay = document.getElementById('chatOverlay');
    if (!overlay) return;
    overlay.classList.remove('hidden');
    document.getElementById('notifPanel')?.classList.add('hidden');

    if (app.currentUser.role === 'gestor') {
        renderGestorChatPanel('chatBody');
    } else {
        const target = targetUserIdOrNull || 'gestor';
        renderChatConversation(target, 'chatBody');
    }
}

function renderGestorChatPage() {
    const el = document.getElementById('pageContent');
    if (!el || !app.currentUser) return;
    const myId  = app.currentUser.id;
    const staff = (app.state.users || []).filter(u => u.role === 'consultor' || u.role === 'instalador');

    const buildConv = (uid) => {
        const key     = getChatKey(myId, uid);
        const msgs    = (app.state.chats || {})[key] || [];
        const other   = (app.state.users || []).find(u => u.id === uid);
        const unread  = msgs.filter(m => m.to === myId && !m.read).length;
        const last    = msgs[msgs.length - 1];
        const preview = last ? (last.from === myId ? 'Você: ' : '') + last.text.slice(0, 50) : 'Nenhuma mensagem ainda';
        const role    = other?.role === 'consultor' ? 'Consultor' : 'Instalador';
        return `<div class="chat-list-item ${unread ? 'has-unread' : ''}" data-page-chat="${esc(uid)}" style="cursor:pointer;">
            <div class="chat-list-avatar">${esc((other?.name || '?').charAt(0).toUpperCase())}</div>
            <div class="chat-list-body">
                <div class="chat-list-name">${esc(other?.name || '?')} <span style="font-size:0.73rem;color:var(--text-soft);">${role}</span></div>
                <div class="chat-list-preview">${esc(preview)}</div>
            </div>
            ${unread ? `<div class="chat-unread-pill">${unread}</div>` : ''}
        </div>`;
    };

    el.innerHTML = `
        <div class="section-header"><div><h2>Mensagens</h2><p>Conversas com consultores e instaladores.</p></div></div>
        <div style="display:grid;grid-template-columns:280px 1fr;gap:16px;height:520px;">
            <div class="card" style="padding:12px;overflow-y:auto;height:100%;">
                ${staff.length === 0
                    ? '<p class="text-muted" style="font-size:0.85rem;padding:12px 0;">Nenhum consultor ou instalador.</p>'
                    : staff.map(u => buildConv(u.id)).join('')}
            </div>
            <div class="card" style="padding:0;overflow:hidden;display:flex;flex-direction:column;height:100%;" id="pageChatConv">
                <div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--text-soft);font-size:0.9rem;">
                    ← Selecione uma conversa
                </div>
            </div>
        </div>`;

    const renderPageConv = (uid) => {
        markChatMessagesRead(uid);
        const key   = getChatKey(myId, uid);
        const msgs  = (app.state.chats || {})[key] || [];
        const other = (app.state.users || []).find(u => u.id === uid);
        const msgsHtml = msgs.length === 0
            ? '<div class="chat-empty">Nenhuma mensagem ainda. Diga oi! 👋</div>'
            : msgs.map(m => `<div class="chat-bubble ${m.from === myId ? 'mine' : 'theirs'}">${esc(m.text)}<span class="chat-bubble-meta">${fmtNotifTime(m.time)}</span></div>`).join('');
        const conv = document.getElementById('pageChatConv');
        if (!conv) return;
        conv.innerHTML = `
            <div class="chat-panel-header" style="border-radius:0;">
                <div class="chat-list-avatar" style="width:30px;height:30px;font-size:0.8rem;">${esc((other?.name||'?').charAt(0).toUpperCase())}</div>
                <h3>${esc(other?.name||'?')}</h3>
            </div>
            <div class="chat-messages" id="pageMsgArea">${msgsHtml}</div>
            <div class="chat-input-area">
                <input type="text" id="pageChatInput" placeholder="Digite uma mensagem…" maxlength="500" autocomplete="off">
                <button type="button" id="pageChatSend">Enviar</button>
            </div>`;
        requestAnimationFrame(() => {
            const area = document.getElementById('pageMsgArea');
            if (area) area.scrollTop = area.scrollHeight;
        });
        const doSend = () => {
            const inp = document.getElementById('pageChatInput');
            if (!inp?.value.trim()) return;
            sendChatMessage(uid, inp.value);
            inp.value = '';
            renderPageConv(uid);
            renderGestorChatPage();
        };
        document.getElementById('pageChatSend')?.addEventListener('click', doSend);
        document.getElementById('pageChatInput')?.addEventListener('keydown', e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); doSend(); } });
    };

    el.querySelectorAll('[data-page-chat]').forEach(item => {
        item.addEventListener('click', () => renderPageConv(item.dataset.pageChat));
    });
}

/* ═══════════════════════════════════════════════════════════════════
   TÉCNICO PROFILE
═══════════════════════════════════════════════════════════════════ */

function renderTecnicoDashboard() {
    if (!app.currentUser || app.currentUser.role !== 'tecnico') return;
    const uid = app.currentUser.id;
    const myChamados  = (app.state.chamados || []).filter(c => c.tecnicoId === uid);
    const assignedIds = ((app.state.tecnicoClients || {})[uid] || []);

    const open    = myChamados.filter(c => c.status === 'Aberto').length;
    const inProg  = myChamados.filter(c => c.status === 'Em andamento').length;
    const waiting = myChamados.filter(c => c.status === 'Aguardando cliente').length;
    const closed  = myChamados.filter(c => ['Resolvido','Fechado'].includes(c.status)).length;

    const tUser = (app.state.users || []).find(u => u.id === uid);
    const quals = tUser ? (tUser.qualifications || []) : [];
    const visibleClients = (app.state.clients || []).filter(c => {
        if (!assignedIds.includes(c.id)) return false;
        if (!quals.length) return true;
        const seg = PRODUCT_SEGMENT_MAP[c.product];
        return !seg || quals.includes(seg);
    });
    const qualBadges = quals.length
        ? quals.map(q => { const s = TECNICO_SEGMENTS.find(x=>x.key===q); return s ? `<span class="badge badge-info" style="font-size:0.75rem;">${s.icon} ${s.label}</span>` : ''; }).join(' ')
        : '<span class="badge badge-active" style="font-size:0.75rem;">Todos os segmentos</span>';

    const stats = document.getElementById('tecnicoStats');
    if (stats) stats.innerHTML = `
        <div class="stat-card"><div class="stat-value">${visibleClients.length}</div><div class="stat-label">Clientes do meu segmento</div></div>
        <div class="stat-card"><div class="stat-value">${open}</div><div class="stat-label">Chamados abertos</div></div>
        <div class="stat-card"><div class="stat-value">${inProg}</div><div class="stat-label">Em andamento</div></div>
        <div class="stat-card"><div class="stat-value">${waiting}</div><div class="stat-label">Aguard. cliente</div></div>
        <div class="stat-card" style="grid-column:1/-1;text-align:left;padding:12px 16px;">
            <div class="stat-label" style="margin-bottom:6px;">Meus segmentos</div>
            <div style="display:flex;gap:6px;flex-wrap:wrap;">${qualBadges}</div>
        </div>
    `;

    const recentes = document.getElementById('tecnicoChamadosRecentes');
    if (recentes) {
        const active = myChamados
            .filter(c => c.status !== 'Fechado')
            .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))
            .slice(0, 5);
        recentes.innerHTML = `
            <div class="card" style="margin-top:18px;">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;">
                    <h3 style="margin:0;">Chamados recentes</h3>
                    <button class="secondary-btn" onclick="showSection('tecnicoChamados');renderTecnicoChamados()">Ver todos</button>
                </div>
                ${active.length === 0
                    ? '<p class="text-muted">Nenhum chamado ativo.</p>'
                    : active.map(ch => renderChamadoCard(ch)).join('')}
            </div>`;
    }
}

function renderTecnicoClientes() {
    if (!app.currentUser || app.currentUser.role !== 'tecnico') return;
    const uid = app.currentUser.id;
    const tUser = (app.state.users || []).find(u => u.id === uid);
    const assignedIds = ((app.state.tecnicoClients || {})[uid] || []);
    const quals = tUser ? (tUser.qualifications || []) : [];
    const clients = (app.state.clients || []).filter(c => {
        if (!assignedIds.includes(c.id)) return false;
        if (!quals.length) return true;
        const seg = PRODUCT_SEGMENT_MAP[c.product];
        return !seg || quals.includes(seg);
    });
    const el = document.getElementById('tecnicoClientesContent');
    if (!el) return;

    if (clients.length === 0) {
        const totalAssigned = assignedIds.length;
        const msg = totalAssigned > 0 && quals.length
            ? `Você tem ${totalAssigned} cliente${totalAssigned !== 1 ? 's' : ''} atribuído${totalAssigned !== 1 ? 's' : ''}, mas nenhum pertence aos seus segmentos qualificados.`
            : 'Nenhum cliente atribuído ainda. Aguarde o gestor atribuir clientes a você.';
        el.innerHTML = `<div class="card"><p class="text-muted">${msg}</p></div>`;
        return;
    }
    el.innerHTML = `<div class="card" style="overflow-x:auto;">
        <table>
            <thead><tr><th>Cliente</th><th>Telefone</th><th>Produto</th><th>Plano</th><th>Chamados ativos</th><th>Ações</th></tr></thead>
            <tbody>
                ${clients.map(c => {
                    const chams = (app.state.chamados || []).filter(ch => ch.clientId === c.id && ch.tecnicoId === uid);
                    const openCount = chams.filter(ch => ['Aberto','Em andamento','Aguardando cliente'].includes(ch.status)).length;
                    const portalUser = (app.state.users || []).find(u => u.role === 'cliente' && u.clientId === c.id);
                    const chkItems = portalUser ? (app.state.docChecklists || {})[portalUser.id] || [] : [];
                    const chkPending = chkItems.filter(i => _chkStatus(i) === 'enviado').length;
                    const chkTotal = chkItems.length;
                    const chkLabel = chkTotal === 0 ? '📋 Checklist' : chkPending > 0 ? `📋 Checklist 🔔${chkPending}` : `📋 Checklist (${chkItems.filter(i=>_chkStatus(i)==='concluido').length}/${chkTotal})`;
                    return `<tr>
                        <td><strong>${esc(c.name)}</strong></td>
                        <td>${esc(c.phone || '—')}</td>
                        <td>${esc(c.product || '—')}</td>
                        <td>${esc(c.plan || '—')}</td>
                        <td>${openCount > 0
                            ? `<span class="badge badge-warn">${openCount} aberto${openCount > 1 ? 's' : ''}</span>`
                            : '<span class="badge badge-active">Sem pendências</span>'}</td>
                        <td class="table-actions">
                            <button class="secondary-btn" onclick="openChamadoModal('${c.id}')">+ Chamado</button>
                            <button class="secondary-btn" onclick="renderTecnicoClienteChamados('${c.id}')">Ver chamados</button>
                            <button class="secondary-btn" onclick="openTecnicoDocModal('${c.id}')">📄 Documentos</button>
                            ${portalUser ? `<button class="secondary-btn${chkPending > 0 ? '" style="border-color:#ffd700;background:#fffbf0;' : '"'} onclick="openDocChecklistModal('${portalUser.id}')">${chkLabel}</button>` : ''}
                        </td>
                    </tr>`;
                }).join('')}
            </tbody>
        </table>
    </div>`;
}

function renderTecnicoClienteChamados(clientId) {
    const client = (app.state.clients || []).find(c => c.id === clientId);
    if (!client) return;
    const uid = app.currentUser.id;
    const chams = (app.state.chamados || [])
        .filter(ch => ch.clientId === clientId && ch.tecnicoId === uid)
        .sort((a, b) => b.createdAt.localeCompare(a.createdAt));
    showModal(`Chamados — ${client.name}`, `
        <div style="margin-bottom:12px;display:flex;justify-content:flex-end;">
            <button class="primary-btn" onclick="closeModal();openChamadoModal('${clientId}')">+ Novo chamado</button>
        </div>
        ${chams.length === 0
            ? '<p class="text-muted">Nenhum chamado registrado para este cliente.</p>'
            : chams.map(ch => renderChamadoCard(ch)).join('')}
    `);
}

/* ─── FEATURE 2: ENVIO DE ARQUIVOS DO TÉCNICO PARA O CLIENTE ─── */

function openTecnicoDocModal(clientId) {
    const client = (app.state.clients || []).find(x => x.id === clientId);
    if (!client) return;
    const uid = app.currentUser.id;
    const docs = (app.state.clientDocuments || []).filter(d => d.clientId === clientId && d.tecnicoId === uid);

    const catOpts = DOC_LIBRARY_TREE.map(cat =>
        `<optgroup label="${cat.icon} ${cat.label}">
            ${cat.folders.map(f => `<option value="${cat.key}|${f}">${f}</option>`).join('')}
        </optgroup>`
    ).join('');

    const docsHtml = docs.length === 0
        ? '<p class="text-muted">Nenhum documento enviado ainda para este cliente.</p>'
        : docs.map(d => {
            const catInfo = DOC_LIBRARY_TREE.find(c => c.key === d.category);
            const vis = d.visibility === 'cliente' ? 'Só cliente' : 'Cliente e Gestor';
            return `
                <div class="extrato-item" style="align-items:center;margin-bottom:6px;">
                    <div>
                        <strong>${esc(d.name)}</strong>
                        <small style="display:block;color:var(--text-soft);">${catInfo ? catInfo.icon + ' ' + catInfo.label : d.category}${d.subfolder ? ' › ' + d.subfolder : ''} · ${d.uploadedAt} · ${vis}</small>
                        ${d.notes ? `<small style="color:var(--text-soft);">${esc(d.notes)}</small>` : ''}
                    </div>
                    <button style="background:none;border:none;cursor:pointer;font-size:1rem;padding:4px 8px;color:#dc3545;" onclick="deleteTecnicoDoc('${d.id}','${clientId}')">🗑</button>
                </div>`;
        }).join('');

    showModal(`Documentos — ${esc(client.name)}`, `
        <div style="margin-bottom:20px;">
            <h4 style="margin:0 0 12px;">Meus envios para este cliente (${docs.length})</h4>
            ${docsHtml}
        </div>
        <h4 style="margin:0 0 12px;">Enviar novo documento</h4>
        <div class="form-grid">
            <div class="field"><label>Nome do documento *</label>
                <input id="tecDocName" type="text" placeholder="Ex: Laudo técnico de instalação"></div>
            <div class="field"><label>Pasta de destino *</label>
                <select id="tecDocFolder" style="border:1.5px solid var(--border);border-radius:10px;padding:8px 12px;background:var(--bg);width:100%;">${catOpts}</select></div>
            <div class="field"><label>Descrição (opcional)</label>
                <input id="tecDocDesc" type="text" placeholder="Observação adicional"></div>
            <div class="field"><label>Visibilidade</label>
                <select id="tecDocVis" style="border:1.5px solid var(--border);border-radius:10px;padding:8px 12px;background:var(--bg);width:100%;">
                    <option value="cliente_gestor">Cliente e Gestor</option>
                    <option value="cliente">Apenas Cliente</option>
                </select></div>
            <div class="field full-width"><label>Arquivo (PDF, imagem, doc — máx. 2 MB)</label>
                <input id="tecDocFile" type="file" accept=".pdf,.png,.jpg,.jpeg,.doc,.docx,.xls,.xlsx,.ppt,.pptx" style="margin-top:4px;"></div>
        </div>
        <div id="tecDocError" class="error-text" style="margin-top:8px;"></div>
        <div class="actions" style="margin-top:12px;">
            <button class="primary-btn" id="tecDocSaveBtn">📤 Enviar documento</button>
            <button class="secondary-btn" onclick="closeModal()">Fechar</button>
        </div>
    `);

    document.getElementById('tecDocSaveBtn').addEventListener('click', () => {
        const name = document.getElementById('tecDocName').value.trim();
        const folderVal = document.getElementById('tecDocFolder').value;
        const desc = document.getElementById('tecDocDesc').value.trim();
        const vis = document.getElementById('tecDocVis').value;
        const file = document.getElementById('tecDocFile').files[0];
        const err = document.getElementById('tecDocError');
        err.textContent = '';
        if (!name) { err.textContent = 'Nome do documento é obrigatório.'; return; }
        if (!file) { err.textContent = 'Selecione um arquivo para enviar.'; return; }
        if (file.size > 2097152) { err.textContent = 'Arquivo muito grande. Máximo 2 MB.'; return; }

        const [category, subfolder] = folderVal.split('|');
        const reader = new FileReader();
        reader.onload = e => {
            if (!app.state.clientDocuments) app.state.clientDocuments = [];
            app.state.clientDocuments.push({
                id: `tdoc_${Date.now()}`, clientId, category, subfolder: subfolder || '',
                name, fileName: file.name, data: e.target.result,
                type: file.type, size: file.size, uploadedAt: todayISO(),
                uploadedBy: app.currentUser.name, uploadedByRole: 'tecnico',
                tecnicoId: uid, visibility: vis, viewedBy: [], notes: desc
            });
            const clientUser = (app.state.users || []).find(u => u.clientId === clientId && u.role === 'cliente');
            if (clientUser) addNotification(clientUser.id, 'new_document', `📄 Novo documento disponível: "${name}"`, null);
            if (vis === 'cliente_gestor') {
                const gestorU = (app.state.users || []).find(u => u.role === 'gestor');
                if (gestorU) addNotification(gestorU.id, 'new_document', `📄 Técnico ${app.currentUser.name} enviou "${name}" para ${client.name}`, null);
            }
            saveState();
            openTecnicoDocModal(clientId);
        };
        reader.readAsDataURL(file);
    });
}

function deleteTecnicoDoc(docId, clientId) {
    if (!confirm('Remover este documento?')) return;
    app.state.clientDocuments = (app.state.clientDocuments || []).filter(d => d.id !== docId);
    saveState();
    openTecnicoDocModal(clientId);
}

function renderTecnicoChamados() {
    if (!app.currentUser || app.currentUser.role !== 'tecnico') return;
    const uid = app.currentUser.id;
    const all = (app.state.chamados || [])
        .filter(c => c.tecnicoId === uid)
        .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
    const el = document.getElementById('tecnicoChamadosContent');
    if (!el) return;

    const filterBar = `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px;">
        ${['Todos','Aberto','Em andamento','Aguardando cliente','Resolvido','Fechado'].map(s =>
            `<button class="secondary-btn" style="font-size:0.8rem;padding:5px 12px;"
                onclick="filterTecnicoChamados('${s}')">${s}</button>`
        ).join('')}
    </div>`;

    el.innerHTML = filterBar + `<div id="tecnicoChamadosList">` +
        (all.length === 0
            ? '<p class="text-muted">Nenhum chamado ainda. Abra um chamado a partir da lista de clientes.</p>'
            : all.map(ch => renderChamadoCard(ch)).join(''))
        + '</div>';
}

function filterTecnicoChamados(status) {
    const uid = app.currentUser.id;
    let chams = (app.state.chamados || []).filter(c => c.tecnicoId === uid);
    if (status !== 'Todos') chams = chams.filter(c => c.status === status);
    chams.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
    const el = document.getElementById('tecnicoChamadosList');
    if (!el) return;
    el.innerHTML = chams.length === 0
        ? '<p class="text-muted">Nenhum chamado com este status.</p>'
        : chams.map(ch => renderChamadoCard(ch)).join('');
}

function renderChamadoCard(ch) {
    const client = (app.state.clients || []).find(c => c.id === ch.clientId);
    const clientName = client ? client.name : 'Cliente desconhecido';
    const statusCls = {
        'Aberto':             'chamado-status-aberto',
        'Em andamento':       'chamado-status-andamento',
        'Aguardando cliente': 'chamado-status-aguardando',
        'Resolvido':          'chamado-status-resolvido',
        'Fechado':            'chamado-status-fechado'
    }[ch.status] || '';
    const priorityIcon = ch.priority === 'Urgente' ? '🔴' : ch.priority === 'Normal' ? '🟡' : '🟢';
    const msgCount = (ch.messages || []).length;
    return `
        <div class="chamado-card" onclick="openChamadoDetail('${ch.id}')">
            <div class="chamado-header">
                <span class="chamado-title">${esc(ch.title)}</span>
                <span class="chamado-status-pill ${statusCls}">${esc(ch.status)}</span>
            </div>
            <div class="chamado-meta">
                ${priorityIcon} <strong>${esc(ch.priority)}</strong> &bull; ${esc(clientName)} &bull; ${ch.createdAt}
            </div>
            <div class="chamado-desc">${esc((ch.description || '').slice(0, 100))}${(ch.description || '').length > 100 ? '…' : ''}</div>
            <div class="chamado-footer">
                <span>${msgCount} mensagem${msgCount !== 1 ? 'ns' : ''}</span>
                <span class="chamado-link">Ver detalhes ›</span>
            </div>
        </div>`;
}

function openChamadoModal(clientId) {
    if (!app.currentUser) return;
    const uid = app.currentUser.id;
    const assignedIds = app.currentUser.role === 'tecnico'
        ? ((app.state.tecnicoClients || {})[uid] || [])
        : (app.state.clients || []).map(c => c.id);
    const clients = (app.state.clients || []).filter(c => assignedIds.includes(c.id));

    showModal('Abrir novo chamado', `
        <form onsubmit="saveChamado(event)">
            <div class="field">
                <label>Cliente *</label>
                <select id="chamadoClientId" required>
                    <option value="">Selecione...</option>
                    ${clients.map(c => `<option value="${c.id}" ${c.id === clientId ? 'selected' : ''}>${esc(c.name)}</option>`).join('')}
                </select>
            </div>
            <div class="field">
                <label>Título *</label>
                <input id="chamadoTitle" type="text" required placeholder="Ex: Rastreador sem sinal">
            </div>
            <div class="field">
                <label>Prioridade</label>
                <select id="chamadoPriority">
                    <option>Normal</option>
                    <option>Urgente</option>
                    <option>Baixa</option>
                </select>
            </div>
            <div class="field">
                <label>Descrição *</label>
                <textarea id="chamadoDesc" rows="4" required placeholder="Descreva o problema ou solicitação..."></textarea>
            </div>
            <div class="actions">
                <button type="submit" class="primary-btn">Abrir chamado</button>
                <button type="button" class="secondary-btn" onclick="closeModal()">Cancelar</button>
            </div>
        </form>
    `);
}

function saveChamado(e) {
    e.preventDefault();
    const clientId = document.getElementById('chamadoClientId').value;
    const title    = document.getElementById('chamadoTitle').value.trim();
    const priority = document.getElementById('chamadoPriority').value;
    const desc     = document.getElementById('chamadoDesc').value.trim();
    if (!clientId || !title || !desc) return;
    const uid = app.currentUser.id;
    const now = todayISO();
    const ch = {
        id: 'ch_' + Date.now(), clientId, tecnicoId: uid, title, description: desc,
        priority, status: 'Aberto', createdAt: now, updatedAt: now,
        messages: [{ id: 'cm_' + Date.now(), from: uid, text: `Chamado aberto: ${desc}`, at: now }]
    };
    if (!app.state.chamados) app.state.chamados = [];
    app.state.chamados.push(ch);
    const gestor = (app.state.users || []).find(u => u.role === 'gestor');
    if (gestor) addNotification(gestor.id, 'chamado', `Novo chamado aberto por ${app.currentUser.name}: "${title}"`, { render: 'renderGestorChamados' });
    saveState();
    closeModal();
    showToast(`Chamado "${title}" aberto com sucesso!`, 'success');
    if (app.currentUser.role === 'tecnico') {
        renderTecnicoChamados();
        renderTecnicoDashboard();
    }
}

function openChamadoDetail(chamadoId) {
    const ch = (app.state.chamados || []).find(c => c.id === chamadoId);
    if (!ch) return;
    const client = (app.state.clients || []).find(c => c.id === ch.clientId);
    const clientName = client ? client.name : 'Desconhecido';
    const priorityIcon = ch.priority === 'Urgente' ? '🔴' : ch.priority === 'Normal' ? '🟡' : '🟢';
    const statusOptions = ['Aberto','Em andamento','Aguardando cliente','Resolvido','Fechado'];
    const canEdit = app.currentUser && (app.currentUser.role === 'tecnico' || app.currentUser.role === 'gestor');

    const msgsHtml = (ch.messages || []).map(m => {
        const sender = (app.state.users || []).find(u => u.id === m.from);
        const senderName = sender ? sender.name : m.from;
        const isMine = m.from === app.currentUser.id;
        return `<div class="chamado-msg ${isMine ? 'chamado-msg-mine' : 'chamado-msg-other'}">
            <div class="chamado-msg-meta">${esc(senderName)} &bull; ${m.at}</div>
            <div class="chamado-msg-text">${esc(m.text)}</div>
        </div>`;
    }).join('');

    showModal(`Chamado #${ch.id.slice(-4)}: ${ch.title}`, `
        <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:12px;font-size:0.9rem;">
            ${priorityIcon} <strong>${esc(ch.priority)}</strong>
            &bull; Cliente: <strong>${esc(clientName)}</strong>
            &bull; Aberto em: ${ch.createdAt}
        </div>
        <div class="card" style="margin-bottom:14px;padding:12px 14px;background:var(--surface-2);">
            <strong>Descrição:</strong><br>${esc(ch.description)}
        </div>
        ${canEdit ? `
        <div class="field" style="margin-bottom:14px;">
            <label>Status do chamado</label>
            <select id="chamadoStatusSel" onchange="updateChamadoStatus('${ch.id}',this.value)">
                ${statusOptions.map(s => `<option ${ch.status === s ? 'selected' : ''}>${s}</option>`).join('')}
            </select>
        </div>` : ''}
        <div class="chamado-thread" id="chamadoThread_${ch.id}">
            ${msgsHtml || '<p class="text-muted" style="text-align:center;padding:18px 0;">Nenhuma mensagem ainda.</p>'}
        </div>
        ${canEdit ? `
        <div class="field" style="margin-top:14px;">
            <label>Adicionar mensagem</label>
            <textarea id="chamadoMsgInput" rows="3" placeholder="Escreva uma atualização ou anotação..."></textarea>
        </div>
        <div class="actions">
            <button class="primary-btn" onclick="sendChamadoMessage('${ch.id}')">Enviar</button>
            <button class="secondary-btn" onclick="closeModal()">Fechar</button>
        </div>` : `<div class="actions"><button class="secondary-btn" onclick="closeModal()">Fechar</button></div>`}
    `);
}

function updateChamadoStatus(chamadoId, newStatus) {
    const ch = (app.state.chamados || []).find(c => c.id === chamadoId);
    if (!ch) return;
    ch.status    = newStatus;
    ch.updatedAt = todayISO();
    if (!ch.messages) ch.messages = [];
    ch.messages.push({ id: 'cm_' + Date.now(), from: app.currentUser.id, text: `Status alterado para: ${newStatus}`, at: todayISO() });
    saveState();
    showToast(`Status do chamado atualizado para "${newStatus}".`, 'success');
    if (app.currentUser.role === 'tecnico') {
        renderTecnicoDashboard();
        renderTecnicoChamados();
    }
}

function sendChamadoMessage(chamadoId) {
    const input = document.getElementById('chamadoMsgInput');
    const text = input?.value.trim();
    if (!text) return;
    const ch = (app.state.chamados || []).find(c => c.id === chamadoId);
    if (!ch) return;
    if (!ch.messages) ch.messages = [];
    ch.messages.push({ id: 'cm_' + Date.now(), from: app.currentUser.id, text, at: todayISO() });
    ch.updatedAt = todayISO();
    if (app.currentUser.role === 'tecnico') {
        const gestor = (app.state.users || []).find(u => u.role === 'gestor');
        if (gestor) addNotification(gestor.id, 'chamado', `Nova mensagem no chamado "${ch.title}" por ${app.currentUser.name}`, { render: 'renderGestorChamados' });
    }
    saveState();
    closeModal();
    openChamadoDetail(chamadoId);
}

/* ─── GESTOR: TÉCNICOS MANAGEMENT ─── */

function renderGestorTecnicos() {
    const tecnicos = (app.state.users || []).filter(u => u.role === 'tecnico');
    const chamados = app.state.chamados || [];
    const tClients = app.state.tecnicoClients || {};
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    el.innerHTML = `
        <div class="section-header">
            <div><h2>Técnicos</h2><p>Cadastre técnicos e gerencie clientes atribuídos.</p></div>
            <button class="primary-btn" onclick="openTecnicoModal()">+ Novo técnico</button>
        </div>
        ${tecnicos.length === 0
            ? `<div class="card"><p class="text-muted">Nenhum técnico cadastrado. Clique em "+ Novo técnico" para começar.</p></div>`
            : `<div class="card" style="overflow-x:auto;">
                <table>
                    <thead><tr><th>Nome</th><th>Qualificações</th><th>Telefone</th><th>Clientes</th><th>Chamados abertos</th><th>Ações</th></tr></thead>
                    <tbody>
                    ${tecnicos.map(t => {
                        const aIds      = tClients[t.id] || [];
                        const openChams = chamados.filter(c => c.tecnicoId === t.id && ['Aberto','Em andamento','Aguardando cliente'].includes(c.status)).length;
                        const quals     = (t.qualifications || []);
                        const qualHtml  = quals.length
                            ? quals.map(q => { const s = TECNICO_SEGMENTS.find(x=>x.key===q); return s ? `<span class="badge badge-info" style="margin:1px;font-size:0.72rem;">${s.icon} ${s.label}</span>` : ''; }).join('')
                            : '<span class="text-muted" style="font-size:0.82rem;">Todos os segmentos</span>';
                        return `<tr>
                            <td><strong>${esc(t.name)}</strong><br><small class="text-muted">${esc(t.email)}</small></td>
                            <td>${qualHtml}</td>
                            <td>${esc(t.phone || '—')}</td>
                            <td><span class="badge badge-active">${aIds.length} cliente${aIds.length !== 1 ? 's' : ''}</span></td>
                            <td>${openChams > 0 ? `<span class="badge badge-warn">${openChams}</span>` : '<span class="badge badge-active">0</span>'}</td>
                            <td class="table-actions">
                                <button class="secondary-btn" onclick="openAssignTecnicoClientModal('${t.id}')">Atribuir clientes</button>
                                <button class="secondary-btn" onclick="openTecnicoModal('${t.id}')">Editar</button>
                                <button class="danger-btn"    onclick="deleteTecnico('${t.id}')">Excluir</button>
                            </td>
                        </tr>`;
                    }).join('')}
                    </tbody>
                </table>
            </div>`}
    `;
    showSection('dynamicContent');
}

function openTecnicoModal(tecnicoId) {
    const t = tecnicoId ? (app.state.users || []).find(u => u.id === tecnicoId) : null;
    const quals = t ? (t.qualifications || []) : [];
    const qualChecks = TECNICO_SEGMENTS.map(s => `
        <label style="display:flex;align-items:center;gap:8px;padding:5px 0;cursor:pointer;">
            <input type="checkbox" class="tec-qual-cb" value="${s.key}" ${quals.includes(s.key) ? 'checked' : ''} style="width:15px;height:15px;">
            <span>${s.icon} ${s.label}</span>
        </label>`).join('');
    showModal(t ? 'Editar técnico' : 'Cadastrar técnico', `
        <form onsubmit="saveTecnico(event,'${tecnicoId || ''}')">
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                <div class="field"><label>Nome *</label><input id="tecNome" value="${t ? esc(t.name) : ''}" required></div>
                <div class="field"><label>E-mail *</label><input id="tecEmail" type="email" value="${t ? esc(t.email) : ''}" required></div>
                <div class="field"><label>Senha${t ? ' (em branco = manter)' : ' *'}</label><input id="tecSenha" type="password" ${t ? '' : 'required'}></div>
                <div class="field"><label>CPF</label><input id="tecCPF" value="${t ? esc(t.cpf || '') : ''}"></div>
                <div class="field"><label>Telefone</label><input id="tecTel" value="${t ? esc(t.phone || '') : ''}"></div>
                <div class="field"><label>WhatsApp</label><input id="tecWA" value="${t ? esc(t.whatsapp || '') : ''}"></div>
                <div class="field" style="grid-column:1/-1;"><label>Especialidade</label><input id="tecEsp" value="${t ? esc(t.specialty || '') : ''}" placeholder="Ex: Rastreamento Veicular"></div>
                <div class="field" style="grid-column:1/-1;">
                    <label style="margin-bottom:6px;display:block;">Qualificações (segmentos que o técnico atende)</label>
                    <div style="border:1px solid var(--border);border-radius:10px;padding:10px 14px;background:var(--bg);">
                        ${qualChecks}
                    </div>
                    <small class="text-muted">O técnico verá apenas clientes dos segmentos selecionados.</small>
                </div>
            </div>
            <div class="actions">
                <button type="submit" class="primary-btn">${t ? 'Salvar' : 'Cadastrar'}</button>
                <button type="button" class="secondary-btn" onclick="closeModal()">Cancelar</button>
            </div>
        </form>
    `);
}

function saveTecnico(e, tecnicoId) {
    e.preventDefault();
    const nome  = document.getElementById('tecNome').value.trim();
    const email = document.getElementById('tecEmail').value.trim().toLowerCase();
    const senha = document.getElementById('tecSenha').value.trim();
    const cpf   = document.getElementById('tecCPF').value.trim();
    const tel   = document.getElementById('tecTel').value.trim();
    const wa    = document.getElementById('tecWA').value.trim();
    const esp   = document.getElementById('tecEsp').value.trim();
    const quals = Array.from(document.querySelectorAll('.tec-qual-cb:checked')).map(cb => cb.value);
    const users = app.state.users || [];

    if (tecnicoId) {
        const u = users.find(x => x.id === tecnicoId);
        if (!u) return;
        u.name = nome; u.email = email; u.cpf = cpf; u.phone = tel; u.whatsapp = wa; u.specialty = esp;
        u.qualifications = quals;
        if (senha) u.password = senha;
        showToast(`Dados de "${nome}" atualizados.`, 'success');
    } else {
        if (users.find(x => x.email === email)) { showToast('Este e-mail já está cadastrado no sistema.', 'error'); return; }
        const newT = { id: 'tecnico_' + Date.now(), name: nome, email, password: senha, role: 'tecnico', cpf, phone: tel, whatsapp: wa, specialty: esp, qualifications: quals };
        users.push(newT);
        if (!app.state.tecnicoClients) app.state.tecnicoClients = {};
        app.state.tecnicoClients[newT.id] = [];
        showToast(`Técnico "${nome}" cadastrado com sucesso!`, 'success');
    }
    saveState();
    closeModal();
    renderGestorTecnicos();
}

function deleteTecnico(tecnicoId) {
    if (!confirm('Excluir este técnico? Os chamados vinculados serão mantidos no histórico.')) return;
    app.state.users = (app.state.users || []).filter(u => u.id !== tecnicoId);
    if (app.state.tecnicoClients) delete app.state.tecnicoClients[tecnicoId];
    saveState();
    renderGestorTecnicos();
}

function openAssignTecnicoClientModal(tecnicoId) {
    const t = (app.state.users || []).find(u => u.id === tecnicoId);
    if (!t) return;
    const allClients = app.state.clients || [];
    const assigned   = ((app.state.tecnicoClients || {})[tecnicoId] || []);
    showModal(`Atribuir clientes — ${t.name}`, `
        <p class="text-muted" style="margin-bottom:14px;">Selecione os clientes que serão atendidos por este técnico:</p>
        <div style="max-height:360px;overflow-y:auto;">
            ${allClients.length === 0
                ? '<p class="text-muted">Nenhum cliente cadastrado.</p>'
                : allClients.map(c => `
                    <label style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid var(--border);cursor:pointer;">
                        <input type="checkbox" value="${c.id}" ${assigned.includes(c.id) ? 'checked' : ''} style="width:16px;height:16px;">
                        <span><strong>${esc(c.name)}</strong> <small class="text-muted">${esc(c.product || '')}</small></span>
                    </label>`).join('')}
        </div>
        <div class="actions" style="margin-top:16px;">
            <button class="primary-btn" onclick="saveAssignTecnicoClients('${tecnicoId}')">Salvar</button>
            <button class="secondary-btn" onclick="closeModal()">Cancelar</button>
        </div>
    `);
}

function saveAssignTecnicoClients(tecnicoId) {
    const boxes = document.querySelectorAll('#modalContent input[type=checkbox]');
    const selected = Array.from(boxes).filter(cb => cb.checked).map(cb => cb.value);
    if (!app.state.tecnicoClients) app.state.tecnicoClients = {};
    app.state.tecnicoClients[tecnicoId] = selected;
    saveState();
    closeModal();
    renderGestorTecnicos();
}

function renderGestorChamados() {
    const chamados = (app.state.chamados || []).sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
    const tecnicos = (app.state.users || []).filter(u => u.role === 'tecnico');
    const clients  = app.state.clients || [];
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    el.innerHTML = `
        <div class="section-header">
            <div><h2>Todos os chamados</h2><p>Visão consolidada de todos os chamados do sistema.</p></div>
        </div>
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px;">
            ${['Todos','Aberto','Em andamento','Aguardando cliente','Resolvido','Fechado'].map(s =>
                `<button class="secondary-btn" style="font-size:0.8rem;padding:5px 12px;"
                    onclick="filterGestorChamados('${s}')">${s}</button>`
            ).join('')}
        </div>
        <div id="gestorChamadosList">
            ${_gestorChamadosListHtml(chamados, clients, tecnicos)}
        </div>
    `;
    showSection('dynamicContent');
}

function _gestorChamadosListHtml(chamados, clients, tecnicos) {
    if (chamados.length === 0) return '<div class="card"><p class="text-muted">Nenhum chamado registrado.</p></div>';
    return chamados.map(ch => {
        const c   = clients.find(x => x.id === ch.clientId);
        const tec = tecnicos.find(x => x.id === ch.tecnicoId);
        const priorityIcon = ch.priority === 'Urgente' ? '🔴' : ch.priority === 'Normal' ? '🟡' : '🟢';
        const statusCls = {
            'Aberto':             'chamado-status-aberto',
            'Em andamento':       'chamado-status-andamento',
            'Aguardando cliente': 'chamado-status-aguardando',
            'Resolvido':          'chamado-status-resolvido',
            'Fechado':            'chamado-status-fechado'
        }[ch.status] || '';
        return `<div class="chamado-card" onclick="openChamadoDetail('${ch.id}')">
            <div class="chamado-header">
                <span class="chamado-title">${esc(ch.title)}</span>
                <span class="chamado-status-pill ${statusCls}">${esc(ch.status)}</span>
            </div>
            <div class="chamado-meta">
                ${priorityIcon} ${esc(ch.priority)} &bull; Cliente: <strong>${c ? esc(c.name) : '—'}</strong> &bull; Técnico: <strong>${tec ? esc(tec.name) : '—'}</strong> &bull; ${ch.updatedAt}
            </div>
        </div>`;
    }).join('');
}

function filterGestorChamados(status) {
    const tecnicos = (app.state.users || []).filter(u => u.role === 'tecnico');
    const clients  = app.state.clients || [];
    let chams = app.state.chamados || [];
    if (status !== 'Todos') chams = chams.filter(c => c.status === status);
    chams = chams.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
    const el = document.getElementById('gestorChamadosList');
    if (el) el.innerHTML = _gestorChamadosListHtml(chams, clients, tecnicos);
}

/* ═══════════════════════════════════════════════════════════════════
   GESTÃO DE PRODUTOS
═══════════════════════════════════════════════════════════════════ */

function getProdutosVisiveis(role) {
    return (app.state.produtos_config || []).filter(p =>
        p.status === 'ativo' && (p.visibilidade || []).includes(role || app.currentUser?.role)
    );
}

function getPlanosProduto(productName) {
    const prod = (app.state.produtos_config || []).find(p => p.nome === productName);
    if (prod && (prod.planos || []).length > 0) return prod.planos;
    return planList.map(p => ({ id: p.name, nome: p.name, valor: p.price }));
}

function buildPlanOptsForProduct(productName, selectedPlan) {
    const plans = getPlanosProduto(productName);
    return plans.map(p => `<option value="${esc(p.nome)}" ${selectedPlan === p.nome ? 'selected' : ''}>${esc(p.nome)}${p.valor !== null && p.valor !== undefined ? ' — R$ ' + p.valor.toFixed(2).replace('.', ',') : ' (personalizado)'}</option>`).join('');
}

function renderGestorProdutos() {
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    const prods = app.state.produtos_config || [];
    el.innerHTML = `
        <div class="section-header" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:1.25rem;flex-wrap:wrap;gap:12px;">
            <div>
                <h2>📦 Gestão de Produtos</h2>
                <p class="section-subtitle">${prods.length} produto${prods.length !== 1 ? 's' : ''} · ${prods.filter(p => p.status === 'ativo').length} ativo${prods.filter(p => p.status === 'ativo').length !== 1 ? 's' : ''}</p>
            </div>
            <button class="primary-btn" onclick="openProdutoModal()">+ Novo Produto</button>
        </div>
        <div class="produtos-grid">
            ${prods.length === 0 ? '<div class="empty-state">Nenhum produto cadastrado.</div>' :
            prods.map(p => {
                const catInfo = PROD_CATEGORIES.find(c => c.key === p.categoria) || {};
                const comTxt = p.comissao
                    ? (p.comissao.tipo === 'fixo' ? `R$ ${formatCurrency(p.comissao.valor)} fixo` : `${p.comissao.valor}% sobre venda`) + (p.comissao.recorrencia ? ` · ${p.comissao.recorrencia}% rec.` : '')
                    : '—';
                const visLabels = (p.visibilidade || []).map(v => v === 'consultor' ? '👥' : '🔧').join(' ');
                const minVal = (p.planos || []).filter(pl => pl.valor).reduce((m, pl) => (!m || pl.valor < m) ? pl.valor : m, null);
                return `<div class="produto-card${p.status !== 'ativo' ? ' inativo' : ''}">
                    <div class="prod-card-header">
                        <span class="prod-card-icon">${esc(p.icone || '📦')}</span>
                        <div style="flex:1;min-width:0;">
                            <div class="prod-card-nome">${esc(p.nome)}${p.destaque ? ' <span class="badge-destaque">★</span>' : ''}</div>
                            <span class="prod-cat-badge">${catInfo.icon || ''} ${catInfo.label || p.categoria}</span>
                        </div>
                        <label class="toggle-switch" title="${p.status === 'ativo' ? 'Desativar' : 'Ativar'}">
                            <input type="checkbox" ${p.status === 'ativo' ? 'checked' : ''} onchange="toggleProdutoStatus('${esc(p.id)}')">
                            <span class="toggle-slider"></span>
                        </label>
                    </div>
                    <p class="prod-card-desc">${esc(p.descricao)}</p>
                    <div class="prod-card-meta">
                        <span>💰 ${(p.planos || []).length} planos${minVal ? ` · a partir R$${formatCurrency(minVal)}` : ''}</span>
                        <span>🤝 ${comTxt}</span>
                    </div>
                    <div class="prod-card-vis">${visLabels || '—'} Visível para: ${(p.visibilidade || []).join(', ') || 'ninguém'}</div>
                    <div class="prod-card-actions">
                        <button class="secondary-btn" style="flex:1;font-size:0.82rem;padding:6px;" onclick="openProdutoModal('${esc(p.id)}')">✏️ Editar</button>
                        <button class="secondary-btn" style="flex:1;font-size:0.82rem;padding:6px;" onclick="openGerenciarPlanosModal('${esc(p.id)}')">📋 Planos (${(p.planos || []).length})</button>
                        <button class="secondary-btn" style="font-size:0.82rem;padding:6px;color:#ef4444;" onclick="deleteProduto('${esc(p.id)}')">🗑</button>
                    </div>
                </div>`;
            }).join('')}
        </div>`;
}

function openProdutoModal(id = null) {
    const ed = id ? (app.state.produtos_config || []).find(p => p.id === id) : null;
    const catOpts = PROD_CATEGORIES.map(c => `<option value="${c.key}" ${ed?.categoria === c.key ? 'selected' : ''}>${c.icon} ${c.label}</option>`).join('');
    const pagMap = { pix: 'PIX', boleto: 'Boleto bancário', cartao: 'Cartão de crédito', transferencia: 'Transferência', personalizado: 'Personalizado' };
    const pagChks = Object.keys(pagMap).map(k => `<label class="checkbox-label"><input type="checkbox" name="prodPag" value="${k}" ${(ed?.pagamentos || ['pix','boleto','cartao']).includes(k) ? 'checked' : ''} /><span>${pagMap[k]}</span></label>`).join('');
    const visChks = [['consultor','👥 Consultores'],['instalador','🔧 Instaladores']].map(([v,l]) => `<label class="checkbox-label"><input type="checkbox" name="prodVis" value="${v}" ${(ed?.visibilidade || ['consultor','instalador']).includes(v) ? 'checked' : ''} /><span>${l}</span></label>`).join('');
    showModal(ed ? `Editar: ${ed.nome}` : 'Novo Produto', `
        <form id="produtoForm" class="form-grid two-columns">
            <div class="form-section-title">Informações Básicas</div>
            <div class="field"><label>Nome *</label><input id="pNome" type="text" value="${esc(ed?.nome)}" required /></div>
            <div class="field"><label>Categoria *</label><select id="pCategoria">${catOpts}</select></div>
            <div class="field full-width"><label>Descrição</label><textarea id="pDesc" rows="2">${esc(ed?.descricao)}</textarea></div>
            <div class="field"><label>Ícone (emoji)</label><input id="pIcone" type="text" maxlength="4" placeholder="📦" value="${esc(ed?.icone || '')}" /></div>
            <div class="field" style="display:flex;gap:16px;align-items:center;padding-top:1.5rem;">
                <label class="checkbox-label"><input type="checkbox" id="pStatus" ${(ed?.status ?? 'ativo') === 'ativo' ? 'checked' : ''} /><span>Produto ativo</span></label>
                <label class="checkbox-label"><input type="checkbox" id="pDestaque" ${ed?.destaque ? 'checked' : ''} /><span>★ Destaque</span></label>
            </div>
            <div class="form-section-title">Preços</div>
            <div class="field"><label>Adesão/Instalação (R$)</label><input id="pAdesao" type="number" min="0" step="0.01" value="${ed?.adesao ?? 0}" /></div>
            <div class="field"><label>Mensalidade base (R$)</label><input id="pMensalidade" type="number" min="0" step="0.01" value="${ed?.mensalidade ?? ''}" /></div>
            <div class="field"><label>Desconto anual (%)</label><input id="pDescontoAnual" type="number" min="0" max="100" value="${ed?.descontoAnual ?? 0}" /></div>
            <div class="field"><label>Condições especiais</label><input id="pCondicoes" type="text" placeholder="Ex: combo, indicação..." value="${esc(ed?.condicoesEspeciais || '')}" /></div>
            <div class="form-section-title">Formas de Pagamento</div>
            <div class="field full-width"><div class="checkbox-group">${pagChks}</div></div>
            <div class="field"><label>Parcelas no cartão</label><input id="pParcelas" type="number" min="1" max="24" value="${ed?.parcelasCartao ?? 12}" /></div>
            <div class="field"><label>Pagamento personalizado</label><input id="pPagPersonalizado" type="text" placeholder="Descreva..." value="${esc(ed?.pagamentoPersonalizado || '')}" /></div>
            <div class="form-section-title">Comissão por Venda</div>
            <div class="field"><label>Tipo</label><select id="pComTipo"><option value="fixo" ${(ed?.comissao?.tipo ?? 'fixo') === 'fixo' ? 'selected' : ''}>Valor fixo (R$)</option><option value="percentual" ${ed?.comissao?.tipo === 'percentual' ? 'selected' : ''}>Percentual (%)</option></select></div>
            <div class="field"><label>Valor de comissão</label><input id="pComValor" type="number" min="0" step="0.01" value="${ed?.comissao?.valor ?? 50}" /></div>
            <div class="field"><label>% recorrência mensal</label><input id="pComRecorrencia" type="number" min="0" max="100" step="0.1" value="${ed?.comissao?.recorrencia ?? 10}" /></div>
            <div class="form-section-title">Visibilidade</div>
            <div class="field full-width"><div class="checkbox-group">${visChks}</div></div>
            <div id="produtoFormError" class="error-text full-width"></div>
            <div class="actions full-width"><button type="submit" class="primary-btn">Salvar produto</button><button type="button" class="secondary-btn" onclick="closeModal()">Cancelar</button></div>
        </form>`);
    document.getElementById('produtoForm').addEventListener('submit', (e) => { e.preventDefault(); saveProduto(id); });
}

function saveProduto(id = null) {
    const nome = document.getElementById('pNome').value.trim();
    const errEl = document.getElementById('produtoFormError');
    errEl.textContent = '';
    if (!nome) { errEl.textContent = 'Nome obrigatório.'; return; }
    const pagamentos = [...document.querySelectorAll('input[name="prodPag"]:checked')].map(i => i.value);
    const visibilidade = [...document.querySelectorAll('input[name="prodVis"]:checked')].map(i => i.value);
    const data = {
        nome,
        descricao:    document.getElementById('pDesc').value.trim(),
        categoria:    document.getElementById('pCategoria').value,
        icone:        document.getElementById('pIcone').value.trim() || '📦',
        status:       document.getElementById('pStatus').checked ? 'ativo' : 'inativo',
        destaque:     document.getElementById('pDestaque').checked,
        adesao:       Number(document.getElementById('pAdesao').value) || 0,
        mensalidade:  Number(document.getElementById('pMensalidade').value) || 0,
        descontoAnual: Number(document.getElementById('pDescontoAnual').value) || 0,
        condicoesEspeciais: document.getElementById('pCondicoes').value.trim(),
        pagamentos, parcelasCartao: Number(document.getElementById('pParcelas').value) || 12,
        pagamentoPersonalizado: document.getElementById('pPagPersonalizado').value.trim(),
        comissao: { tipo: document.getElementById('pComTipo').value, valor: Number(document.getElementById('pComValor').value) || 0, recorrencia: Number(document.getElementById('pComRecorrencia').value) || 0 },
        visibilidade
    };
    if (id) {
        const prod = (app.state.produtos_config || []).find(p => p.id === id);
        if (prod) Object.assign(prod, data);
    } else {
        if (!app.state.produtos_config) app.state.produtos_config = [];
        app.state.produtos_config.push({ id: `prod_${Date.now()}`, planos: [], ...data });
    }
    saveState(); closeModal(); renderGestorProdutos();
}

function deleteProduto(id) {
    const prod = (app.state.produtos_config || []).find(p => p.id === id);
    if (!prod || !confirm(`Excluir o produto "${prod.nome}"?`)) return;
    app.state.produtos_config = app.state.produtos_config.filter(p => p.id !== id);
    saveState(); renderGestorProdutos();
}

function toggleProdutoStatus(id) {
    const prod = (app.state.produtos_config || []).find(p => p.id === id);
    if (!prod) return;
    prod.status = prod.status === 'ativo' ? 'inativo' : 'ativo';
    saveState(); renderGestorProdutos();
}

function openGerenciarPlanosModal(prodId) {
    const prod = (app.state.produtos_config || []).find(p => p.id === prodId);
    if (!prod) return;
    const renderList = () => {
        const planos = prod.planos || [];
        return planos.length === 0
            ? '<p style="color:var(--text-muted);text-align:center;padding:16px 0;">Nenhum plano criado ainda.</p>'
            : planos.map(pl => `<div class="plano-row">
                <div style="flex:1;min-width:0;">
                    <strong>${esc(pl.nome)}</strong>
                    <span style="color:var(--text-muted);margin-left:8px;">${pl.valor !== null && pl.valor !== undefined ? `R$ ${formatCurrency(pl.valor)}/mês` : 'Personalizado'}</span>
                    ${pl.descricao ? `<div style="font-size:0.8rem;color:var(--text-soft);">${esc(pl.descricao)}</div>` : ''}
                    ${(pl.itens||[]).length ? `<div style="font-size:0.77rem;color:var(--text-muted);">${pl.itens.map(i => `• ${i}`).join('  ')}</div>` : ''}
                </div>
                <div style="display:flex;gap:6px;flex-shrink:0;">
                    <button class="secondary-btn" style="font-size:0.78rem;padding:4px 9px;" onclick="openEditarPlanoModal('${esc(prodId)}','${esc(pl.id)}')">✏️</button>
                    <button class="secondary-btn" style="font-size:0.78rem;padding:4px 9px;color:#ef4444;" onclick="excluirPlanoProduto('${esc(prodId)}','${esc(pl.id)}')">🗑</button>
                </div>
            </div>`).join('');
    };
    showModal(`📋 Planos — ${prod.nome}`, `
        <div id="planosListContainer">${renderList()}</div>
        <button class="primary-btn" style="width:100%;margin-top:12px;" onclick="openEditarPlanoModal('${esc(prodId)}',null)">+ Adicionar Plano</button>
        <button class="secondary-btn" style="width:100%;margin-top:8px;" onclick="closeModal()">Fechar</button>`);
}

function openEditarPlanoModal(prodId, planId) {
    const prod = (app.state.produtos_config || []).find(p => p.id === prodId);
    if (!prod) return;
    const pl = planId ? (prod.planos || []).find(p => p.id === planId) : null;
    showModal(pl ? 'Editar Plano' : 'Novo Plano', `
        <form id="planoForm" class="form-grid">
            <div class="field"><label>Nome *</label><input id="plNome" type="text" value="${esc(pl?.nome)}" required /></div>
            <div class="field"><label>Valor R$/mês (vazio = personalizado)</label><input id="plValor" type="number" min="0" step="0.01" value="${pl?.valor ?? ''}" placeholder="Ex: 54.90" /></div>
            <div class="field full-width"><label>Descrição</label><input id="plDesc" type="text" value="${esc(pl?.descricao)}" placeholder="Ex: Ideal para autônomos" /></div>
            <div class="field full-width"><label>Itens inclusos (um por linha)</label><textarea id="plItens" rows="5" placeholder="Localização em tempo real&#10;Histórico 30 dias&#10;...">${esc((pl?.itens || []).join('\n'))}</textarea></div>
            <div id="planoError" class="error-text full-width"></div>
            <div class="actions full-width">
                <button type="submit" class="primary-btn">Salvar</button>
                <button type="button" class="secondary-btn" onclick="openGerenciarPlanosModal('${esc(prodId)}')">← Voltar</button>
            </div>
        </form>`);
    document.getElementById('planoForm').addEventListener('submit', (e) => { e.preventDefault(); salvarPlanoProduto(prodId, planId); });
}

function salvarPlanoProduto(prodId, planId) {
    const prod = (app.state.produtos_config || []).find(p => p.id === prodId);
    if (!prod) return;
    const nome = document.getElementById('plNome').value.trim();
    const errEl = document.getElementById('planoError');
    errEl.textContent = '';
    if (!nome) { errEl.textContent = 'Nome obrigatório.'; return; }
    const valorRaw = document.getElementById('plValor').value.trim();
    const valor = valorRaw !== '' ? Number(valorRaw) : null;
    const itens = document.getElementById('plItens').value.split('\n').map(s => s.trim()).filter(Boolean);
    const plData = { nome, valor, descricao: document.getElementById('plDesc').value.trim(), itens };
    if (planId) {
        const pl = (prod.planos || []).find(p => p.id === planId);
        if (pl) Object.assign(pl, plData);
    } else {
        if (!prod.planos) prod.planos = [];
        prod.planos.push({ id: `pln_${Date.now()}`, ...plData });
    }
    saveState(); openGerenciarPlanosModal(prodId);
}

function excluirPlanoProduto(prodId, planId) {
    const prod = (app.state.produtos_config || []).find(p => p.id === prodId);
    if (!prod || !confirm('Excluir este plano?')) return;
    prod.planos = (prod.planos || []).filter(p => p.id !== planId);
    saveState(); openGerenciarPlanosModal(prodId);
}

/* ═══════════════════════════════════════════════════════════════════
   EDITOR DE FORMULÁRIOS
═══════════════════════════════════════════════════════════════════ */

function getFormFields(formId) {
    const defaults = DEFAULT_FORM_CONFIGS[formId] || [];
    const stored = ((app.state.formConfigs || {})[formId] || {}).fields || [];
    const overrides = {};
    stored.forEach(f => { overrides[f.id] = f; });
    const result = defaults.map(def => ({
        ...def,
        ...(overrides[def.id] ? { active: overrides[def.id].active, required: overrides[def.id].required, label: overrides[def.id].label ?? def.label, order: overrides[def.id].order ?? def.order } : {})
    }));
    stored.filter(f => !f.system).forEach(f => result.push({ ...f }));
    return result.sort((a, b) => a.order - b.order);
}

function applyFormConfig(formId) {
    const fields = getFormFields(formId);
    const map = FORM_FIELD_INPUT_MAP[formId] || {};
    fields.filter(f => f.system).forEach(field => {
        const mapping = map[field.id];
        if (!mapping) return;
        let wrapperEl = null;
        if (mapping.inputs) {
            const inp = document.getElementById(mapping.inputs[0]);
            if (inp) wrapperEl = inp.closest('.field');
        } else if (mapping.selector) {
            const el = document.querySelector('#genericModal ' + mapping.selector);
            if (el) wrapperEl = el.closest('.field');
        }
        if (!wrapperEl) return;
        wrapperEl.style.display = field.active === false ? 'none' : '';
        if (field.active !== false && mapping.inputs) {
            const inp = document.getElementById(mapping.inputs[0]);
            if (inp) {
                if (field.required) inp.setAttribute('required', '');
                else inp.removeAttribute('required');
            }
        }
    });
    const customFields = fields.filter(f => !f.system && f.active !== false);
    if (customFields.length > 0) {
        const formEl = document.querySelector('#genericModal form');
        if (formEl) {
            const actionsEl = formEl.querySelector('.actions');
            const section = document.createElement('div');
            section.innerHTML = `<div class="form-section-title">Campos Adicionais</div>${customFields.map(f => renderCustomFieldInput(f, null)).join('')}`;
            actionsEl ? formEl.insertBefore(section, actionsEl) : formEl.appendChild(section);
        }
    }
}

function renderCustomFieldInput(field, value) {
    const val = value ?? '';
    const req = field.required ? ' *' : '';
    const reqAttr = field.required ? ' required' : '';
    switch (field.type) {
        case 'text': case 'email': case 'tel': case 'number':
            return `<div class="field"><label>${esc(field.label)}${req}</label><input id="cf_${esc(field.id)}" type="${field.type}"${reqAttr} value="${esc(String(val))}" placeholder="${esc(field.label)}" /></div>`;
        case 'textarea':
            return `<div class="field full-width"><label>${esc(field.label)}${req}</label><textarea id="cf_${esc(field.id)}"${reqAttr} rows="2">${esc(String(val))}</textarea></div>`;
        case 'date':
            return `<div class="field"><label>${esc(field.label)}${req}</label><input id="cf_${esc(field.id)}" type="date"${reqAttr} value="${esc(String(val))}" /></div>`;
        case 'select': {
            const opts = (field.options || []).map(o => `<option value="${esc(o)}" ${val === o ? 'selected' : ''}>${esc(o)}</option>`).join('');
            return `<div class="field"><label>${esc(field.label)}${req}</label><select id="cf_${esc(field.id)}"${reqAttr}><option value="">Selecione...</option>${opts}</select></div>`;
        }
        case 'radio': {
            const rOpts = (field.options || ['Sim', 'Não']).map(o => `<label class="checkbox-label"><input type="radio" name="cf_${esc(field.id)}" value="${esc(o)}" ${val === o ? 'checked' : ''} /><span>${esc(o)}</span></label>`).join('');
            return `<div class="field"><label>${esc(field.label)}</label><div style="display:flex;gap:12px;">${rOpts}</div></div>`;
        }
        case 'checkbox':
            return `<div class="field"><label class="checkbox-label"><input type="checkbox" id="cf_${esc(field.id)}" ${val ? 'checked' : ''} /><span>${esc(field.label)}</span></label></div>`;
        case 'multicheck': {
            const vals = Array.isArray(val) ? val : [];
            const mcOpts = (field.options || []).map(o => `<label class="checkbox-label"><input type="checkbox" name="cfm_${esc(field.id)}" value="${esc(o)}" ${vals.includes(o) ? 'checked' : ''} /><span>${esc(o)}</span></label>`).join('');
            return `<div class="field full-width"><label>${esc(field.label)}</label><div class="checkbox-group">${mcOpts}</div></div>`;
        }
        default: return '';
    }
}

const FIELD_TYPE_LABELS = {
    text: 'Texto simples', email: 'E-mail', tel: 'Telefone', number: 'Número', textarea: 'Texto longo',
    date: 'Data', select: 'Seleção única', radio: 'Opção', checkbox: 'Checkbox', multicheck: 'Múltipla escolha',
    yesno: 'Sim / Não', file: 'Anexo de arquivo', camera: 'Foto pela câmera', password: 'Senha'
};

const FORM_LABELS = { cliente: 'Cadastro de Cliente', consultor: 'Cadastro de Consultor', instalador: 'Cadastro de Instalador' };
let _activeFormTab = 'cliente';

function renderGestorFormEditor() {
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    const tab = _activeFormTab;
    el.innerHTML = `
        <div class="section-header" style="margin-bottom:1rem;">
            <h2>🔧 Editor de Formulários</h2>
            <p class="section-subtitle">Configure campos de qualquer formulário. As alterações refletem imediatamente.</p>
        </div>
        <div class="form-editor-tabs">
            ${Object.entries(FORM_LABELS).map(([key, label]) =>
                `<button class="form-editor-tab${tab === key ? ' active' : ''}" onclick="_activeFormTab='${key}'; renderGestorFormEditor();">${label}</button>`
            ).join('')}
        </div>
        <div id="formEditorContent">${renderFormFieldsEditor(tab)}</div>`;
}

function renderFormFieldsEditor(formId) {
    const fields = getFormFields(formId);
    const history = ((app.state.formConfigs || {})[formId] || {}).history || [];
    const LOCKED_REQ = ['fc_name','fc_phone','fc_product','fc_plan','fc_fee','cc_name','cc_email','cc_pass','ic_name','ic_email','ic_pass','ic_cpf','ic_store'];
    return `
        <div style="display:flex;justify-content:space-between;align-items:center;margin:1rem 0 0.75rem;flex-wrap:wrap;gap:8px;">
            <span style="font-size:0.83rem;color:var(--text-muted);">${fields.length} campos · ${fields.filter(f => f.active !== false).length} ativos</span>
            <div style="display:flex;gap:8px;flex-wrap:wrap;">
                <button class="secondary-btn" style="font-size:0.82rem;" onclick="openAddFieldModal('${formId}')">+ Campo personalizado</button>
                <button class="secondary-btn" style="font-size:0.82rem;color:#f59e0b;" onclick="resetFormConfig('${formId}')">↺ Resetar padrão</button>
            </div>
        </div>
        <div class="form-fields-table">
            <div class="fft-header">
                <span style="flex:2;">Campo</span>
                <span style="flex:1;text-align:center;">Tipo</span>
                <span style="flex:1;text-align:center;">Obrigatório</span>
                <span style="flex:1;text-align:center;">Ativo</span>
                <span style="flex:1;text-align:center;">Ações</span>
            </div>
            ${fields.map((f, idx) => {
                const reqLocked = LOCKED_REQ.includes(f.id);
                return `<div class="fft-row${f.active === false ? ' fft-inactive' : ''}">
                    <span style="flex:2;font-weight:${f.system ? '600' : '400'};font-size:0.88rem;">${esc(f.label)}${!f.system ? ' <span class="badge-custom">✦</span>' : ''}</span>
                    <span style="flex:1;text-align:center;"><span class="field-type-badge">${FIELD_TYPE_LABELS[f.type] || f.type}</span></span>
                    <span style="flex:1;text-align:center;">${reqLocked
                        ? '<span title="Obrigatório fixo" style="font-size:0.85rem;">🔒</span>'
                        : `<label class="toggle-switch toggle-sm"><input type="checkbox" ${f.required ? 'checked' : ''} onchange="toggleFormFieldRequired('${formId}','${f.id}')" /><span class="toggle-slider"></span></label>`
                    }</span>
                    <span style="flex:1;text-align:center;"><label class="toggle-switch toggle-sm"><input type="checkbox" ${f.active !== false ? 'checked' : ''} onchange="toggleFormFieldActive('${formId}','${f.id}')" /><span class="toggle-slider"></span></label></span>
                    <span style="flex:1;display:flex;gap:3px;justify-content:center;align-items:center;">
                        <button class="icon-btn" title="Cima" ${idx === 0 ? 'disabled' : ''} onclick="moveFormField('${formId}','${f.id}',-1)">↑</button>
                        <button class="icon-btn" title="Baixo" ${idx === fields.length - 1 ? 'disabled' : ''} onclick="moveFormField('${formId}','${f.id}',1)">↓</button>
                        <button class="icon-btn" title="Renomear" onclick="openRenameFieldModal('${formId}','${f.id}')">✏️</button>
                        ${!f.system ? `<button class="icon-btn" title="Excluir" style="color:#ef4444;" onclick="deleteCustomField('${formId}','${f.id}')">🗑</button>` : ''}
                    </span>
                </div>`;
            }).join('')}
        </div>
        ${history.length > 0 ? `<details style="margin-top:1.25rem;"><summary style="cursor:pointer;font-size:0.83rem;color:var(--text-muted);">📋 Histórico (${history.length})</summary>
            <div style="margin-top:8px;display:flex;flex-direction:column;gap:4px;">
                ${history.slice(-10).reverse().map(h => `<div style="font-size:0.78rem;color:var(--text-muted);padding:4px 8px;background:var(--surface-2);border-radius:6px;">${esc(h.at)} — ${esc(h.action)}</div>`).join('')}
            </div></details>` : ''}`;
}

function _saveFormFieldOverride(formId, fieldId, overrideData) {
    if (!app.state.formConfigs) app.state.formConfigs = {};
    if (!app.state.formConfigs[formId]) app.state.formConfigs[formId] = { fields: [], history: [] };
    const config = app.state.formConfigs[formId];
    const existing = config.fields.find(f => f.id === fieldId);
    const histAction = overrideData._histAction;
    delete overrideData._histAction;
    if (existing) Object.assign(existing, overrideData);
    else config.fields.push({ id: fieldId, ...overrideData });
    if (!config.history) config.history = [];
    if (histAction) config.history.push({ at: new Date().toLocaleString('pt-BR'), action: histAction });
    saveState();
}

function toggleFormFieldActive(formId, fieldId) {
    const f = getFormFields(formId).find(f => f.id === fieldId);
    if (!f) return;
    _saveFormFieldOverride(formId, fieldId, { active: f.active === false, _histAction: `"${f.label}" ${f.active === false ? 'ativado' : 'desativado'}` });
    document.getElementById('formEditorContent').innerHTML = renderFormFieldsEditor(formId);
}

function toggleFormFieldRequired(formId, fieldId) {
    const f = getFormFields(formId).find(f => f.id === fieldId);
    if (!f) return;
    _saveFormFieldOverride(formId, fieldId, { required: !f.required, _histAction: `"${f.label}" marcado como ${!f.required ? 'obrigatório' : 'opcional'}` });
    document.getElementById('formEditorContent').innerHTML = renderFormFieldsEditor(formId);
}

function moveFormField(formId, fieldId, dir) {
    const fields = getFormFields(formId);
    const idx = fields.findIndex(f => f.id === fieldId);
    if (idx < 0) return;
    const targetIdx = idx + dir;
    if (targetIdx < 0 || targetIdx >= fields.length) return;
    const thisOrder = fields[idx].order;
    const otherOrder = fields[targetIdx].order;
    _saveFormFieldOverride(formId, fieldId, { order: otherOrder, _histAction: `"${fields[idx].label}" reordenado` });
    _saveFormFieldOverride(formId, fields[targetIdx].id, { order: thisOrder });
    document.getElementById('formEditorContent').innerHTML = renderFormFieldsEditor(formId);
}

function openAddFieldModal(formId) {
    showModal('Adicionar Campo Personalizado', `
        <form id="addFieldForm" class="form-grid">
            <div class="field"><label>Nome do campo *</label><input id="afLabel" type="text" required placeholder="Ex: CNPJ da empresa" /></div>
            <div class="field"><label>Tipo *</label>
                <select id="afType" onchange="document.getElementById('afOptionsRow').style.display=['select','radio','multicheck'].includes(this.value)?'':'none'">
                    <option value="text">Texto simples</option>
                    <option value="textarea">Texto longo</option>
                    <option value="number">Número</option>
                    <option value="date">Data</option>
                    <option value="email">E-mail</option>
                    <option value="tel">Telefone</option>
                    <option value="checkbox">Sim/Não (checkbox)</option>
                    <option value="radio">Opção binária (radio)</option>
                    <option value="select">Seleção única (dropdown)</option>
                    <option value="multicheck">Múltipla escolha</option>
                </select>
            </div>
            <div class="field full-width" id="afOptionsRow" style="display:none;"><label>Opções (uma por linha)</label><textarea id="afOptions" rows="3" placeholder="Opção 1&#10;Opção 2&#10;Opção 3"></textarea></div>
            <div class="field"><label class="checkbox-label"><input type="checkbox" id="afRequired" /><span>Campo obrigatório</span></label></div>
            <div id="addFieldError" class="error-text full-width"></div>
            <div class="actions full-width">
                <button type="submit" class="primary-btn">Adicionar</button>
                <button type="button" class="secondary-btn" onclick="closeModal(); renderGestorFormEditor();">Cancelar</button>
            </div>
        </form>`);
    document.getElementById('addFieldForm').addEventListener('submit', (e) => { e.preventDefault(); saveCustomField(formId); });
}

function saveCustomField(formId) {
    const label = document.getElementById('afLabel').value.trim();
    const errEl = document.getElementById('addFieldError');
    errEl.textContent = '';
    if (!label) { errEl.textContent = 'Nome obrigatório.'; return; }
    const type = document.getElementById('afType').value;
    const required = document.getElementById('afRequired').checked;
    const options = ['select','radio','multicheck'].includes(type)
        ? document.getElementById('afOptions').value.split('\n').map(s => s.trim()).filter(Boolean) : [];
    const fields = getFormFields(formId);
    const maxOrder = fields.reduce((mx, f) => Math.max(mx, f.order), -1);
    if (!app.state.formConfigs) app.state.formConfigs = {};
    if (!app.state.formConfigs[formId]) app.state.formConfigs[formId] = { fields: [], history: [] };
    const config = app.state.formConfigs[formId];
    config.fields.push({ id: `cf_${Date.now()}`, label, type, required, active: true, system: false, order: maxOrder + 1, options });
    if (!config.history) config.history = [];
    config.history.push({ at: new Date().toLocaleString('pt-BR'), action: `Campo "${label}" adicionado` });
    saveState(); closeModal(); renderGestorFormEditor();
}

function deleteCustomField(formId, fieldId) {
    const f = getFormFields(formId).find(f => f.id === fieldId);
    if (!f || f.system || !confirm(`Excluir o campo "${f.label}"?`)) return;
    if (!app.state.formConfigs) app.state.formConfigs = {};
    if (!app.state.formConfigs[formId]) app.state.formConfigs[formId] = { fields: [], history: [] };
    const config = app.state.formConfigs[formId];
    config.fields = config.fields.filter(cf => cf.id !== fieldId);
    if (!config.history) config.history = [];
    config.history.push({ at: new Date().toLocaleString('pt-BR'), action: `Campo "${f.label}" excluído` });
    saveState();
    document.getElementById('formEditorContent').innerHTML = renderFormFieldsEditor(formId);
}

function openRenameFieldModal(formId, fieldId) {
    const f = getFormFields(formId).find(f => f.id === fieldId);
    if (!f) return;
    showModal('Renomear Campo', `
        <div class="field"><label>Novo nome</label><input id="rfLabel" type="text" value="${esc(f.label)}" required /></div>
        <div id="rfError" class="error-text" style="margin-top:6px;"></div>
        <div class="actions" style="margin-top:1rem;">
            <button class="primary-btn" onclick="saveFieldRename('${formId}','${fieldId}')">Salvar</button>
            <button class="secondary-btn" onclick="closeModal(); renderGestorFormEditor();">Cancelar</button>
        </div>`);
}

function saveFieldRename(formId, fieldId) {
    const newLabel = document.getElementById('rfLabel').value.trim();
    if (!newLabel) { document.getElementById('rfError').textContent = 'Nome obrigatório.'; return; }
    const f = getFormFields(formId).find(f => f.id === fieldId);
    _saveFormFieldOverride(formId, fieldId, { label: newLabel, _histAction: `"${f?.label}" renomeado para "${newLabel}"` });
    closeModal(); renderGestorFormEditor();
}

function resetFormConfig(formId) {
    if (!confirm(`Resetar "${FORM_LABELS[formId]}" para o padrão? Campos personalizados serão excluídos.`)) return;
    if (!app.state.formConfigs) app.state.formConfigs = {};
    app.state.formConfigs[formId] = { fields: [], history: [{ at: new Date().toLocaleString('pt-BR'), action: 'Formulário resetado para o padrão' }] };
    saveState();
    document.getElementById('formEditorContent').innerHTML = renderFormFieldsEditor(formId);
}

