const TOUR_STORAGE_KEY = 'tracktiv_tours';

const TOUR_STEPS = [
    { navId: null,           title: 'Bem-vindo ao Portal! 👋', message: 'Olá! Sou o TRAK, seu assistente virtual. Vou te mostrar tudo que você precisa para começar a vender e ganhar comissões. Leva menos de 1 minuto!' },
    { navId: 'c_dashboard',  title: 'Dashboard 📊',            message: 'Aqui você acompanha seu desempenho em tempo real: vendas do mês, comissões, leads no funil e seus rankings. Tudo numa tela só!' },
    { navId: 'c_crm',        title: 'CRM de Vendas 🎯',         message: 'Seu funil de vendas completo. Cadastre leads, mova entre etapas, acompanhe follow-ups e nunca perca uma oportunidade de fechar negócio.' },
    { navId: 'c_clientes',   title: 'Clientes 🌐',              message: 'Lista de todos os seus clientes ativos. Aqui você acessa o histórico, edita dados e cadastra novos clientes com facilidade.' },
    { navId: 'c_financeiro', title: 'Financeiro 💰',            message: 'Acompanhe suas comissões, recorrências e bônus de indicação. Use o simulador para calcular quanto você vai ganhar em cada cenário de venda.' },
    { navId: 'c_treinamentos', title: 'Treinamentos 🎓',        message: 'Módulos de treinamento completos para você dominar todos os produtos Tracktiv. Quanto mais você aprende, mais vende. Comece pelo Módulo 1!' },
    { navId: 'c_comunicados', title: 'Comunicados 📢',           message: 'Fique por dentro das novidades, metas e recados do gestor. Comunicados urgentes aparecem como alertas automáticos assim que você entrar.' },
    { navId: null,           title: 'Tudo pronto! 🚀',          message: 'Agora você conhece o portal. Minha dica: comece pelo Dashboard e depois cadastre seu primeiro lead no CRM. Qualquer dúvida, estou aqui!' }
];

function isTourCompleted(userId) {
    try {
        const data = JSON.parse(localStorage.getItem(TOUR_STORAGE_KEY) || '{}');
        return !!data[userId];
    } catch { return false; }
}

function setTourCompleted(userId) {
    try {
        const data = JSON.parse(localStorage.getItem(TOUR_STORAGE_KEY) || '{}');
        data[userId] = true;
        localStorage.setItem(TOUR_STORAGE_KEY, JSON.stringify(data));
    } catch {}
}

let _tourStep = 0;

function startTour() {
    _tourStep = 0;
    document.getElementById('tourOverlay').classList.remove('hidden');
    document.body.classList.add('tour-active');
    showTourStep(_tourStep);
}

function showTourStep(idx) {
    const steps = TOUR_STEPS;
    const step = steps[idx];
    if (!step) { tourEnd(); return; }

    document.getElementById('tourStepTitle').textContent = step.title;
    document.getElementById('tourMessage').textContent = step.message;

    // Progress fill
    const pct = ((idx) / (steps.length - 1)) * 100;
    document.getElementById('tourProgressFill').style.width = pct + '%';

    // Dots
    const dotsEl = document.getElementById('tourDots');
    dotsEl.innerHTML = steps.map((_, i) =>
        `<span class="tour-dot${i === idx ? ' active' : ''}"></span>`
    ).join('');

    // Nav/prev buttons
    const prevBtn = document.getElementById('tourPrevBtn');
    const nextBtn = document.getElementById('tourNextBtn');
    prevBtn.style.visibility = idx === 0 ? 'hidden' : 'visible';
    nextBtn.textContent = idx === steps.length - 1 ? 'Concluir ✓' : 'Próximo →';

    // Highlight nav item
    document.querySelectorAll('#navigationTabs .tour-highlight').forEach(el => el.classList.remove('tour-highlight'));
    if (step.navId) {
        const navBtn = document.querySelector(`#navigationTabs [data-nav-id="${step.navId}"]`);
        if (navBtn) navBtn.classList.add('tour-highlight');
    }
}

function tourNext() {
    if (window._activeTourSteps === PRESIDENTE_TOUR_STEPS) {
        const next = (window._presidenteTourStep || 0) + 1;
        if (next >= PRESIDENTE_TOUR_STEPS.length) { tourEnd(); return; }
        _showPresidenteTourStep(next);
        return;
    }
    const steps = TOUR_STEPS;
    if (_tourStep >= steps.length - 1) { tourEnd(); return; }
    _tourStep++;
    showTourStep(_tourStep);
}

function tourPrev() {
    if (window._activeTourSteps === PRESIDENTE_TOUR_STEPS) {
        const prev = Math.max(0, (window._presidenteTourStep || 0) - 1);
        _showPresidenteTourStep(prev);
        return;
    }
    if (_tourStep <= 0) return;
    _tourStep--;
    showTourStep(_tourStep);
}

function tourEnd() {
    document.getElementById('tourOverlay').classList.add('hidden');
    document.body.classList.remove('tour-active');
    document.querySelectorAll('#navigationTabs .tour-highlight').forEach(el => el.classList.remove('tour-highlight'));
    window._activeTourSteps = null;
    if (app.currentUser) setTourCompleted(app.currentUser.id);
}

function reopenTour() {
    if (!app.currentUser) return;
    // Reset completion so it can be replayed
    try {
        const data = JSON.parse(localStorage.getItem(TOUR_STORAGE_KEY) || '{}');
        delete data[app.currentUser.id];
        localStorage.setItem(TOUR_STORAGE_KEY, JSON.stringify(data));
    } catch {}
    startTour();
}

/* ═══════════════════════════════════════════════════════════════════
   RECUPERAÇÃO DE SENHA
═══════════════════════════════════════════════════════════════════ */

let _resetCode = '';
let _resetEmail = '';

function showForgotPassword() {
    document.getElementById('loginSection').classList.add('hidden');
    document.getElementById('resetSection').classList.remove('hidden');
    document.getElementById('resetStep1').classList.remove('hidden');
    document.getElementById('resetStep2').classList.add('hidden');
    document.getElementById('resetStep3').classList.add('hidden');
    document.getElementById('resetEmailInput').value = '';
    document.getElementById('resetError1').textContent = '';
}

function showLoginForm() {
    document.getElementById('loginSection').classList.remove('hidden');
    document.getElementById('resetSection').classList.add('hidden');
}

function resetStep1Submit() {
    const email = document.getElementById('resetEmailInput').value.trim().toLowerCase();
    const errEl = document.getElementById('resetError1');
    errEl.textContent = '';
    const user = (app.state.users || []).find(u => u.email === email);
    if (!user) { errEl.textContent = 'E-mail não encontrado.'; return; }
    _resetEmail = email;
    _resetCode = String(Math.floor(100000 + Math.random() * 900000));
    document.getElementById('resetCodeDisplay').textContent = _resetCode;
    document.getElementById('resetStep1').classList.add('hidden');
    document.getElementById('resetStep2').classList.remove('hidden');
    document.getElementById('resetCodeInput').value = '';
    document.getElementById('resetError2').textContent = '';
}

function resetStep2Submit() {
    const entered = document.getElementById('resetCodeInput').value.trim();
    const errEl = document.getElementById('resetError2');
    errEl.textContent = '';
    if (entered !== _resetCode) { errEl.textContent = 'Código incorreto. Tente novamente.'; return; }
    document.getElementById('resetStep2').classList.add('hidden');
    document.getElementById('resetStep3').classList.remove('hidden');
    document.getElementById('resetNewPass').value = '';
    document.getElementById('resetConfirmPass').value = '';
    document.getElementById('resetError3').textContent = '';
}

function resetStep3Submit() {
    const newPass     = document.getElementById('resetNewPass').value;
    const confirmPass = document.getElementById('resetConfirmPass').value;
    const errEl       = document.getElementById('resetError3');
    errEl.textContent = '';
    if (newPass.length < 6) { errEl.textContent = 'A senha deve ter pelo menos 6 caracteres.'; return; }
    if (newPass !== confirmPass) { errEl.textContent = 'As senhas não coincidem.'; return; }
    const user = (app.state.users || []).find(u => u.email === _resetEmail);
    if (!user) { errEl.textContent = 'Erro interno. Tente novamente.'; return; }
    user.password = newPass;
    saveState();
    document.getElementById('resetStep3').classList.add('hidden');
    document.getElementById('resetSuccess').classList.remove('hidden');
    setTimeout(() => {
        document.getElementById('resetSuccess').classList.add('hidden');
        showLoginForm();
    }, 2500);
}

/* ═══════════════════════════════════════════════════════════════════
   MURAL DE COMUNICADOS
═══════════════════════════════════════════════════════════════════ */

function getComunicadosAtivos() {
    if (!app.state || !app.state.comunicados) return [];
    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - 30);
    const cutoffISO = cutoff.toISOString().slice(0, 10);
    return (app.state.comunicados || []).filter(c => c.criadoEm >= cutoffISO);
}

function getComunicadosNaoLidos() {
    if (!app.currentUser) return [];
    const uid = app.currentUser.id;
    return getComunicadosAtivos().filter(c => !(c.lidos || []).includes(uid));
}

function markComunicadoRead(comId) {
    if (!app.currentUser) return;
    const uid = app.currentUser.id;
    const com = (app.state.comunicados || []).find(c => c.id === comId);
    if (com && !(com.lidos || []).includes(uid)) {
        com.lidos = [...(com.lidos || []), uid];
        saveState();
    }
}

let _urgenteQueue = [];
let _urgenteIdx = 0;

function checkUrgentePopup() {
    if (!app.currentUser) return;
    const uid = app.currentUser.id;
    _urgenteQueue = getComunicadosAtivos().filter(c =>
        c.prioridade === 'urgente' && !(c.lidos || []).includes(uid)
    );
    _urgenteIdx = 0;
    if (_urgenteQueue.length > 0) showUrgentePopupItem(0);
}

function showUrgentePopupItem(idx) {
    const com = _urgenteQueue[idx];
    if (!com) return;
    document.getElementById('urgentePopupTitulo').textContent = com.titulo;
    document.getElementById('urgentePopupMeta').textContent = `📅 ${com.criadoEm} · Por: Gestor`;
    document.getElementById('urgentePopupMsg').textContent = com.mensagem;
    const nextBtn = document.getElementById('urgentePopupNext');
    if (nextBtn) nextBtn.classList.toggle('hidden', _urgenteQueue.length <= 1 || idx >= _urgenteQueue.length - 1);
    document.getElementById('urgentePopup').classList.remove('hidden');
}

function urgentePopupNext() {
    markComunicadoRead(_urgenteQueue[_urgenteIdx].id);
    _urgenteIdx++;
    if (_urgenteIdx < _urgenteQueue.length) {
        showUrgentePopupItem(_urgenteIdx);
    } else {
        urgentePopupClose();
    }
    updateNotifBadge();
}

function urgentePopupClose() {
    if (_urgenteQueue[_urgenteIdx]) markComunicadoRead(_urgenteQueue[_urgenteIdx].id);
    document.getElementById('urgentePopup').classList.add('hidden');
    updateNotifBadge();
}

function renderGestorComunicados() {
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    const coms = (app.state.comunicados || []).sort((a, b) => b.criadoEm.localeCompare(a.criadoEm));
    const allUsers = (app.state.users || []).filter(u => ['consultor', 'instalador', 'tecnico'].includes(u.role));

    el.innerHTML = `
        <div class="section-header" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:1rem;">
            <div>
                <h2>📢 Mural de Comunicados</h2>
                <p class="section-subtitle">Crie e gerencie comunicados para consultores e instaladores.</p>
            </div>
            <button class="primary-btn" onclick="openComunicadoModal()">+ Novo Comunicado</button>
        </div>
        ${coms.length === 0 ? '<div class="empty-state">Nenhum comunicado criado ainda.</div>' :
        coms.map(c => {
            const lidos = (c.lidos || []).length;
            const total = allUsers.length;
            const priLabel = c.prioridade === 'urgente' ? '<span class="pill-urgente">🚨 Urgente</span>' :
                             c.prioridade === 'importante' ? '<span class="pill-importante">⚠️ Importante</span>' :
                             '<span class="pill-normal">📋 Normal</span>';
            return `<div class="comunicado-card ${c.prioridade}">
                <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:0.5rem;flex-wrap:wrap;">
                    <div style="flex:1;">
                        <div style="display:flex;align-items:center;gap:0.5rem;margin-bottom:0.25rem;">
                            ${priLabel}
                            <span class="comunicado-titulo">${esc(c.titulo)}</span>
                        </div>
                        <div class="comunicado-meta">📅 ${esc(c.criadoEm)}</div>
                        <div class="comunicado-msg">${esc(c.mensagem)}</div>
                    </div>
                    <div style="display:flex;gap:0.5rem;flex-shrink:0;align-items:flex-start;">
                        <button class="secondary-btn" style="padding:4px 10px;font-size:0.78rem;" onclick="openComunicadoLidosModal('${esc(c.id)}')">👁 ${lidos}/${total} lidos</button>
                        <button class="secondary-btn" style="padding:4px 10px;font-size:0.78rem;color:#ef4444;" onclick="deleteComunicado('${esc(c.id)}')">🗑</button>
                    </div>
                </div>
            </div>`;
        }).join('')}
    `;
}

function openComunicadoModal() {
    const modal = document.getElementById('genericModal');
    const body  = document.getElementById('modalBody');
    body.innerHTML = `
        <h3 style="margin-bottom:1rem;">📢 Novo Comunicado</h3>
        <label class="form-label">Título *</label>
        <input id="comTitulo" class="form-input" maxlength="80" placeholder="Ex: Meta de julho anunciada!">
        <label class="form-label" style="margin-top:0.75rem;">Mensagem *</label>
        <textarea id="comMensagem" class="form-input" rows="4" placeholder="Escreva o comunicado aqui..."></textarea>
        <label class="form-label" style="margin-top:0.75rem;">Prioridade</label>
        <select id="comPrioridade" class="form-input">
            <option value="normal">📋 Normal</option>
            <option value="importante">⚠️ Importante</option>
            <option value="urgente">🚨 Urgente</option>
        </select>
        <div id="comError" style="color:#ef4444;margin-top:0.5rem;font-size:0.85rem;"></div>
        <div style="display:flex;gap:0.75rem;margin-top:1.25rem;">
            <button class="primary-btn" style="flex:1;" onclick="saveComunicado()">Publicar</button>
            <button class="btn-outline" onclick="closeModal()">Cancelar</button>
        </div>`;
    modal.classList.remove('hidden');
}

function saveComunicado() {
    const titulo    = document.getElementById('comTitulo').value.trim();
    const mensagem  = document.getElementById('comMensagem').value.trim();
    const prioridade = document.getElementById('comPrioridade').value;
    const errEl     = document.getElementById('comError');
    errEl.textContent = '';
    if (!titulo) { errEl.textContent = 'Título obrigatório.'; return; }
    if (!mensagem) { errEl.textContent = 'Mensagem obrigatória.'; return; }
    const novo = {
        id: 'com_' + Date.now(),
        autorId: app.currentUser.id,
        titulo, mensagem, prioridade,
        criadoEm: todayISO(),
        lidos: []
    };
    app.state.comunicados = [novo, ...(app.state.comunicados || [])];
    saveState();
    closeModal();
    showToast(`Comunicado "${titulo}" publicado com sucesso!`, 'success');
    renderGestorComunicados();
}

function deleteComunicado(comId) {
    if (!confirm('Excluir este comunicado?')) return;
    app.state.comunicados = (app.state.comunicados || []).filter(c => c.id !== comId);
    saveState();
    renderGestorComunicados();
}

function openComunicadoLidosModal(comId) {
    const com = (app.state.comunicados || []).find(c => c.id === comId);
    if (!com) return;
    const allUsers = (app.state.users || []).filter(u => ['consultor', 'instalador', 'tecnico'].includes(u.role));
    const lidosIds = com.lidos || [];
    const modal = document.getElementById('genericModal');
    const body  = document.getElementById('modalBody');
    body.innerHTML = `
        <h3 style="margin-bottom:1rem;">👁 Quem leu: ${esc(com.titulo)}</h3>
        <div style="display:flex;flex-direction:column;gap:0.5rem;">
            ${allUsers.length === 0 ? '<div class="empty-state">Nenhum usuário.</div>' :
            allUsers.map(u => {
                const leu = lidosIds.includes(u.id);
                return `<div style="display:flex;justify-content:space-between;padding:0.5rem;background:var(--surface-2);border-radius:8px;">
                    <span>${esc(u.name)}</span>
                    <span style="color:${leu ? '#10b981' : '#6b7280'}">${leu ? '✓ Leu' : '— Não leu'}</span>
                </div>`;
            }).join('')}
        </div>
        <button class="btn-outline" style="margin-top:1rem;width:100%;" onclick="closeModal()">Fechar</button>`;
    modal.classList.remove('hidden');
}

function renderComunicadosMural() {
    const el = document.getElementById('dynamicContent');
    if (!el || !app.currentUser) return;
    const uid = app.currentUser.id;
    const coms = getComunicadosAtivos().sort((a, b) => b.criadoEm.localeCompare(a.criadoEm));

    // Mark all as read when opening the mural
    coms.forEach(c => markComunicadoRead(c.id));
    updateNotifBadge();

    el.innerHTML = `
        <div class="section-header" style="margin-bottom:1rem;">
            <h2>📢 Mural de Comunicados</h2>
            <p class="section-subtitle">Comunicados do gestor para você. Últimos 30 dias.</p>
        </div>
        ${coms.length === 0 ? '<div class="empty-state">Nenhum comunicado recente.</div>' :
        coms.map(c => {
            const priLabel = c.prioridade === 'urgente' ? '<span class="pill-urgente">🚨 Urgente</span>' :
                             c.prioridade === 'importante' ? '<span class="pill-importante">⚠️ Importante</span>' :
                             '<span class="pill-normal">📋 Normal</span>';
            return `<div class="comunicado-card ${c.prioridade}">
                <div style="display:flex;align-items:center;gap:0.5rem;margin-bottom:0.25rem;">
                    ${priLabel}
                    <span class="comunicado-titulo">${esc(c.titulo)}</span>
                </div>
                <div class="comunicado-meta">📅 ${esc(c.criadoEm)}</div>
                <div class="comunicado-msg">${esc(c.mensagem)}</div>
            </div>`;
        }).join('')}
    `;
}

/* ═══════════════════════════════════════════════════════════════════
   INIT
═══════════════════════════════════════════════════════════════════ */

function init() {
    loadState();
    applyBrandConfig();

    initGlobalSearch();

    // Verificar se é acesso via link público (consultor ou técnico)
    if (checkPublicCadastroParam()) return;
    if (checkTecnicoFormParam()) return;

    document.getElementById('loginForm').addEventListener('submit', handleLogin);
    document.getElementById('demoButton').addEventListener('click', handleDemo);

    document.getElementById('logoutBtn').addEventListener('click', () => {
        if (app.demoMode) exitDemoMode();
        app.currentUser = null;
        app.demoMode = false;
        document.getElementById('appScreen').classList.add('hidden');
        document.getElementById('loginScreen').classList.remove('hidden');
        document.getElementById('loginMessage').textContent = 'Use suas credenciais para acessar o portal. Clique em Demo para uma demonstração.';
    });

    document.getElementById('clienteLogoutBtn').addEventListener('click', () => {
        app.currentUser = null;
        document.getElementById('clientePortal').classList.add('hidden');
        document.getElementById('loginScreen').classList.remove('hidden');
        document.getElementById('loginMessage').textContent = 'Use suas credenciais para acessar o portal. Clique em Demo para uma demonstração.';
    });

    document.getElementById('openGestorClienteModalBtn').addEventListener('click', () => openGestorClienteModal());

    document.getElementById('closeModalBtn').addEventListener('click', closeModal);
    document.getElementById('modalBackdrop').addEventListener('click', e => {
        if (e.target === document.getElementById('modalBackdrop')) closeModal();
    });

    // Gestor buttons
    document.getElementById('openConsultorModalBtn').addEventListener('click',      () => openConsultorModal());
    document.getElementById('openConsultorModalBtn2').addEventListener('click',     () => openConsultorModal());
    document.getElementById('openInstaladorModalBtnDash').addEventListener('click', () => openInstaladorModal());
    document.getElementById('openInstaladorModalBtn').addEventListener('click',     () => openInstaladorModal());
    document.getElementById('openInstallationModalBtn').addEventListener('click',   () => openInstallationModal());
    document.getElementById('openCouponModalBtn').addEventListener('click',         () => openCouponModal());

    // Consultor buttons
    document.getElementById('openClientModalBtn').addEventListener('click',  () => openClientModal());
    document.getElementById('openClientModalBtn2').addEventListener('click', () => openClientModal());

    // Instalador buttons
    document.getElementById('openInstaladorClientModalBtn').addEventListener('click', () => openClientModal());
    document.getElementById('openInstaladorClientCRMBtn').addEventListener('click',   () => openClientModal());

    // Pre-render public sections
    renderProducts();
    renderTrainingModules();

    // Notification bell
    document.getElementById('notifBtn')?.addEventListener('click', e => {
        e.stopPropagation();
        toggleNotifPanel();
    });

    // Chat button
    document.getElementById('chatBtn')?.addEventListener('click', e => {
        e.stopPropagation();
        openChatOverlay(null);
    });

    // Chat overlay backdrop
    document.getElementById('chatOverlayBackdrop')?.addEventListener('click', () => {
        document.getElementById('chatOverlay')?.classList.add('hidden');
    });

    // Close notification panel when clicking outside
    document.addEventListener('click', e => {
        const panel = document.getElementById('notifPanel');
        const btn   = document.getElementById('notifBtn');
        if (panel && !panel.classList.contains('hidden') && !panel.contains(e.target) && e.target !== btn && !btn?.contains(e.target)) {
            panel.classList.add('hidden');
        }
    });

    // Feature 3: Check re-engagement queue on load
    checkReengagementQueue();
}

/* ═══════════════════════════════════════════════════════════════════
   FEATURE 1 — MOTOR DE CHURN PREDITIVO
═══════════════════════════════════════════════════════════════════ */

function calculateChurnScore(client) {
    if (!client || client.stage !== 'Fechado') return 0;
    let score = 0;

    // Sinal 1: Sem follow-up há 45+ dias (max 30pts)
    const fups = (app.state.followUps || []).filter(f => f.clientId === client.id);
    const lastFup = fups.length ? fups.sort((a,b) => (b.createdAt||'').localeCompare(a.createdAt||'')).find(f=>f.done) : null;
    if (lastFup) {
        const daysSince = Math.floor((Date.now() - new Date(lastFup.createdAt).getTime()) / 86400000);
        if (daysSince > 90) score += 30;
        else if (daysSince > 45) score += 20;
        else if (daysSince > 20) score += 10;
    } else {
        score += 25; // nunca teve follow-up
    }

    // Sinal 2: Chamado aberto há 7+ dias sem solução (max 25pts)
    const openChams = (app.state.chamados || []).filter(ch => ch.clientId === client.id && ['Aberto','Em andamento'].includes(ch.status));
    if (openChams.length > 0) {
        const oldest = openChams.sort((a,b) => a.createdAt.localeCompare(b.createdAt))[0];
        const daysOpen = Math.floor((Date.now() - new Date(oldest.createdAt).getTime()) / 86400000);
        if (daysOpen > 14) score += 25;
        else if (daysOpen > 7) score += 15;
        else score += 8;
    }

    // Sinal 3: Plano Essencial há mais de 6 meses (sem upgrade) (max 20pts)
    if (client.plan === 'Essencial' && client.closedDate) {
        const monthsClosed = Math.floor((Date.now() - new Date(client.closedDate + 'T00:00:00').getTime()) / (86400000 * 30));
        if (monthsClosed > 12) score += 20;
        else if (monthsClosed > 6) score += 12;
    }

    // Sinal 4: Sem anotações de contato há 60+ dias (max 15pts)
    const history = client.contactHistory || [];
    if (history.length === 0) {
        score += 10;
    } else {
        const last = history[history.length - 1];
        const ld = last.rawDate || (last.date ? new Date(last.date.split('/').reverse().join('-')).getTime() : 0);
        const daysSinceContact = Math.floor((Date.now() - ld) / 86400000);
        if (daysSinceContact > 60) score += 15;
        else if (daysSinceContact > 30) score += 8;
    }

    // Sinal 5: Score de propensão original baixo (<30) — comprou por preço, não por valor (max 10pts)
    const propScore = calcScore(client);
    if (propScore < 20) score += 10;
    else if (propScore < 30) score += 5;

    return Math.min(100, score);
}

function getChurnBadge(score) {
    if (score >= 70) return { label: 'Alto',   cls: 'high',   icon: '🔴', color: '#dc2626' };
    if (score >= 40) return { label: 'Médio',  cls: 'medium', icon: '🟡', color: '#d97706' };
    return                  { label: 'Baixo',  cls: 'low',    icon: '🟢', color: '#059669' };
}

function getChurnTrakMsg(score, client) {
    const badge = getChurnBadge(score);
    if (score >= 70) return `⚠️ Risco ALTO de churn! ${esc(client.name)} tem ${score} pontos de risco. Ligue agora — um cliente retido vale muito mais que reconquistar um perdido.`;
    if (score >= 40) return `🌡️ Atenção: risco MÉDIO detectado em ${esc(client.name)} (${score} pts). Uma chamada proativa pode fazer toda a diferença. Não espere o cliente reclamar.`;
    return `✅ ${esc(client.name)} está estável (${score} pts de risco). Ótimo trabalho! Continue o follow-up regular para manter assim.`;
}

function renderClientesEmRisco() {
    const el = document.getElementById('dynamicContent');
    if (!el) return;
    const uid   = app.currentUser.id;
    const role  = app.currentUser.role;
    const myClients = (app.state.clients || []).filter(c => c.stage === 'Fechado' && (role === 'gestor' || c.consultantId === uid || c.instaladorId === uid));
    const withScore = myClients.map(c => ({ c, score: calculateChurnScore(c) })).sort((a, b) => b.score - a.score);
    const atRisk = withScore.filter(x => x.score >= 40);

    const rows = withScore.map(({ c, score }) => {
        const badge = getChurnBadge(score);
        const cons = (app.state.users || []).find(u => u.id === c.consultantId);
        return `<tr>
            <td><strong>${esc(c.name)}</strong></td>
            ${role === 'gestor' ? `<td>${esc(cons?.name || '—')}</td>` : ''}
            <td>${esc(c.plan || '—')}</td>
            <td>R$ ${formatCurrency(c.monthlyFee)}</td>
            <td><span class="churn-score-badge churn-${badge.cls}">${badge.icon} ${score} pts — ${badge.label}</span></td>
            <td><div class="table-actions">
                <button class="small-btn" onclick="openChurnDetail('${c.id}')">🔍 Detalhes</button>
                ${c.isWhatsapp ? `<a href="https://wa.me/55${(c.phone||'').replace(/\D/g,'')}" target="_blank" class="small-btn" style="text-decoration:none;">💬 WhatsApp</a>` : ''}
            </div></td>
        </tr>`;
    }).join('');

    el.innerHTML = `
        <div class="section-header">
            <div><h2>⚠️ Clientes em Risco de Churn</h2>
            <p>Clientes ativos monitorados por sinais de desengajamento. Priorize os de risco alto.</p></div>
        </div>
        <div class="cards-grid" style="margin-bottom:16px;">
            <div class="card"><h3>Clientes monitorados</h3><div class="metric">${withScore.length}</div><small>com plano ativo</small></div>
            <div class="card" style="border-color:${atRisk.length > 0 ? 'var(--danger)' : 'var(--border)'}"><h3 style="color:${atRisk.length > 0 ? 'var(--danger)' : 'inherit'}">Em risco (≥40 pts)</h3><div class="metric" style="color:${atRisk.length > 0 ? 'var(--danger)' : 'var(--success)'};">${atRisk.length}</div><small>requerem atenção</small></div>
            <div class="card"><h3>Risco alto (≥70 pts)</h3><div class="metric" style="color:var(--danger);">${withScore.filter(x=>x.score>=70).length}</div><small>ação urgente</small></div>
        </div>
        ${atRisk.length > 0 ? `<div class="trak-bubble" style="margin-bottom:16px;"><div class="trak-avatar">🤖</div><div class="trak-text">TRAK detectou <strong>${atRisk.length}</strong> cliente${atRisk.length>1?'s':''} em risco. Clientes com risco alto têm maior probabilidade de cancelar nos próximos 30 dias. Priorize um contato proativo — uma ligada de 5 minutos pode salvar meses de recorrência.</div></div>` : `<div class="trak-bubble" style="margin-bottom:16px;"><div class="trak-avatar">🤖</div><div class="trak-text">Ótimo trabalho! Nenhum cliente em risco neste momento. Continue fazendo follow-ups regulares para manter essa situação.</div></div>`}
        <div class="card" style="overflow-x:auto;">
            <table>
                <thead><tr><th>Cliente</th>${role === 'gestor' ? '<th>Consultor</th>' : ''}<th>Plano</th><th>Mensalidade</th><th>Score de Risco</th><th>Ações</th></tr></thead>
                <tbody>${rows || '<tr><td colspan="6" style="text-align:center;color:var(--text-soft);">Nenhum cliente ativo cadastrado.</td></tr>'}</tbody>
            </table>
        </div>`;
    showSection('dynamicContent');

    // Auto-alert: notifica consultor se clientes novos em risco alto
    withScore.filter(x => x.score >= 70).forEach(({ c }) => {
        const key = `churn_${c.id}`;
        if (!(app.state.churnAlertsSent || {})[key]) {
            addNotification(app.currentUser.id, 'churn', `⚠️ ${esc(c.name)} atingiu risco ALTO de churn (${calculateChurnScore(c)} pts)`, null);
            queueEmail(app.currentUser.id, `⚠️ Alerta de churn: ${c.name}`,
                `O cliente ${c.name} atingiu risco ALTO de cancelamento (${calculateChurnScore(c)} pontos).\n\nAcesse o sistema e tome uma ação de retenção imediatamente.\n\n— Portal Tracktiv`);
            if (!app.state.churnAlertsSent) app.state.churnAlertsSent = {};
            app.state.churnAlertsSent[key] = todayISO();
            saveState();
        }
    });
}

function openChurnDetail(clientId) {
    const c = (app.state.clients || []).find(x => x.id === clientId);
    if (!c) return;
    const score = calculateChurnScore(c);
    const badge = getChurnBadge(score);
    const msg   = getChurnTrakMsg(score, c);

    const fups = (app.state.followUps || []).filter(f => f.clientId === clientId && f.done).length;
    const openChams = (app.state.chamados || []).filter(ch => ch.clientId === clientId && ['Aberto','Em andamento'].includes(ch.status)).length;
    const monthsClosed = c.closedDate ? Math.floor((Date.now() - new Date(c.closedDate + 'T00:00:00').getTime()) / (86400000 * 30)) : 0;
    const histLen = (c.contactHistory || []).length;
    const propScore = calcScore(c);

    showModal(`⚠️ Análise de Risco — ${esc(c.name)}`, `
        <div style="text-align:center;padding:12px 0 18px;">
            <div class="churn-score-circle churn-${badge.cls}">${score}</div>
            <div style="font-size:0.8rem;color:var(--text-soft);margin-top:4px;">pontos de risco de churn</div>
            <div style="font-size:1.1rem;font-weight:700;margin-top:4px;">${badge.icon} Risco ${badge.label}</div>
        </div>
        <div class="trak-bubble" style="margin-bottom:20px;"><div class="trak-avatar">🤖</div><div class="trak-text">${msg}</div></div>
        <div style="display:grid;gap:10px;margin-bottom:20px;">
            <div class="churn-signal-row">
                <span>Follow-ups registrados</span>
                <strong style="color:${fups > 2 ? 'var(--success)' : 'var(--warning)'};">${fups} realizados</strong>
            </div>
            <div class="churn-signal-row">
                <span>Chamados em aberto</span>
                <strong style="color:${openChams > 0 ? 'var(--danger)' : 'var(--success)'};">${openChams}</strong>
            </div>
            <div class="churn-signal-row">
                <span>Tempo como cliente</span>
                <strong>${monthsClosed} ${monthsClosed === 1 ? 'mês' : 'meses'}</strong>
            </div>
            <div class="churn-signal-row">
                <span>Anotações de contato</span>
                <strong style="color:${histLen > 0 ? 'var(--success)' : 'var(--warning)'};">${histLen}</strong>
            </div>
            <div class="churn-signal-row">
                <span>Score de propensão original</span>
                <strong>${propScore} pts</strong>
            </div>
        </div>
        <div style="display:flex;flex-wrap:wrap;gap:10px;">
            <button class="primary-btn" onclick="openFollowUpModal('${clientId}');closeModal();">📅 Agendar follow-up</button>
            ${c.isWhatsapp ? `<a href="https://wa.me/55${(c.phone||'').replace(/\D/g,'')}" target="_blank" class="secondary-btn" style="text-decoration:none;">💬 WhatsApp</a>` : ''}
            <button class="secondary-btn" onclick="generateProposta('${clientId}');closeModal();">📄 Proposta Upsell</button>
        </div>
    `);
}

function renderGestorRisco() {
    renderClientesEmRisco();
}

