// ── CUSTOM COSTS ──

function addSimCustomCost() {
    ensureSimState();
    showModal('Nova linha de custo', `
        <div class="field"><label>Nome</label><input id="cc_name" type="text" placeholder="ex: Aluguel escritório"/></div>
        <div class="field"><label>Tipo</label>
            <select id="cc_type">
                <option value="fixo">Fixo mensal (valor fixo por mês)</option>
                <option value="por_cliente">Por cliente ativo (R$ × clientes/mês)</option>
                <option value="por_venda">Por venda realizada (R$ × vendas/mês)</option>
            </select>
        </div>
        <div class="field"><label>Valor (R$)</label><input id="cc_val" type="number" min="0" step="0.01" value="0"/></div>
        <div style="display:flex;gap:10px;margin-top:16px;">
            <button class="primary-btn" style="flex:1;" onclick="confirmAddCustomCost()">Adicionar</button>
            <button class="secondary-btn" onclick="closeModal()">Cancelar</button>
        </div>
    `);
}

function confirmAddCustomCost() {
    const n = document.getElementById('cc_name')?.value?.trim();
    const t = document.getElementById('cc_type')?.value;
    const v = Number(document.getElementById('cc_val')?.value) || 0;
    if (!n) { showToast('Informe o nome.', 'warning'); return; }
    ensureSimState();
    app.state.simCustomCosts.push({ id: 'cc_' + Date.now(), name: n, type: t, value: v });
    saveState(); closeModal(); renderCustomCostsUI(); calcSimulador();
}

function removeSimCustomCost(id) {
    ensureSimState();
    app.state.simCustomCosts = app.state.simCustomCosts.filter(c => c.id !== id);
    saveState(); renderCustomCostsUI(); calcSimulador();
}

function syncCustomCosts() {
    ensureSimState();
    app.state.simCustomCosts.forEach(c => {
        const inp = document.getElementById('cc_val_' + c.id);
        if (inp) c.value = Number(inp.value) || 0;
    });
    saveState(); calcSimulador();
}

function renderCustomCostsUI() {
    ensureSimState();
    const el = document.getElementById('sim_custom_costs_list');
    if (!el) return;
    if (!app.state.simCustomCosts.length) {
        el.innerHTML = '<p style="font-size:.8rem;color:var(--text-soft);text-align:center;padding:8px 0;">Nenhum custo personalizado</p>';
        return;
    }
    const typeLabel = { fixo: 'fixo/mês', por_cliente: '/cliente/mês', por_venda: '/venda' };
    el.innerHTML = app.state.simCustomCosts.map(c => `
        <div style="display:flex;align-items:center;gap:8px;background:var(--bg);border-radius:8px;padding:8px 10px;">
            <span style="flex:1;font-size:.83rem;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(c.name)}</span>
            <span style="font-size:.72rem;color:var(--text-soft);white-space:nowrap;">${typeLabel[c.type]||c.type}</span>
            <input id="cc_val_${c.id}" type="number" min="0" step="0.01" value="${c.value}" style="width:76px;padding:4px 6px;border:1px solid var(--border);border-radius:6px;font-size:.8rem;" oninput="syncCustomCosts()"/>
            <button onclick="removeSimCustomCost('${c.id}')" style="background:none;border:none;color:var(--danger);cursor:pointer;font-size:1rem;line-height:1;padding:0 2px;" title="Remover">✕</button>
        </div>
    `).join('');
}

// ── CUSTOM REVENUES ──

function addSimCustomRevenue() {
    ensureSimState();
    showModal('Nova linha de receita', `
        <div class="field"><label>Nome</label><input id="cr_name" type="text" placeholder="ex: Taxa de instalação"/></div>
        <div class="field"><label>Tipo</label>
            <select id="cr_type">
                <option value="recorrente">Recorrente por cliente (R$ × clientes/mês)</option>
                <option value="por_venda">Por venda realizada (R$ × vendas/mês)</option>
                <option value="eventual">Eventual mensal (valor fixo adicional)</option>
            </select>
        </div>
        <div class="field"><label>Valor (R$)</label><input id="cr_val" type="number" min="0" step="0.01" value="0"/></div>
        <div style="display:flex;gap:10px;margin-top:16px;">
            <button class="primary-btn" style="flex:1;" onclick="confirmAddCustomRevenue()">Adicionar</button>
            <button class="secondary-btn" onclick="closeModal()">Cancelar</button>
        </div>
    `);
}

function confirmAddCustomRevenue() {
    const n = document.getElementById('cr_name')?.value?.trim();
    const t = document.getElementById('cr_type')?.value;
    const v = Number(document.getElementById('cr_val')?.value) || 0;
    if (!n) { showToast('Informe o nome.', 'warning'); return; }
    ensureSimState();
    app.state.simCustomRevenues.push({ id: 'cr_' + Date.now(), name: n, type: t, value: v });
    saveState(); closeModal(); renderCustomRevenuesUI(); calcSimulador();
}

function removeSimCustomRevenue(id) {
    ensureSimState();
    app.state.simCustomRevenues = app.state.simCustomRevenues.filter(r => r.id !== id);
    saveState(); renderCustomRevenuesUI(); calcSimulador();
}

function syncCustomRevenues() {
    ensureSimState();
    app.state.simCustomRevenues.forEach(r => {
        const inp = document.getElementById('cr_val_' + r.id);
        if (inp) r.value = Number(inp.value) || 0;
    });
    saveState(); calcSimulador();
}

function renderCustomRevenuesUI() {
    ensureSimState();
    const el = document.getElementById('sim_custom_revenues_list');
    if (!el) return;
    if (!app.state.simCustomRevenues.length) {
        el.innerHTML = '<p style="font-size:.8rem;color:var(--text-soft);text-align:center;padding:8px 0;">Nenhuma receita personalizada</p>';
        return;
    }
    const typeLabel = { recorrente: '/cliente/mês', por_venda: '/venda', eventual: 'eventual/mês' };
    el.innerHTML = app.state.simCustomRevenues.map(r => `
        <div style="display:flex;align-items:center;gap:8px;background:var(--bg);border-radius:8px;padding:8px 10px;">
            <span style="flex:1;font-size:.83rem;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(r.name)}</span>
            <span style="font-size:.72rem;color:var(--text-soft);white-space:nowrap;">${typeLabel[r.type]||r.type}</span>
            <input id="cr_val_${r.id}" type="number" min="0" step="0.01" value="${r.value}" style="width:76px;padding:4px 6px;border:1px solid var(--border);border-radius:6px;font-size:.8rem;" oninput="syncCustomRevenues()"/>
            <button onclick="removeSimCustomRevenue('${r.id}')" style="background:none;border:none;color:var(--danger);cursor:pointer;font-size:1rem;line-height:1;padding:0 2px;" title="Remover">✕</button>
        </div>
    `).join('');
}

// ── CALC ──

function calcSimulador() {
    ensureSimState();
    const cons     = Number(document.getElementById('sim_cons')?.value)     || 1;
    const meta     = Number(document.getElementById('sim_meta')?.value)     || 0;
    const conv     = Number(document.getElementById('sim_conv')?.value)     || 30;
    const churn    = Number(document.getElementById('sim_churn')?.value)    || 3;
    const pctEss   = Number(document.getElementById('sim_pct_ess')?.value)  || 30;
    const pctPro   = Number(document.getElementById('sim_pct_pro')?.value)  || 50;
    const pctCT    = Number(document.getElementById('sim_pct_ct')?.value)   || 20;
    const fixo     = Number(document.getElementById('sim_fixo')?.value)     || 0;
    const cv       = Number(document.getElementById('sim_cv')?.value)       || 0;
    const comisPct = Number(document.getElementById('sim_comis_pct')?.value)|| 18;

    const vendasMes   = Math.round(cons * meta * conv / 100);
    const ticketMed   = (44.90 * pctEss/100) + (54.90 * pctPro/100) + (64.90 * pctCT/100);
    const customCosts    = app.state.simCustomCosts    || [];
    const customRevenues = app.state.simCustomRevenues || [];

    const el = document.getElementById('sim_resultado');
    if (!el) return;

    let clients = 0;
    const meses = [];
    for (let i = 1; i <= 12; i++) {
        clients = clients * (1 - churn/100) + vendasMes;
        const rec    = clients * ticketMed;
        const comis  = rec * comisPct / 100;

        let extraRec = 0;
        customRevenues.forEach(r => {
            if      (r.type === 'recorrente') extraRec += r.value * clients;
            else if (r.type === 'por_venda')  extraRec += r.value * vendasMes;
            else if (r.type === 'eventual')   extraRec += r.value;
        });

        let extraCost = 0;
        customCosts.forEach(c => {
            if      (c.type === 'fixo')        extraCost += c.value;
            else if (c.type === 'por_cliente') extraCost += c.value * clients;
            else if (c.type === 'por_venda')   extraCost += c.value * vendasMes;
        });

        const totalRec = rec + extraRec;
        const custos   = clients * cv + fixo + comis + extraCost;
        const lucro    = totalRec - custos;
        meses.push({ i, clients: Math.round(clients), rec, extraRec, totalRec, comis, custos, extraCost, lucro });
    }

    const m1  = meses[0];
    const m12 = meses[11];

    const calcCenario = (fator) => {
        let c = 0, lucro12 = 0;
        for (let i = 1; i <= 12; i++) {
            c = c * (1 - churn/100) + vendasMes * fator;
            let er = 0;
            customRevenues.forEach(r => {
                if      (r.type === 'recorrente') er += r.value * c;
                else if (r.type === 'por_venda')  er += r.value * vendasMes * fator;
                else if (r.type === 'eventual')   er += r.value;
            });
            let ec = 0;
            customCosts.forEach(cc => {
                if      (cc.type === 'fixo')        ec += cc.value;
                else if (cc.type === 'por_cliente') ec += cc.value * c;
                else if (cc.type === 'por_venda')   ec += cc.value * vendasMes * fator;
            });
            const totalRec = c * ticketMed + er;
            lucro12 += totalRec - (c * cv + fixo + totalRec * comisPct/100 + ec);
        }
        return lucro12;
    };

    el.innerHTML = `
        <h3>📊 Resultado — Mês 1</h3>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:12px 0;">
            ${[
                ['Vendas geradas',  vendasMes],
                ['Clientes no mês', m1.clients],
                ['Receita base',    'R$ ' + formatCurrency(m1.rec)],
                ['Receita extra',   'R$ ' + formatCurrency(m1.extraRec)],
                ['Custos totais',   'R$ ' + formatCurrency(m1.custos)],
                ['Lucro líquido',   'R$ ' + formatCurrency(m1.lucro)]
            ].map(([l,v]) => `<div style="background:var(--bg);border-radius:10px;padding:10px;text-align:center;">
                <div style="font-size:.75rem;color:var(--text-soft);">${l}</div>
                <div style="font-size:1.1rem;font-weight:700;">${v}</div>
            </div>`).join('')}
        </div>
        <h4 style="margin:16px 0 8px;">📅 3 cenários — 12 meses</h4>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;">
            ${[
                ['😟 Pessimista', 0.7, 'var(--danger)'],
                ['😐 Realista',   1,   'var(--accent)'],
                ['😊 Otimista',   1.3, 'var(--success)']
            ].map(([l,f,c]) => {
                const v = calcCenario(f);
                return `<div style="background:var(--bg);border-radius:10px;padding:12px;text-align:center;">
                    <div style="font-size:.8rem;color:var(--text-soft);">${l}</div>
                    <div style="font-size:1.1rem;font-weight:700;color:${c};">R$ ${formatCurrency(v)}</div>
                    <div style="font-size:.72rem;color:var(--text-soft);">lucro 12 meses</div>
                </div>`;
            }).join('')}
        </div>`;

    const tblCard = document.getElementById('sim_tabela_card');
    const tbl     = document.getElementById('sim_tabela');
    if (tblCard) tblCard.style.display = '';
    if (tbl) {
        tbl.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:.83rem;">
            <thead><tr style="border-bottom:2px solid var(--border);">
                <th style="padding:8px;text-align:left;">Mês</th>
                <th style="padding:8px;text-align:right;">Clientes</th>
                <th style="padding:8px;text-align:right;">Rec. base</th>
                <th style="padding:8px;text-align:right;">Rec. extra</th>
                <th style="padding:8px;text-align:right;">Custos</th>
                <th style="padding:8px;text-align:right;">Lucro</th>
            </tr></thead>
            <tbody>
                ${meses.map(m => `<tr style="border-bottom:1px solid var(--border);">
                    <td style="padding:8px;">Mês ${m.i}</td>
                    <td style="padding:8px;text-align:right;">${m.clients}</td>
                    <td style="padding:8px;text-align:right;">R$ ${formatCurrency(m.rec)}</td>
                    <td style="padding:8px;text-align:right;color:var(--success);">R$ ${formatCurrency(m.extraRec)}</td>
                    <td style="padding:8px;text-align:right;">R$ ${formatCurrency(m.custos)}</td>
                    <td style="padding:8px;text-align:right;font-weight:${m.i===12?700:400};color:${m.lucro>0?'var(--success)':'var(--danger)'};">R$ ${formatCurrency(m.lucro)}</td>
                </tr>`).join('')}
            </tbody>
        </table>`;
    }

    window._simData = { vendasMes, ticketMed, meses, m12, churn, comisPct, pctEss, pctPro, pctCT, customCosts, customRevenues, fixo, cv };
    updateChartsActions();
}

// ── CHART HELPERS ──

function _svgNiceMax(v) {
    if (v <= 0) return 100;
    const exp = Math.pow(10, Math.floor(Math.log10(v)));
    return Math.ceil(v / exp) * exp;
}

function _svgGrid(maxVal, steps, x0, y0, w, h) {
    let out = '';
    for (let i = 0; i <= steps; i++) {
        const y   = y0 + h - (i / steps) * h;
        const val = maxVal * i / steps;
        const lbl = val >= 1000000 ? (val/1000000).toFixed(1)+'M' : val >= 1000 ? (val/1000).toFixed(0)+'k' : val.toFixed(0);
        out += `<line x1="${x0}" y1="${y.toFixed(1)}" x2="${x0+w}" y2="${y.toFixed(1)}" stroke="#e2e8f0" stroke-width="1"/>`;
        out += `<text x="${x0-5}" y="${(y+4).toFixed(1)}" text-anchor="end" font-size="9" fill="#94a3b8">${lbl}</text>`;
    }
    return out;
}

// ── CHART BUILDERS ──

function buildSVGBarChart(sd, title) {
    const meses  = sd.meses;
    const maxRec = Math.max(...meses.map(m => m.totalRec), 1);
    const maxVal = _svgNiceMax(maxRec * 1.1);
    const W=580, H=300, x0=60, y0=20, w=500, h=220;
    const bSlot  = w / meses.length;
    const bw     = Math.max(2, bSlot * 0.32);

    let bars = '', xlabels = '';
    meses.forEach((m, i) => {
        const cx = x0 + bSlot * i + bSlot / 2;
        const pairs = [
            { v: m.totalRec, color: '#3b82f6', dx: -bw },
            { v: Math.max(0, m.lucro), color: m.lucro >= 0 ? '#10b981' : '#ef4444', dx: 0 }
        ];
        pairs.forEach(p => {
            const bh = (p.v / maxVal) * h;
            const by = y0 + h - bh;
            bars += `<rect x="${(cx + p.dx).toFixed(1)}" y="${by.toFixed(1)}" width="${bw.toFixed(1)}" height="${bh.toFixed(1)}" fill="${p.color}" rx="2" opacity="0.85"/>`;
        });
        if (i % 2 === 0 || meses.length <= 6) {
            xlabels += `<text x="${cx.toFixed(1)}" y="${y0+h+14}" text-anchor="middle" font-size="9" fill="#64748b">M${m.i}</text>`;
        }
    });

    return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;">
        <text x="${W/2}" y="13" text-anchor="middle" font-size="11" font-weight="bold" fill="#1a2e4a">${esc(title||'Receita × Lucro — 12 meses')}</text>
        ${_svgGrid(maxVal, 4, x0, y0, w, h)}
        <line x1="${x0}" y1="${y0}" x2="${x0}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        <line x1="${x0}" y1="${y0+h}" x2="${x0+w}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        ${bars}${xlabels}
        <rect x="${x0}" y="${H-18}" width="10" height="10" fill="#3b82f6" rx="2"/>
        <text x="${x0+14}" y="${H-9}" font-size="9" fill="#64748b">Receita total</text>
        <rect x="${x0+100}" y="${H-18}" width="10" height="10" fill="#10b981" rx="2"/>
        <text x="${x0+114}" y="${H-9}" font-size="9" fill="#64748b">Lucro líquido</text>
    </svg>`;
}

function buildSVGLineChart(sd, title) {
    const meses     = sd.meses;
    const maxC      = Math.max(...meses.map(m => m.clients), 1);
    const maxVal    = _svgNiceMax(maxC * 1.1);
    const W=580, H=300, x0=60, y0=20, w=500, h=220;
    const getX = i  => x0 + (i / (meses.length - 1)) * w;
    const getY = v  => y0 + h - (v / maxVal) * h;

    const path = meses.map((m, i) => `${i===0?'M':'L'}${getX(i).toFixed(1)},${getY(m.clients).toFixed(1)}`).join(' ');
    const area = path + ` L${getX(meses.length-1).toFixed(1)},${y0+h} L${getX(0).toFixed(1)},${y0+h} Z`;

    let dots = '', xlabels = '';
    meses.forEach((m, i) => {
        dots += `<circle cx="${getX(i).toFixed(1)}" cy="${getY(m.clients).toFixed(1)}" r="3.5" fill="#3b82f6" stroke="white" stroke-width="1.5"/>`;
        if (i % 2 === 0 || meses.length <= 6)
            xlabels += `<text x="${getX(i).toFixed(1)}" y="${y0+h+14}" text-anchor="middle" font-size="9" fill="#64748b">M${m.i}</text>`;
    });

    return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;">
        <defs><linearGradient id="lg_line" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stop-color="#3b82f6" stop-opacity="0.25"/>
            <stop offset="100%" stop-color="#3b82f6" stop-opacity="0.02"/>
        </linearGradient></defs>
        <text x="${W/2}" y="13" text-anchor="middle" font-size="11" font-weight="bold" fill="#1a2e4a">${esc(title||'Crescimento de Clientes — 12 meses')}</text>
        ${_svgGrid(maxVal, 4, x0, y0, w, h)}
        <path d="${area}" fill="url(#lg_line)"/>
        <path d="${path}" fill="none" stroke="#3b82f6" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>
        ${dots}${xlabels}
        <line x1="${x0}" y1="${y0}" x2="${x0}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        <line x1="${x0}" y1="${y0+h}" x2="${x0+w}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        <rect x="${x0}" y="${H-18}" width="10" height="10" fill="#3b82f6" rx="2"/>
        <text x="${x0+14}" y="${H-9}" font-size="9" fill="#64748b">Clientes ativos</text>
    </svg>`;
}

function buildSVGPieChart(sd, title) {
    const total = (sd.pctEss + sd.pctPro + sd.pctCT) || 100;
    const slices = [
        { label: 'Essencial',      pct: sd.pctEss / total, color: '#3b82f6' },
        { label: 'Profissional',   pct: sd.pctPro / total, color: '#f5820d' },
        { label: 'Controle Total', pct: sd.pctCT  / total, color: '#10b981' }
    ].filter(s => s.pct > 0);

    const W=580, H=300, cx=190, cy=148, r=115;
    let angle = -Math.PI / 2, paths = '', legends = '';

    slices.forEach((s, i) => {
        const end = angle + s.pct * 2 * Math.PI;
        const x1 = cx + r * Math.cos(angle), y1 = cy + r * Math.sin(angle);
        const x2 = cx + r * Math.cos(end),   y2 = cy + r * Math.sin(end);
        const large = s.pct > 0.5 ? 1 : 0;
        paths += `<path d="M${cx},${cy} L${x1.toFixed(1)},${y1.toFixed(1)} A${r},${r} 0 ${large},1 ${x2.toFixed(1)},${y2.toFixed(1)} Z" fill="${s.color}" stroke="white" stroke-width="2"/>`;
        if (s.pct > 0.06) {
            const mid = (angle + end) / 2;
            paths += `<text x="${(cx + r*0.62*Math.cos(mid)).toFixed(1)}" y="${(cy + r*0.62*Math.sin(mid)+4).toFixed(1)}" text-anchor="middle" font-size="11" font-weight="bold" fill="white">${(s.pct*100).toFixed(0)}%</text>`;
        }
        legends += `<rect x="370" y="${36+i*26}" width="13" height="13" fill="${s.color}" rx="3"/>
            <text x="388" y="${36+i*26+11}" font-size="11" fill="#475569">${esc(s.label)} (R$${[44.90,54.90,64.90][i]})</text>`;
        angle = end;
    });

    return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;">
        <text x="${W/2}" y="13" text-anchor="middle" font-size="11" font-weight="bold" fill="#1a2e4a">${esc(title||'Mix de Planos')}</text>
        ${paths}${legends}
    </svg>`;
}

function buildSVGWaterfallChart(sd, title) {
    const m       = sd.meses[11];
    const items   = [
        { label: 'Receita',    value: m.totalRec,      type: 'pos' },
        { label: 'Custo fixo', value: sd.fixo,         type: 'neg' },
        { label: 'Custo var.', value: sd.cv * m.clients, type: 'neg' },
        { label: 'Comissões',  value: m.comis,         type: 'neg' }
    ];
    sd.customCosts.forEach(c => {
        let v = 0;
        if      (c.type === 'fixo')        v = c.value;
        else if (c.type === 'por_cliente') v = c.value * m.clients;
        else if (c.type === 'por_venda')   v = c.value * sd.vendasMes;
        if (v > 0) items.push({ label: c.name.slice(0, 9), value: v, type: 'neg' });
    });
    items.push({ label: 'Lucro', value: Math.abs(m.lucro), type: m.lucro >= 0 ? 'result' : 'result-neg' });

    const W=580, H=320, x0=60, y0=20, w=500, h=230;
    const bSlot  = w / items.length;
    const bw     = Math.max(2, bSlot * 0.55);
    const maxAbs = _svgNiceMax(Math.max(...items.map(it => it.value), 1) * 1.15);
    const scale  = h / maxAbs;
    const colors = { pos: '#10b981', neg: '#ef4444', result: '#3b82f6', 'result-neg': '#ef4444' };

    let running = 0, bars = '', xlabels = '';
    items.forEach((it, i) => {
        const cx  = x0 + bSlot * i + bSlot / 2;
        const bx  = cx - bw / 2;
        let barY, barH;
        if (it.type === 'pos') {
            barH  = it.value * scale;
            barY  = y0 + h - (running + it.value) * scale;
            running += it.value;
        } else if (it.type === 'neg') {
            barH  = it.value * scale;
            barY  = y0 + h - running * scale;
            running -= it.value;
        } else {
            barH  = it.value * scale;
            barY  = y0 + h - it.value * scale;
        }
        barH = Math.max(1, barH);
        bars += `<rect x="${bx.toFixed(1)}" y="${barY.toFixed(1)}" width="${bw.toFixed(1)}" height="${barH.toFixed(1)}" fill="${colors[it.type]}" rx="3" opacity="0.9"/>`;
        xlabels += `<text x="${cx.toFixed(1)}" y="${y0+h+14}" text-anchor="middle" font-size="9" fill="#64748b">${esc(it.label)}</text>`;
    });

    return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;">
        <text x="${W/2}" y="13" text-anchor="middle" font-size="11" font-weight="bold" fill="#1a2e4a">${esc(title||'Waterfall — Breakdown mês 12')}</text>
        ${_svgGrid(maxAbs, 4, x0, y0, w, h)}
        <line x1="${x0}" y1="${y0}" x2="${x0}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        <line x1="${x0}" y1="${y0+h}" x2="${x0+w}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        ${bars}${xlabels}
        <rect x="${x0}" y="${H-18}" width="10" height="10" fill="#10b981" rx="2"/>
        <text x="${x0+14}" y="${H-9}" font-size="9" fill="#64748b">Receita</text>
        <rect x="${x0+80}" y="${H-18}" width="10" height="10" fill="#ef4444" rx="2"/>
        <text x="${x0+94}" y="${H-9}" font-size="9" fill="#64748b">Custo</text>
        <rect x="${x0+160}" y="${H-18}" width="10" height="10" fill="#3b82f6" rx="2"/>
        <text x="${x0+174}" y="${H-9}" font-size="9" fill="#64748b">Resultado</text>
    </svg>`;
}

function buildSVGAreaChart(sd, title) {
    const meses  = sd.meses;
    const maxRec = Math.max(...meses.map(m => m.totalRec), 1);
    const maxVal = _svgNiceMax(maxRec * 1.1);
    const W=580, H=300, x0=60, y0=20, w=500, h=220;
    const gX = i => x0 + (i / (meses.length - 1)) * w;
    const gY = v => y0 + h - Math.max(0, v) / maxVal * h;

    const buildPath = key => meses.map((m, i) => `${i===0?'M':'L'}${gX(i).toFixed(1)},${gY(m[key]).toFixed(1)}`).join(' ');
    const buildArea = (pathStr, color, op) => {
        const last = meses.length - 1;
        return `<path d="${pathStr} L${gX(last).toFixed(1)},${y0+h} L${gX(0).toFixed(1)},${y0+h} Z" fill="${color}" opacity="${op}"/>`;
    };

    const pRec   = buildPath('totalRec');
    const pCost  = buildPath('custos');
    const pLucro = buildPath('lucro');

    let xlabels = '';
    meses.forEach((m, i) => {
        if (i % 2 === 0 || meses.length <= 6)
            xlabels += `<text x="${gX(i).toFixed(1)}" y="${y0+h+14}" text-anchor="middle" font-size="9" fill="#64748b">M${m.i}</text>`;
    });

    return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;">
        <text x="${W/2}" y="13" text-anchor="middle" font-size="11" font-weight="bold" fill="#1a2e4a">${esc(title||'Receita, Custos e Lucro — 12 meses')}</text>
        ${_svgGrid(maxVal, 4, x0, y0, w, h)}
        ${buildArea(pRec,   '#3b82f6', '0.12')}
        ${buildArea(pCost,  '#ef4444', '0.12')}
        ${buildArea(pLucro, '#10b981', '0.18')}
        <path d="${pRec}"   fill="none" stroke="#3b82f6" stroke-width="2"   stroke-linejoin="round"/>
        <path d="${pCost}"  fill="none" stroke="#ef4444" stroke-width="2"   stroke-linejoin="round"/>
        <path d="${pLucro}" fill="none" stroke="#10b981" stroke-width="2.5" stroke-linejoin="round"/>
        ${xlabels}
        <line x1="${x0}" y1="${y0}" x2="${x0}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        <line x1="${x0}" y1="${y0+h}" x2="${x0+w}" y2="${y0+h}" stroke="#94a3b8" stroke-width="1.5"/>
        <rect x="${x0}"     y="${H-18}" width="10" height="10" fill="#3b82f6" rx="2"/>
        <text x="${x0+14}"  y="${H-9}"  font-size="9" fill="#64748b">Receita</text>
        <rect x="${x0+78}"  y="${H-18}" width="10" height="10" fill="#ef4444" rx="2"/>
        <text x="${x0+92}"  y="${H-9}"  font-size="9" fill="#64748b">Custos</text>
        <rect x="${x0+156}" y="${H-18}" width="10" height="10" fill="#10b981" rx="2"/>
        <text x="${x0+170}" y="${H-9}"  font-size="9" fill="#64748b">Lucro</text>
    </svg>`;
}

// ── CHART ACTIONS ──

function gerarGrafico() {
    if (!window._simData) { showToast('Calcule a simulação primeiro.', 'warning'); return; }
    const type  = document.getElementById('sim_chart_type')?.value || 'barras';
    const title = document.getElementById('sim_chart_title')?.value || '';

    const builders = { barras: buildSVGBarChart, linha: buildSVGLineChart, pizza: buildSVGPieChart, waterfall: buildSVGWaterfallChart, area: buildSVGAreaChart };
    const svgHtml  = (builders[type] || buildSVGBarChart)(window._simData, title);

    const area = document.getElementById('sim_charts_area');
    if (!area) return;
    const chartId   = 'chart_' + Date.now();
    const typeNames = { barras: 'Barras', linha: 'Linha', pizza: 'Pizza', waterfall: 'Waterfall', area: 'Área' };

    const wrap = document.createElement('div');
    wrap.className = 'sim-chart-wrapper';
    wrap.id = chartId;
    wrap.innerHTML = `
        <div class="sim-chart-header">
            <span class="sim-chart-tag">${typeNames[type]||type}</span>
            <div style="display:flex;gap:6px;">
                <button onclick="exportChartPNG('${chartId}')" title="Exportar PNG" class="sim-chart-btn">⬇ PNG</button>
                <button onclick="document.getElementById('${chartId}').remove();updateChartsActions();" title="Remover" class="sim-chart-btn sim-chart-btn-remove">✕</button>
            </div>
        </div>
        <div class="sim-chart-body">${svgHtml}</div>`;
    area.appendChild(wrap);
    updateChartsActions();
    showToast('Gráfico gerado!', 'success', 2000);
}

function exportChartPNG(chartId) {
    const wrap  = document.getElementById(chartId);
    const svgEl = wrap?.querySelector('svg');
    if (!svgEl) return;
    const svgData = new XMLSerializer().serializeToString(svgEl);
    const blob    = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
    const url     = URL.createObjectURL(blob);
    const img     = new Image();
    img.onload = () => {
        const canvas  = document.createElement('canvas');
        canvas.width  = svgEl.viewBox.baseVal.width  || 580;
        canvas.height = svgEl.viewBox.baseVal.height || 300;
        const ctx = canvas.getContext('2d');
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        URL.revokeObjectURL(url);
        const a = document.createElement('a');
        a.download = 'grafico_tracktiv_' + Date.now() + '.png';
        a.href = canvas.toDataURL('image/png');
        a.click();
        showToast('PNG exportado!', 'success', 2000);
    };
    img.src = url;
}

function exportSimPDF() { window.print(); }

function clearCharts() {
    const area = document.getElementById('sim_charts_area');
    if (area) area.innerHTML = '';
    updateChartsActions();
}

function updateChartsActions() {
    const area    = document.getElementById('sim_charts_area');
    const actions = document.getElementById('sim_charts_actions');
    if (!area || !actions) return;
    actions.style.display = area.children.length > 0 ? 'flex' : 'none';
}

// ── SAVE / DELETE ──

function saveSimulacao() {
    const sd = window._simData;
    if (!sd) { showToast('Calcule a simulação primeiro.', 'warning'); return; }
    const name = prompt('Nome para este cenário:', 'Cenário ' + todayISO());
    if (!name) return;
    ensureSimState();
    app.state.savedSimulations.unshift({
        id: 'sim_' + Date.now(), name, date: todayISO(),
        receita12m: sd.meses[11]?.totalRec || 0,
        margem12m:  sd.meses[11]?.lucro    || 0,
        data: sd
    });
    saveState();
    showToast('Cenário "' + name + '" salvo!', 'success');
    renderPresidenteSimulador();
}

function deleteSimulacao(id) {
    app.state.savedSimulations = (app.state.savedSimulations || []).filter(s => s.id !== id);
    saveState();
    showToast('Cenário excluído.', 'info');
    renderPresidenteSimulador();
}

/* ═══════════════════════════════════════════════════════════════════
   QUALIFICAÇÃO, LINK E FORMULÁRIO DO TÉCNICO
═══════════════════════════════════════════════════════════════════ */

// ── HELPERS ──────────────────────────────────────────────────────

function getTecnicoForms(tecId) {
    const data = (app.state.tecnicoForms || {})[tecId];
    if (Array.isArray(data) && data.length) return data;
    const def = { id: 'tform_default_' + tecId, name: 'Formulário padrão', sector: 'rastreamento', createdAt: todayISO(), fields: JSON.parse(JSON.stringify(TECNICO_DEFAULT_FORM_FIELDS)) };
    if (!app.state.tecnicoForms) app.state.tecnicoForms = {};
    app.state.tecnicoForms[tecId] = [def];
    return [def];
}

function getTecnicoFormById(tecId, formId) {
    return getTecnicoForms(tecId).find(f => f.id === formId) || null;
}

// Backward compat — returns first form's fields (used by public link)
function getTecnicoFormFields(tecId, formId) {
    const form = formId ? getTecnicoFormById(tecId, formId) : getTecnicoForms(tecId)[0];
    return form ? JSON.parse(JSON.stringify(form.fields)) : JSON.parse(JSON.stringify(TECNICO_DEFAULT_FORM_FIELDS));
}

// Backward compat — saves to specific or first form
function saveTecnicoFormFields(tecId, fields, formId) {
    const forms = getTecnicoForms(tecId);
    const target = formId ? forms.find(f => f.id === formId) : forms[0];
    if (target) { target.fields = fields; app.state.tecnicoForms[tecId] = forms; saveState(); }
}

// ── LINK PERSONALIZADO ───────────────────────────────────────────

function getTecnicoLinkCode(userId) {
    return btoa(userId).replace(/=/g, '');
}

function resolveTecnicoFromCode(code) {
    try {
        const padded = code + '=='.slice((code.length % 4) || 4);
        const userId = atob(padded);
        return (app.state.users || []).find(u => u.id === userId && u.role === 'tecnico');
    } catch (e) { return null; }
}

function getTecnicoPublicLink(userId) {
    const code = getTecnicoLinkCode(userId);
    return `${window.location.origin}${window.location.pathname}?tecnico=${code}`;
}

function checkTecnicoFormParam() {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('tecnico');
    if (!code) return false;
    const sendId = params.get('send') || null;
    const tecnico = resolveTecnicoFromCode(code);
    showTecnicoPublicForm(tecnico, sendId);
    return true;
}

// ── FORMULÁRIO PÚBLICO ───────────────────────────────────────────

function showTecnicoPublicForm(tecnico, sendId) {
    const overlay = document.createElement('div');
    overlay.id = 'tecnicoPublicFormScreen';
    overlay.className = 'public-cadastro-screen';
    document.body.appendChild(overlay);

    const loginEl = document.getElementById('loginScreen');
    if (loginEl) loginEl.style.display = 'none';

    // Track access
    if (tecnico) {
        if (!app.state.tecnicoLinkStats) app.state.tecnicoLinkStats = {};
        if (!app.state.tecnicoLinkStats[tecnico.id]) app.state.tecnicoLinkStats[tecnico.id] = { accesses: 0, lastAccess: null };
        app.state.tecnicoLinkStats[tecnico.id].accesses++;
        app.state.tecnicoLinkStats[tecnico.id].lastAccess = todayISO();
        // If opened from a sent form link, mark as 'aberto'
        if (sendId) {
            const send = (app.state.tecnicoFormSends || []).find(s => s.id === sendId);
            if (send && send.status === 'enviado') { send.status = 'aberto'; send.openedAt = todayISO(); }
        }
        saveState();
    }

    function renderForm() {
        const fields = tecnico ? getTecnicoFormFields(tecnico.id) : JSON.parse(JSON.stringify(TECNICO_DEFAULT_FORM_FIELDS));
        const activeFields = fields.filter(f => f.active);

        overlay.innerHTML = `
        <div class="public-form-container">
            <div class="public-form-header">
                <div class="public-logo">
                    <span style="font-size:1.8rem;">📡</span>
                    <span class="public-brand">Tracktiv</span>
                </div>
                ${tecnico
                    ? `<div class="public-consultor-tag">Técnico responsável: <strong>${esc(tecnico.name)}</strong></div>`
                    : `<div class="public-consultor-tag" style="color:#ef4444;">⚠️ Link inválido — mas você ainda pode preencher</div>`}
            </div>
            <div style="padding:20px 28px 8px;">
                <h2 style="margin:0 0 4px;font-size:1.25rem;color:var(--primary);">Formulário de atendimento</h2>
                <p style="margin:0;color:var(--text-soft);font-size:0.9rem;">Preencha seus dados para que possamos entrar em contato.</p>
            </div>
            <form id="tecnicoPublicForm" class="public-form-body">
                <div class="pub-form-grid">
                    ${activeFields.map(f => _renderTecPubField(f)).join('')}
                </div>
                <div class="public-form-actions" style="margin-top:24px;">
                    <button type="submit" class="primary-btn" style="background:linear-gradient(135deg,var(--accent),#e06b00);flex:1;">✅ Enviar</button>
                </div>
                <div id="tecPubFormError" class="error-text" style="margin-top:8px;"></div>
            </form>
        </div>`;

        document.getElementById('tecnicoPublicForm').addEventListener('submit', async e => {
            e.preventDefault();
            const errEl = document.getElementById('tecPubFormError');
            errEl.textContent = '';
            const data = {};
            let valid = true;

            for (const f of activeFields) {
                if (f.type === 'multicheck') {
                    data[f.id] = Array.from(document.querySelectorAll(`.tpf_mc_${f.id}:checked`)).map(c => c.value);
                    if (f.required && !data[f.id].length) { errEl.textContent = `Selecione ao menos uma opção em "${f.label}".`; valid = false; break; }
                } else if (f.type === 'file' || f.type === 'camera') {
                    data[f.id] = null; // handled with FileReader below
                } else {
                    const inp = document.getElementById(`tpf_${f.id}`);
                    data[f.id] = inp ? inp.value.trim() : '';
                    if (f.required && !data[f.id]) { errEl.textContent = `O campo "${f.label}" é obrigatório.`; if(inp) inp.focus(); valid = false; break; }
                }
            }
            if (!valid) return;

            // Process file/camera inputs with FileReader
            const filePromises = [];
            for (const f of activeFields) {
                if (f.type === 'file' || f.type === 'camera') {
                    const inp = document.getElementById(`tpf_${f.id}`);
                    if (inp && inp.files[0]) {
                        if (inp.files[0].size > 5242880) { errEl.textContent = `Arquivo "${f.label}" é muito grande (máx. 5 MB).`; valid = false; break; }
                        filePromises.push(new Promise(resolve => {
                            const reader = new FileReader();
                            reader.onload = ev => { data[f.id] = { name: inp.files[0].name, data: ev.target.result, type: inp.files[0].type, size: inp.files[0].size }; resolve(); };
                            reader.readAsDataURL(inp.files[0]);
                        }));
                    }
                    if (f.required && !inp?.files?.[0]) { errEl.textContent = `O campo "${f.label}" é obrigatório.`; valid = false; break; }
                }
            }
            if (!valid) return;
            await Promise.all(filePromises);

            if (!app.state.tecnicoSubmissions) app.state.tecnicoSubmissions = {};
            const tecId = tecnico ? tecnico.id : '__unknown__';
            if (!app.state.tecnicoSubmissions[tecId]) app.state.tecnicoSubmissions[tecId] = [];
            const sub = { id: `tsub_${Date.now()}`, submittedAt: todayISO(), sendId: sendId || null, data };
            app.state.tecnicoSubmissions[tecId].push(sub);
            // If this was a sent form, mark as preenchido
            if (sendId) {
                const send = (app.state.tecnicoFormSends || []).find(s => s.id === sendId);
                if (send) { send.status = 'preenchido'; send.submittedAt = todayISO(); send.submission = data; }
            }
            if (tecnico) {
                const nomeVal = data['tf_name'] || 'cliente desconhecido';
                addNotification(tecnico.id, 'info', `📥 Nova resposta no seu formulário: ${esc(nomeVal)}`, null);
            }
            saveState();

            overlay.innerHTML = `
            <div class="public-form-container" style="text-align:center;padding:48px 32px;">
                <div style="font-size:4rem;margin-bottom:20px;">✅</div>
                <h2 style="color:var(--primary);margin-bottom:12px;">Dados recebidos!</h2>
                <p style="color:var(--text-soft);font-size:1.05rem;margin-bottom:8px;">Obrigado pelo preenchimento!</p>
                <p style="color:var(--text-soft);margin-bottom:28px;">Em breve um de nossos especialistas entrará em contato.</p>
                <div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:12px;padding:16px 20px;margin-bottom:28px;text-align:left;font-size:0.9rem;color:#065f46;">
                    <strong>✅ O que acontece agora?</strong><br>
                    • Seu atendente recebeu uma notificação<br>
                    • Em até 24h entraremos em contato<br>
                    • Seus dados estão seguros conosco
                </div>
                <p style="color:var(--text-muted);font-size:0.85rem;">© Tracktiv — Rastreamento e Segurança Veicular</p>
            </div>`;
        });
    }

    renderForm();
}

function _renderTecPubField(f) {
    const req = f.required ? ' *' : '';
    const reqAttr = f.required ? ' required' : '';
    const wide = ['textarea','file','camera','multicheck'].includes(f.type) ? 'full-width' : '';
    if (f.type === 'text' || f.type === 'number' || f.type === 'date') {
        return `<div class="field ${wide}"><label>${esc(f.label)}${req}</label><input id="tpf_${f.id}" type="${f.type}"${reqAttr} placeholder="${esc(f.placeholder||'')}"></div>`;
    }
    if (f.type === 'email') {
        return `<div class="field ${wide}"><label>${esc(f.label)}${req}</label><input id="tpf_${f.id}" type="email"${reqAttr} placeholder="seu@email.com"></div>`;
    }
    if (f.type === 'textarea') {
        return `<div class="field full-width"><label>${esc(f.label)}${req}</label><textarea id="tpf_${f.id}" rows="3"${reqAttr} placeholder="${esc(f.placeholder||'')}"></textarea></div>`;
    }
    if (f.type === 'yesno') {
        return `<div class="field ${wide}"><label>${esc(f.label)}${req}</label><select id="tpf_${f.id}"${reqAttr}><option value="">Selecione…</option><option value="sim">Sim</option><option value="nao">Não</option></select></div>`;
    }
    if (f.type === 'select') {
        const opts = (f.options||[]).map(o=>`<option value="${esc(o)}">${esc(o)}</option>`).join('');
        return `<div class="field ${wide}"><label>${esc(f.label)}${req}</label><select id="tpf_${f.id}"${reqAttr}><option value="">Selecione…</option>${opts}</select></div>`;
    }
    if (f.type === 'multicheck') {
        const opts = (f.options||[]).map(o=>`<label style="display:flex;align-items:center;gap:8px;padding:4px 0;cursor:pointer;"><input type="checkbox" class="tpf_mc_${f.id}" value="${esc(o)}" style="width:15px;height:15px;">${esc(o)}</label>`).join('');
        return `<div class="field full-width"><label>${esc(f.label)}${req}</label><div style="margin-top:6px;">${opts}</div></div>`;
    }
    if (f.type === 'file') {
        return `<div class="field full-width"><label>${esc(f.label)}${req}</label><input id="tpf_${f.id}" type="file" accept=".pdf,.png,.jpg,.jpeg,.doc,.docx"${reqAttr}></div>`;
    }
    if (f.type === 'camera') {
        return `<div class="field full-width"><label>${esc(f.label)}${req}</label><input id="tpf_${f.id}" type="file" accept="image/*" capture="environment"${reqAttr}></div>`;
    }
    return '';
}

// ── PAINEL DO TÉCNICO: MEU LINK ───────────────────────────────────

function renderMeuLinkTecnico() {
    const u = app.currentUser;
    if (!u || u.role !== 'tecnico') return;
    const link = getTecnicoPublicLink(u.id);
    const waMsg = encodeURIComponent(`Olá! Preencha o formulário de atendimento Tracktiv pelo link:\n${link}\n\nQualquer dúvida, estou à disposição! 😊`);

    // Stats
    const subs = ((app.state.tecnicoSubmissions || {})[u.id] || []);
    const subsThisMonth = subs.filter(s => (s.submittedAt || '').startsWith(getCurrentMonthKey()));
    const stats = (app.state.tecnicoLinkStats || {})[u.id] || { accesses: 0, lastAccess: null };

    // Sent forms
    const sends = (app.state.tecnicoFormSends || []).filter(s => s.tecnicoId === u.id)
        .sort((a, b) => b.sentAt.localeCompare(a.sentAt));
    const abertos    = sends.filter(s => s.status === 'aberto').length;
    const preenchidos = sends.filter(s => s.status === 'preenchido').length;
    const pendentes  = sends.filter(s => s.status === 'enviado').length;

    // Assigned clients for "send to client" button
    const assignedIds = ((app.state.tecnicoClients || {})[u.id] || []);
    const hasClients = assignedIds.length > 0;

    const statusBadge = s => {
        if (s.status === 'preenchido') return '<span class="badge badge-active" style="font-size:0.72rem;">✅ Preenchido</span>';
        if (s.status === 'aberto')     return '<span class="badge badge-warn" style="font-size:0.72rem;">👁 Aberto</span>';
        return '<span class="badge" style="background:#f1f5f9;color:#64748b;font-size:0.72rem;">📨 Enviado</span>';
    };

    const el = document.getElementById('dynamicContent');
    el.innerHTML = `
        <div class="section-header" style="margin-bottom:24px;">
            <div><h2>🔗 Meu Link de Formulário</h2>
            <p>Compartilhe seu link ou envie diretamente para um cliente.</p></div>
            <button class="secondary-btn" onclick="renderTecnicoFormLibrary()">📝 Meus formulários</button>
        </div>

        <!-- Link público -->
        <div class="card" style="text-align:center;margin-bottom:20px;">
            <div style="font-size:0.85rem;color:var(--text-muted);margin-bottom:8px;font-weight:600;letter-spacing:.05em;">SEU LINK PERSONALIZADO</div>
            <div class="meu-link-url">${esc(link)}</div>
            <div style="display:flex;gap:10px;justify-content:center;margin-top:16px;flex-wrap:wrap;">
                <button class="primary-btn" id="copyTecLinkBtn">📋 Copiar link</button>
                <a href="https://wa.me/?text=${waMsg}" target="_blank" class="secondary-btn" style="text-decoration:none;">💬 Compartilhar no WhatsApp</a>
                <button class="secondary-btn" onclick="openSendFormModal('${u.id}')" ${!hasClients ? 'disabled title="Aguardando gestor designar clientes"' : ''}>📤 Enviar para cliente</button>
            </div>
        </div>

        ${abertos > 0 ? `<div style="background:#fff3cd;border:1.5px solid #ffc107;border-radius:12px;padding:12px 18px;margin-bottom:16px;font-size:0.9rem;">
            👁 <strong>${abertos} cliente${abertos > 1 ? 's' : ''} abriu seu formulário mas ainda não preencheu.</strong> Considere fazer um follow-up!
        </div>` : ''}

        <!-- Stats grid -->
        <div class="tec-link-stats-grid" style="margin-bottom:20px;">
            <div class="card" style="text-align:center;padding:14px;">
                <div class="metric" style="font-size:2rem;">${stats.accesses}</div>
                <small style="color:var(--text-soft);">Acessos ao link</small>
            </div>
            <div class="card" style="text-align:center;padding:14px;">
                <div class="metric" style="font-size:2rem;">${subs.length}</div>
                <small style="color:var(--text-soft);">Respostas públicas</small>
            </div>
            <div class="card" style="text-align:center;padding:14px;">
                <div class="metric" style="font-size:2rem;color:var(--success);">${preenchidos}</div>
                <small style="color:var(--text-soft);">Formulários preenchidos</small>
            </div>
            <div class="card" style="text-align:center;padding:14px;">
                <div class="metric" style="font-size:2rem;color:${abertos > 0 ? 'var(--warning)' : 'var(--text)'};">${abertos}</div>
                <small style="color:var(--text-soft);">Abertos sem resposta</small>
            </div>
        </div>
        ${stats.lastAccess ? `<p style="font-size:0.82rem;color:var(--text-soft);margin-bottom:16px;">Último acesso ao link: <strong>${formatDate(stats.lastAccess)}</strong></p>` : ''}

        <!-- Formulários enviados -->
        <div class="card" style="padding:0;overflow:hidden;">
            <div style="padding:14px 20px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;">
                <strong>Formulários enviados para clientes (${sends.length})</strong>
                <button class="primary-btn" style="font-size:0.82rem;padding:6px 14px;" onclick="openSendFormModal('${u.id}')" ${!hasClients ? 'disabled' : ''}>+ Enviar novo</button>
            </div>
            ${sends.length === 0
                ? `<div style="padding:32px;text-align:center;color:var(--text-soft);">
                    <p>Nenhum formulário enviado ainda.</p>
                    ${hasClients ? `<button class="primary-btn" onclick="openSendFormModal('${u.id}')">📤 Enviar para um cliente</button>` : `<p style="font-size:0.88rem;">Aguardando o gestor designar clientes a você.</p>`}
                   </div>`
                : `<table style="width:100%;border-collapse:collapse;">
                    <thead style="background:var(--bg);">
                        <tr>
                            <th style="padding:10px 16px;text-align:left;font-size:0.82rem;font-weight:600;">Cliente</th>
                            <th style="padding:10px 16px;text-align:left;font-size:0.82rem;font-weight:600;">Enviado em</th>
                            <th style="padding:10px 16px;text-align:left;font-size:0.82rem;font-weight:600;">Status</th>
                            <th style="padding:10px 16px;text-align:left;font-size:0.82rem;font-weight:600;">Preenchido em</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${sends.map(s => {
                            const client = (app.state.clients || []).find(c => c.id === s.clientId);
                            return `<tr style="border-top:1px solid var(--border);">
                                <td style="padding:10px 16px;font-size:0.88rem;"><strong>${esc(client ? client.name : s.clientName || '—')}</strong></td>
                                <td style="padding:10px 16px;font-size:0.88rem;">${formatDate(s.sentAt)}</td>
                                <td style="padding:10px 16px;">${statusBadge(s)}</td>
                                <td style="padding:10px 16px;font-size:0.82rem;color:var(--text-soft);">${s.submittedAt ? formatDate(s.submittedAt) : '—'}</td>
                            </tr>`;
                        }).join('')}
                    </tbody>
                </table>`}
        </div>

        ${subs.length ? `
        <div class="card" style="text-align:center;padding:16px;margin-top:16px;">
            <button class="secondary-btn" onclick="renderTecnicoFormSubmissions()">📥 Ver respostas públicas do link (${subs.length})</button>
        </div>` : ''}
    `;
    showSection('dynamicContent');

    document.getElementById('copyTecLinkBtn').addEventListener('click', () => {
        navigator.clipboard.writeText(link).then(() => {
            showToast('Link copiado!', 'success');
            const btn = document.getElementById('copyTecLinkBtn');
            if (btn) { btn.textContent = '✅ Copiado!'; setTimeout(() => { if (document.getElementById('copyTecLinkBtn')) document.getElementById('copyTecLinkBtn').textContent = '📋 Copiar link'; }, 2000); }
        }).catch(() => showToast('Não foi possível copiar automaticamente.', 'warning'));
    });
}

// ── BIBLIOTECA DE FORMULÁRIOS ─────────────────────────────────────

function renderTecnicoFormLibrary() {
    const u = app.currentUser;
    if (!u || u.role !== 'tecnico') return;
    const forms = getTecnicoForms(u.id);
    const el = document.getElementById('dynamicContent');
    el.innerHTML = `
        <div class="section-header" style="margin-bottom:24px;">
            <div><h2>📝 Meus Formulários</h2>
            <p>Crie e gerencie formulários personalizados para enviar aos seus clientes.</p></div>
            <button class="primary-btn" onclick="openCreateFormModal('${u.id}')">+ Criar formulário</button>
        </div>
        ${forms.length === 0
            ? `<div class="card" style="text-align:center;padding:48px;color:var(--text-soft);">
                <div style="font-size:2.5rem;margin-bottom:12px;">📝</div>
                <p>Nenhum formulário criado ainda.</p>
                <button class="primary-btn" style="margin-top:12px;" onclick="openCreateFormModal('${u.id}')">+ Criar primeiro formulário</button>
               </div>`
            : forms.map(form => {
                const seg    = TECNICO_SEGMENTS.find(s => s.key === form.sector);
                const active = (form.fields || []).filter(f => f.active).length;
                const total  = (form.fields || []).length;
                return `<div class="card" style="margin-bottom:12px;display:flex;align-items:center;gap:16px;flex-wrap:wrap;">
                    <div style="flex:1;min-width:180px;">
                        <div style="font-weight:700;font-size:1rem;">${esc(form.name)}</div>
                        <div style="font-size:0.82rem;color:var(--text-soft);margin-top:3px;">
                            ${seg ? `${seg.icon} ${seg.label}` : '📋 Geral'} &bull; ${active} campo${active !== 1 ? 's' : ''} ativo${active !== 1 ? 's' : ''} de ${total}
                        </div>
                        <div style="font-size:0.78rem;color:var(--text-muted);">Criado em ${formatDate(form.createdAt)}</div>
                    </div>
                    <div style="display:flex;gap:8px;flex-shrink:0;flex-wrap:wrap;">
                        <button class="secondary-btn" style="font-size:0.82rem;" onclick="renderTecnicoFormEditorById('${form.id}','${u.id}')">✏️ Editar</button>
                        <button class="secondary-btn" style="font-size:0.82rem;" onclick="duplicateTecnicoForm('${form.id}','${u.id}')">📋 Duplicar</button>
                        <button class="danger-btn"    style="font-size:0.82rem;" onclick="deleteTecnicoForm('${form.id}','${u.id}')">🗑</button>
                    </div>
                </div>`;
            }).join('')}
    `;
    showSection('dynamicContent');
}

function openCreateFormModal(tecId) {
    showModal('Criar novo formulário', `
        <div class="field">
            <label>Nome do formulário *</label>
            <input id="newFormName" type="text" placeholder="Ex: Ficha de atendimento SST">
        </div>
        <div class="field">
            <label>Setor</label>
            <select id="newFormSector">
                ${TECNICO_SEGMENTS.map(s => `<option value="${s.key}">${s.icon} ${s.label}</option>`).join('')}
                <option value="geral">📋 Geral</option>
            </select>
        </div>
        <div class="field">
            <label style="display:flex;align-items:center;gap:8px;cursor:pointer;">
                <input type="checkbox" id="newFormCopyDefault" checked style="width:15px;height:15px;">
                Iniciar com campos padrão (nome, telefone, e-mail…)
            </label>
        </div>
        <div id="createFormError" class="error-text" style="margin-top:4px;"></div>
        <div class="actions" style="margin-top:16px;">
            <button class="primary-btn" onclick="saveNewForm('${tecId}')">Criar formulário</button>
            <button class="secondary-btn" onclick="closeModal()">Cancelar</button>
        </div>
    `);
    setTimeout(() => document.getElementById('newFormName')?.focus(), 100);
}

function saveNewForm(tecId) {
    const name        = (document.getElementById('newFormName')?.value || '').trim();
    const sector      = document.getElementById('newFormSector')?.value || 'geral';
    const copyDefault = document.getElementById('newFormCopyDefault')?.checked ?? true;
    const errEl       = document.getElementById('createFormError');
    if (!name) { if (errEl) errEl.textContent = 'O nome é obrigatório.'; return; }
    const forms = getTecnicoForms(tecId);
    if (forms.find(f => f.name.toLowerCase() === name.toLowerCase())) {
        if (errEl) errEl.textContent = 'Já existe um formulário com este nome.'; return;
    }
    const newForm = {
        id: 'tform_' + Date.now(), name, sector,
        createdAt: todayISO(),
        fields: copyDefault ? JSON.parse(JSON.stringify(TECNICO_DEFAULT_FORM_FIELDS)) : []
    };
    forms.push(newForm);
    if (!app.state.tecnicoForms) app.state.tecnicoForms = {};
    app.state.tecnicoForms[tecId] = forms;
    saveState();
    closeModal();
    showToast(`Formulário "${name}" criado!`, 'success');
    renderTecnicoFormEditorById(newForm.id, tecId);
}

function duplicateTecnicoForm(formId, tecId) {
    const forms    = getTecnicoForms(tecId);
    const original = forms.find(f => f.id === formId);
    if (!original) return;
    const copy = JSON.parse(JSON.stringify(original));
    copy.id = 'tform_' + Date.now();
    copy.name = original.name + ' (cópia)';
    copy.createdAt = todayISO();
    forms.push(copy);
    app.state.tecnicoForms[tecId] = forms;
    saveState();
    showToast(`Formulário "${copy.name}" criado!`, 'success');
    renderTecnicoFormLibrary();
}

function deleteTecnicoForm(formId, tecId) {
    const forms = getTecnicoForms(tecId);
    if (forms.length <= 1) { showToast('Você precisa ter pelo menos um formulário.', 'warning'); return; }
    const form = forms.find(f => f.id === formId);
    if (!form) return;
    if (!confirm(`Excluir o formulário "${form.name}"?`)) return;
    app.state.tecnicoForms[tecId] = forms.filter(f => f.id !== formId);
    saveState();
    showToast('Formulário excluído.', 'success');
    renderTecnicoFormLibrary();
}

// ── EDITOR POR FORMULÁRIO ─────────────────────────────────────────

function renderTecnicoFormEditor() { renderTecnicoFormLibrary(); } // compat redirect

function renderTecnicoFormEditorById(formId, tecId) {
    tecId = tecId || app.currentUser?.id;
    const form = getTecnicoFormById(tecId, formId);
    if (!form) { showToast('Formulário não encontrado.', 'error'); renderTecnicoFormLibrary(); return; }
    const fields = form.fields || [];
    const seg    = TECNICO_SEGMENTS.find(s => s.key === form.sector);
    const el     = document.getElementById('dynamicContent');
    el.innerHTML = `
        <div class="section-header" style="margin-bottom:24px;">
            <div>
                <button class="secondary-btn" style="font-size:0.78rem;padding:4px 10px;margin-bottom:8px;" onclick="renderTecnicoFormLibrary()">← Meus Formulários</button>
                <h2>✏️ ${esc(form.name)}</h2>
                <p>${seg ? `${seg.icon} ${seg.label}` : '📋 Geral'} &bull; ${fields.filter(f=>f.active).length} campos ativos de ${fields.length}</p>
            </div>
            <button class="secondary-btn" onclick="openRenameFormModal('${formId}','${tecId}')">✏️ Renomear</button>
        </div>
        <div id="tecFormFieldsList">
            ${_renderFormFieldsList(fields, tecId, formId)}
        </div>
        <div class="card" style="margin-top:20px;">
            <h3 style="margin:0 0 16px;">➕ Adicionar novo campo</h3>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                <div class="field" style="margin:0;"><label>Nome do campo *</label>
                    <input id="newFieldLabel" type="text" placeholder="Ex: Data de nascimento"></div>
                <div class="field" style="margin:0;"><label>Tipo *</label>
                    <select id="newFieldType" onchange="onNewFieldTypeChange()">
                        <option value="text">Texto simples</option>
                        <option value="textarea">Texto longo</option>
                        <option value="number">Número</option>
                        <option value="date">Data</option>
                        <option value="yesno">Sim / Não</option>
                        <option value="select">Seleção única (dropdown)</option>
                        <option value="multicheck">Múltipla escolha (checkboxes)</option>
                        <option value="file">Anexo de arquivo (PDF, imagem)</option>
                        <option value="camera">Foto pela câmera</option>
                    </select></div>
            </div>
            <div id="newFieldOptionsWrap" style="display:none;margin-top:12px;">
                <div class="field" style="margin:0;"><label>Opções (separadas por vírgula) *</label>
                    <input id="newFieldOptions" type="text" placeholder="Opção 1, Opção 2, Opção 3"></div>
            </div>
            <div style="margin-top:14px;">
                <button class="primary-btn" onclick="addTecnicoFormField('${tecId}','${formId}')">+ Adicionar campo</button>
            </div>
            <div id="addFieldError" class="error-text" style="margin-top:8px;"></div>
        </div>
    `;
    showSection('dynamicContent');
}

function openRenameFormModal(formId, tecId) {
    const form = getTecnicoFormById(tecId, formId);
    if (!form) return;
    showModal('Renomear formulário', `
        <div class="field"><label>Nome *</label>
            <input id="renameFormInput" type="text" value="${esc(form.name)}"></div>
        <div class="field"><label>Setor</label>
            <select id="renameFormSector">
                ${TECNICO_SEGMENTS.map(s => `<option value="${s.key}" ${form.sector===s.key?'selected':''}>${s.icon} ${s.label}</option>`).join('')}
                <option value="geral" ${form.sector==='geral'?'selected':''}>📋 Geral</option>
            </select></div>
        <div class="actions" style="margin-top:16px;">
            <button class="primary-btn" onclick="_saveRenameForm('${formId}','${tecId}')">Salvar</button>
            <button class="secondary-btn" onclick="closeModal()">Cancelar</button>
        </div>
    `);
}

function _saveRenameForm(formId, tecId) {
    const name   = (document.getElementById('renameFormInput')?.value || '').trim();
    const sector = document.getElementById('renameFormSector')?.value || 'geral';
    if (!name) { showToast('Nome é obrigatório.', 'warning'); return; }
    const forms = getTecnicoForms(tecId);
    const form  = forms.find(f => f.id === formId);
    if (!form) return;
    form.name = name; form.sector = sector;
    app.state.tecnicoForms[tecId] = forms;
    saveState();
    closeModal();
    showToast('Formulário atualizado.', 'success');
    renderTecnicoFormEditorById(formId, tecId);
}

function _renderFormFieldsList(fields, tecId, formId) {
    const fid = formId || '';
    if (!fields.length) return `<div class="card"><p class="text-muted">Nenhum campo ainda. Use "Adicionar novo campo" abaixo para começar.</p></div>`;
    return `<div class="card" style="padding:0;overflow:hidden;">
        <div style="padding:12px 20px;border-bottom:1px solid var(--border);background:var(--bg);display:flex;justify-content:space-between;align-items:center;">
            <strong>Campos do formulário</strong>
            <span style="font-size:0.82rem;color:var(--text-soft);">${fields.filter(f=>f.active).length} ativos de ${fields.length} total</span>
        </div>
        ${fields.map((f, idx) => `
        <div class="tec-form-field-row ${f.active ? '' : 'field-row-inactive'}">
            <div class="field-row-info">
                <span class="field-row-drag" title="Usar ▲▼ para reordenar">⠿</span>
                <div>
                    <span class="field-row-label">${esc(f.label)}</span>
                    <span class="field-row-type">${esc(FIELD_TYPE_LABELS[f.type] || f.type)}</span>
                    ${f.required ? '<span class="field-row-badge badge-req">Obrigatório</span>' : '<span class="field-row-badge badge-opt">Opcional</span>'}
                    ${f.system ? '<span class="field-row-badge badge-sys">Sistema</span>' : ''}
                    ${!f.active ? '<span class="field-row-badge" style="background:#fee2e2;color:#b91c1c;">Desativado</span>' : ''}
                </div>
            </div>
            <div class="field-row-actions">
                ${idx > 0
                    ? `<button class="icon-btn" onclick="moveTecnicoField('${tecId}','${fid}',${idx},-1)" title="Mover para cima">▲</button>`
                    : '<span style="width:28px;display:inline-block;"></span>'}
                ${idx < fields.length - 1
                    ? `<button class="icon-btn" onclick="moveTecnicoField('${tecId}','${fid}',${idx},1)" title="Mover para baixo">▼</button>`
                    : '<span style="width:28px;display:inline-block;"></span>'}
                <button class="icon-btn" onclick="toggleTecnicoField('${tecId}','${fid}',${idx})" title="${f.active ? 'Desativar' : 'Ativar'}">${f.active ? '👁' : '🚫'}</button>
                <button class="icon-btn" onclick="toggleTecnicoFieldRequired('${tecId}','${fid}',${idx})" title="${f.required ? 'Tornar opcional' : 'Tornar obrigatório'}">⭐</button>
                <button class="icon-btn" onclick="renameTecnicoField('${tecId}','${fid}',${idx})" title="Renomear">✏️</button>
                ${!f.system ? `<button class="icon-btn icon-btn-danger" onclick="removeTecnicoField('${tecId}','${fid}',${idx})" title="Remover">🗑</button>` : ''}
            </div>
        </div>`).join('')}
    </div>`;
}

function onNewFieldTypeChange() {
    const type = document.getElementById('newFieldType')?.value;
    const wrap = document.getElementById('newFieldOptionsWrap');
    if (wrap) wrap.style.display = (type === 'select' || type === 'multicheck') ? 'block' : 'none';
}

function addTecnicoFormField(tecId, formId) {
    const label = (document.getElementById('newFieldLabel')?.value || '').trim();
    const type  = document.getElementById('newFieldType')?.value || 'text';
    const errEl = document.getElementById('addFieldError');
    if (errEl) errEl.textContent = '';
    if (!label) { if (errEl) errEl.textContent = 'O nome do campo é obrigatório.'; return; }
    const fields = getTecnicoFormFields(tecId, formId);
    if (fields.find(f => f.label.toLowerCase() === label.toLowerCase())) {
        if (errEl) errEl.textContent = 'Já existe um campo com este nome.'; return;
    }
    const newField = { id: 'tf_custom_' + Date.now(), label, type, required: false, active: true, system: false };
    if (type === 'select' || type === 'multicheck') {
        const optsRaw = (document.getElementById('newFieldOptions')?.value || '');
        newField.options = optsRaw.split(',').map(o => o.trim()).filter(Boolean);
        if (!newField.options.length) { if (errEl) errEl.textContent = 'Adicione pelo menos uma opção.'; return; }
    }
    fields.push(newField);
    saveTecnicoFormFields(tecId, fields, formId);
    showToast(`Campo "${label}" adicionado!`, 'success');
    renderTecnicoFormEditorById(formId, tecId);
}

function toggleTecnicoField(tecId, formId, idx) {
    const fields = getTecnicoFormFields(tecId, formId);
    if (fields[idx]) { fields[idx].active = !fields[idx].active; saveTecnicoFormFields(tecId, fields, formId); renderTecnicoFormEditorById(formId, tecId); }
}

function toggleTecnicoFieldRequired(tecId, formId, idx) {
    const fields = getTecnicoFormFields(tecId, formId);
    if (fields[idx]) { fields[idx].required = !fields[idx].required; saveTecnicoFormFields(tecId, fields, formId); renderTecnicoFormEditorById(formId, tecId); }
}

function renameTecnicoField(tecId, formId, idx) {
    const fields = getTecnicoFormFields(tecId, formId);
    if (!fields[idx]) return;
    const newLabel = prompt('Novo nome para este campo:', fields[idx].label);
    if (!newLabel || !newLabel.trim()) return;
    fields[idx].label = newLabel.trim();
    saveTecnicoFormFields(tecId, fields, formId);
    showToast('Campo renomeado.', 'success');
    renderTecnicoFormEditorById(formId, tecId);
}

function removeTecnicoField(tecId, formId, idx) {
    const fields = getTecnicoFormFields(tecId, formId);
    if (!fields[idx] || fields[idx].system) return;
    if (!confirm(`Remover campo "${fields[idx].label}"?`)) return;
    fields.splice(idx, 1);
    saveTecnicoFormFields(tecId, fields, formId);
    renderTecnicoFormEditorById(formId, tecId);
}

function moveTecnicoField(tecId, formId, idx, dir) {
    const fields = getTecnicoFormFields(tecId, formId);
    const newIdx = idx + dir;
    if (newIdx < 0 || newIdx >= fields.length) return;
    [fields[idx], fields[newIdx]] = [fields[newIdx], fields[idx]];
    saveTecnicoFormFields(tecId, fields, formId);
    renderTecnicoFormEditorById(formId, tecId);
}

// ── RESPOSTAS DO FORMULÁRIO ──────────────────────────────────────

function renderTecnicoFormSubmissions() {
    const u = app.currentUser;
    if (!u || u.role !== 'tecnico') return;
    const fields = getTecnicoFormFields(u.id);
    const subs = ((app.state.tecnicoSubmissions || {})[u.id] || [])
        .slice().sort((a, b) => b.submittedAt.localeCompare(a.submittedAt));

    const el = document.getElementById('dynamicContent');
    el.innerHTML = `
        <div class="section-header" style="margin-bottom:24px;">
            <div><h2>📥 Respostas do Formulário</h2>
            <p>${subs.length} resposta${subs.length !== 1 ? 's' : ''} recebida${subs.length !== 1 ? 's' : ''} via link.</p></div>
            <button class="secondary-btn" onclick="renderMeuLinkTecnico()">🔗 Meu link</button>
        </div>
        ${subs.length === 0
            ? `<div class="card" style="text-align:center;padding:48px;color:var(--text-soft);">
                <div style="font-size:2.5rem;margin-bottom:12px;">📝</div>
                <p>Nenhuma resposta ainda.</p>
                <p style="font-size:0.88rem;">Compartilhe seu link para começar a receber dados!</p>
               </div>`
            : subs.map(s => {
                const nome = s.data['tf_name'] || '—';
                const tel  = s.data['tf_phone'] || '';
                const dataEntries = fields
                    .filter(f => f.active && s.data[f.id] !== undefined && s.data[f.id] !== null && s.data[f.id] !== '')
                    .map(f => {
                        let val = s.data[f.id];
                        if (Array.isArray(val)) val = val.length ? val.join(', ') : '—';
                        if (val && typeof val === 'object' && val.name) val = `📎 ${val.name}`;
                        if (!val) return '';
                        return `<div style="display:flex;gap:8px;padding:5px 0;border-bottom:1px solid var(--border);font-size:0.88rem;">
                            <span style="color:var(--text-soft);min-width:140px;flex-shrink:0;">${esc(f.label)}</span>
                            <span>${esc(String(val))}</span>
                        </div>`;
                    }).join('');
                return `<div class="card" style="margin-bottom:12px;">
                    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;flex-wrap:wrap;gap:8px;">
                        <div>
                            <strong style="font-size:1rem;">${esc(nome)}</strong>
                            ${tel ? `<span style="color:var(--text-soft);margin-left:10px;font-size:0.88rem;">📞 ${esc(tel)}</span>` : ''}
                        </div>
                        <span class="badge badge-active" style="font-size:0.78rem;">${formatDate(s.submittedAt)}</span>
                    </div>
                    ${dataEntries || '<p class="text-muted" style="margin:0;">Sem dados adicionais.</p>'}
                </div>`;
            }).join('')}
    `;
    showSection('dynamicContent');
}

/* ═══════════════════════════════════════════════════════════════════
   PARCEIRO EXECUTIVO — PAINEL DO PRESIDENTE
═══════════════════════════════════════════════════════════════════ */

// ── HELPERS ──────────────────────────────────────────────────────

function getExecClientConfig(executivoId) {
    return (app.state.executivoClientConfig || {})[executivoId] || [];
}

function getExecPayments(executivoId) {
    return (app.state.executivoPayments || []).filter(p => p.executivoId === executivoId);
}

function getExecSales(executivoId) {
    return (app.state.executivoSales || []).filter(s => s.executivoId === executivoId);
}

// Calculates profit-based commission for a single config
function calcPortfolioComm(cfg) {
    const revenue = cfg.monthlyRevenue || 0;
    const cost    = cfg.operationalCost || 0;
    const profit  = revenue - cost;
    const comm    = profit * (cfg.profitCommPct || 0) / 100;
    const compNet = profit - comm;
    return { revenue, cost, profit, pct: cfg.profitCommPct || 0, comm, compNet };
}

// Calculates sales commission for a sale record
function calcSaleComm(u, planValue) {
    if (!u.hasConsultorRole) return 0;
    if (u.saleCommType === 'fixed') return u.saleCommFixed || 0;
    if (u.saleCommType === 'percentage') return planValue * (u.saleCommPct || 0) / 100;
    // 'standard': use existing commission rules
    const rules = app.state.commissionRules || {};
    return rules.consultorFirstSale || 50;
}

function calcExecMetrics(executivoId) {
    const month   = getCurrentMonthKey();
    const configs = getExecClientConfig(executivoId);
    const pays    = getExecPayments(executivoId);
    const sales   = getExecSales(executivoId);
    const u       = (app.state.users || []).find(x => x.id === executivoId);

    let totalRevenue = 0, totalPortfolioComm = 0, totalCompNet = 0;
    configs.forEach(cfg => {
        const r = calcPortfolioComm(cfg);
        totalRevenue       += r.revenue;
        totalPortfolioComm += r.comm;
        totalCompNet       += r.compNet;
    });

    // Sales commission this month
    const thisMoSalesComm = sales.filter(s => s.month === month).reduce((sum,s) => sum + (s.commValue||0), 0);
    // Recurrence commission this month (if configured)
    let recurrenceComm = 0;
    if (u?.hasRecurrence && u?.recurrenceType !== 'none') {
        if (u.recurrenceType === 'fixed_pct') {
            recurrenceComm = totalRevenue * (u.recurrenceCustomPct || 0) / 100;
        }
    }

    const totalComissaoMes = totalPortfolioComm + thisMoSalesComm + recurrenceComm;

    const paidComm = pays.filter(p => p.commissionStatus === 'pago').reduce((s,p) => s + (p.portfolioComm||0), 0)
                   + sales.filter(s => s.commissionStatus === 'pago').reduce((s,x) => s + (x.commValue||0), 0);
    const pendComm = pays.filter(p => p.commissionStatus === 'pendente').reduce((s,p) => s + (p.portfolioComm||0), 0)
                   + sales.filter(s => s.commissionStatus === 'pendente').reduce((s,x) => s + (x.commValue||0), 0);

    return { totalRevenue, totalPortfolioComm, totalCompNet, totalComissaoMes,
             paidComm, pendComm, thisMoSalesComm, recurrenceComm, clientCount: configs.length };
}

